# ============================================================================
# 1. COMPONENTES FUNDAMENTALES MEJORADOS
# ============================================================================

class MultiHeadAttention(nn.Module):
    """
    Multi-Head Attention Mechanism - Versión Mejorada
    
    Este es el componente central de la arquitectura Transformer.
    Permite al modelo enfocarse en diferentes partes de la secuencia simultáneamente.
    
    Mejoras:
    - Soporte para diferentes tipos de máscaras
    - Optimización de memoria
    - Mejor manejo de errores
    - Validación de inputs
    
    Conceptos clave:
    - Query (Q): Qué estamos buscando
    - Key (K): Qué tenemos disponible
    - Value (V): El contenido real que queremos
    - Attention Score: Similitud entre Q y K
    
    Ejemplo:
        >>> attention = MultiHeadAttention(d_model=512, num_heads=8)
        >>> x = torch.randn(1, 10, 512)  # (batch, seq_len, d_model)
        >>> output, weights = attention(x, x, x)
        >>> print(output.shape)  # (1, 10, 512)
    """
    
    def __init__(
        self,
        d_model: int,
        num_heads: int,
        dropout: float = 0.1,
        bias: bool = True
    ):
        """
        Initialize Multi-Head Attention.
        
        Args:
            d_model: Dimensión del modelo (ej: 512)
            num_heads: Número de cabezas de atención (ej: 8)
            dropout: Tasa de dropout
            bias: Si usar bias en las proyecciones lineales
        """
        super().__init__()
        assert d_model % num_heads == 0, f"d_model ({d_model}) debe ser divisible por num_heads ({num_heads})"
        
        self.d_model = d_model
        self.num_heads = num_heads
        self.d_k = d_model // num_heads  # Dimensión por cabeza
        self.scale = 1.0 / math.sqrt(self.d_k)
        
        # Proyecciones lineales para Q, K, V
        self.W_q = nn.Linear(d_model, d_model, bias=bias)
        self.W_k = nn.Linear(d_model, d_model, bias=bias)
        self.W_v = nn.Linear(d_model, d_model, bias=bias)
        self.W_o = nn.Linear(d_model, d_model, bias=bias)
        
        self.dropout = nn.Dropout(dropout)
        
        # Inicialización mejorada
        self._init_weights()
    
    def _init_weights(self):
        """Inicialización mejorada de pesos."""
        for module in [self.W_q, self.W_k, self.W_v, self.W_o]:
            nn.init.xavier_uniform_(module.weight)
            if module.bias is not None:
                nn.init.constant_(module.bias, 0.0)
    
    def forward(
        self,
        query: torch.Tensor,
        key: torch.Tensor,
        value: torch.Tensor,
        mask: Optional[torch.Tensor] = None,
        return_attention: bool = False
    ) -> Tuple[torch.Tensor, Optional[torch.Tensor]]:
        """
        Forward pass de Multi-Head Attention.
        
        Args:
            query: Tensor de queries (batch, seq_len, d_model)
            key: Tensor de keys (batch, seq_len, d_model)
            value: Tensor de values (batch, seq_len, d_model)
            mask: Máscara opcional (batch, seq_len, seq_len) o (seq_len, seq_len)
            return_attention: Si retornar pesos de atención
            
        Returns:
            output: Tensor de salida (batch, seq_len, d_model)
            attention_weights: Pesos de atención si return_attention=True
        """
        batch_size = query.size(0)
        seq_len = query.size(1)
        
        # Validación de inputs
        assert query.size(-1) == self.d_model, f"Query dim mismatch: {query.size(-1)} != {self.d_model}"
        assert key.size(-1) == self.d_model, f"Key dim mismatch: {key.size(-1)} != {self.d_model}"
        assert value.size(-1) == self.d_model, f"Value dim mismatch: {value.size(-1)} != {self.d_model}"
        
        # 1. Proyectar Q, K, V
        Q = self.W_q(query)  # (batch, seq_len, d_model)
        K = self.W_k(key)
        V = self.W_v(value)
        
        # 2. Reshape para multi-head: (batch, num_heads, seq_len, d_k)
        Q = Q.view(batch_size, seq_len, self.num_heads, self.d_k).transpose(1, 2)
        K = K.view(batch_size, seq_len, self.num_heads, self.d_k).transpose(1, 2)
        V = V.view(batch_size, seq_len, self.num_heads, self.d_k).transpose(1, 2)
        
        # 3. Calcular atención
        scores = torch.matmul(Q, K.transpose(-2, -1)) * self.scale
        
        # 4. Aplicar máscara si existe
        if mask is not None:
            # Ajustar dimensión de máscara si es necesario
            if mask.dim() == 2:
                mask = mask.unsqueeze(0).unsqueeze(0)  # (1, 1, seq_len, seq_len)
            elif mask.dim() == 3:
                mask = mask.unsqueeze(1)  # (batch, 1, seq_len, seq_len)
            
            scores = scores.masked_fill(mask == 0, float('-inf'))
        
        # 5. Softmax para obtener pesos de atención
        attention_weights = F.softmax(scores, dim=-1)
        attention_weights = self.dropout(attention_weights)
        
        # 6. Aplicar pesos a los values
        context = torch.matmul(attention_weights, V)
        
        # 7. Concatenar las cabezas
        context = context.transpose(1, 2).contiguous().view(
            batch_size, seq_len, self.d_model
        )
        
        # 8. Proyección final
        output = self.W_o(context)
        
        if return_attention:
            return output, attention_weights
        return output, None


class PositionalEncoding(nn.Module):
    """
    Positional Encoding - Versión Mejorada
    
    Los Transformers no tienen memoria inherente del orden de las palabras.
    Positional Encoding añade información sobre la posición de cada token.
    
    Soporta dos modos:
    - Sinusoidal: Funciones seno/coseno fijas (original)
    - Learned: Embeddings aprendidos (más común en GPT)
    
    Ejemplo:
        >>> pos_encoding = PositionalEncoding(d_model=512, max_len=1000, learned=True)
        >>> x = torch.randn(1, 10, 512)
        >>> x_encoded = pos_encoding(x)
    """
    
    def __init__(
        self,
        d_model: int,
        max_len: int = 5000,
        dropout: float = 0.1,
        learned: bool = True
    ):
        """
        Initialize Positional Encoding.
        
        Args:
            d_model: Dimensión del modelo
            max_len: Longitud máxima de secuencia
            dropout: Tasa de dropout
            learned: Si usar learned embeddings (True) o sinusoidal (False)
        """
        super().__init__()
        
        self.d_model = d_model
        self.max_len = max_len
        self.learned = learned
        
        if learned:
            # Learned positional embeddings (más común en modelos modernos)
            self.pos_embedding = nn.Embedding(max_len, d_model)
            nn.init.normal_(self.pos_embedding.weight, std=0.02)
        else:
            # Sinusoidal positional encoding (original Transformer)
            pe = self._create_sinusoidal_pe(max_len, d_model)
            self.register_buffer('pe', pe)
        
        self.dropout = nn.Dropout(dropout)
    
    def _create_sinusoidal_pe(self, max_len: int, d_model: int) -> torch.Tensor:
        """Crea positional encoding sinusoidal."""
        pe = torch.zeros(max_len, d_model)
        position = torch.arange(0, max_len, dtype=torch.float).unsqueeze(1)
        
        div_term = torch.exp(
            torch.arange(0, d_model, 2).float() * 
            (-math.log(10000.0) / d_model)
        )
        
        pe[:, 0::2] = torch.sin(position * div_term)
        pe[:, 1::2] = torch.cos(position * div_term)
        
        return pe.unsqueeze(0)  # (1, max_len, d_model)
    
    def forward(self, x: torch.Tensor) -> torch.Tensor:
        """
        Añade positional encoding a la entrada.
        
        Args:
            x: Tensor de entrada (batch, seq_len, d_model)
            
        Returns:
            Tensor con positional encoding añadido
        """
        seq_len = x.size(1)
        
        if self.learned:
            positions = torch.arange(seq_len, device=x.device, dtype=torch.long)
            pos_emb = self.pos_embedding(positions)  # (seq_len, d_model)
            x = x + pos_emb.unsqueeze(0)  # Broadcasting
        else:
            x = x + self.pe[:, :seq_len, :]
        
        return self.dropout(x)


class FeedForward(nn.Module):
    """
    Feed Forward Network - Versión Mejorada
    
    Red neuronal feed-forward simple con dos capas lineales.
    Se aplica independientemente a cada posición.
    
    Soporta diferentes activaciones:
    - ReLU: Activación original
    - GELU: Más común en modelos modernos (GPT, BERT)
    - Swish: Variante de GELU
    
    FFN(x) = max(0, xW1 + b1)W2 + b2  (ReLU)
    FFN(x) = GELU(xW1 + b1)W2 + b2    (GELU)
    
    Ejemplo:
        >>> ff = FeedForward(d_model=512, d_ff=2048, activation='gelu')
        >>> x = torch.randn(1, 10, 512)
        >>> output = ff(x)
    """
    
    def __init__(
        self,
        d_model: int,
        d_ff: int,
        dropout: float = 0.1,
        activation: str = 'gelu'
    ):
        """
        Initialize Feed Forward Network.
        
        Args:
            d_model: Dimensión del modelo
            d_ff: Dimensión de la capa intermedia (típicamente 4x d_model)
            dropout: Tasa de dropout
            activation: Tipo de activación ('relu', 'gelu', 'swish')
        """
        super().__init__()
        self.linear1 = nn.Linear(d_model, d_ff)
        self.linear2 = nn.Linear(d_ff, d_model)
        self.dropout = nn.Dropout(dropout)
        
        # Seleccionar activación
        if activation == 'relu':
            self.activation = nn.ReLU()
        elif activation == 'gelu':
            self.activation = nn.GELU()
        elif activation == 'swish':
            self.activation = nn.SiLU()  # Swish = SiLU
        else:
            raise ValueError(f"Activation '{activation}' no soportada. Use 'relu', 'gelu', o 'swish'")
        
        # Inicialización
        self._init_weights()
    
    def _init_weights(self):
        """Inicialización mejorada de pesos."""
        nn.init.xavier_uniform_(self.linear1.weight)
        nn.init.xavier_uniform_(self.linear2.weight)
        if self.linear1.bias is not None:
            nn.init.constant_(self.linear1.bias, 0.0)
        if self.linear2.bias is not None:
            nn.init.constant_(self.linear2.bias, 0.0)
    
    def forward(self, x: torch.Tensor) -> torch.Tensor:
        """
        Forward pass de la red feed-forward.
        
        Args:
            x: Tensor de entrada (batch, seq_len, d_model)
            
        Returns:
            Tensor de salida (batch, seq_len, d_model)
        """
        x = self.linear1(x)
        x = self.activation(x)
        x = self.dropout(x)
        x = self.linear2(x)
        x = self.dropout(x)
        return x


class EncoderLayer(nn.Module):
    """
    Encoder Layer - Versión Mejorada
    
    Un bloque completo del encoder que contiene:
    1. Multi-Head Self-Attention
    2. Feed-Forward Network
    3. Residual connections y Layer Normalization
    
    Soporta arquitectura Pre-LN (más común) y Post-LN (original).
    
    Ejemplo:
        >>> encoder = EncoderLayer(d_model=512, num_heads=8, d_ff=2048)
        >>> x = torch.randn(1, 10, 512)
        >>> output = encoder(x)
    """
    
    def __init__(
        self,
        d_model: int,
        num_heads: int,
        d_ff: int,
        dropout: float = 0.1,
        pre_norm: bool = True,
        activation: str = 'gelu'
    ):
        """
        Initialize Encoder Layer.
        
        Args:
            d_model: Dimensión del modelo
            num_heads: Número de cabezas de atención
            d_ff: Dimensión de la capa feed-forward
            dropout: Tasa de dropout
            pre_norm: Si usar Pre-LN (True) o Post-LN (False)
            activation: Activación para FFN
        """
        super().__init__()
        self.pre_norm = pre_norm
        
        self.self_attn = MultiHeadAttention(d_model, num_heads, dropout)
        self.feed_forward = FeedForward(d_model, d_ff, dropout, activation)
        self.norm1 = nn.LayerNorm(d_model)
        self.norm2 = nn.LayerNorm(d_model)
        self.dropout = nn.Dropout(dropout)
    
    def forward(
        self,
        x: torch.Tensor,
        mask: Optional[torch.Tensor] = None
    ) -> torch.Tensor:
        """
        Forward pass del encoder layer.
        
        Args:
            x: Tensor de entrada (batch, seq_len, d_model)
            mask: Máscara opcional
            
        Returns:
            Tensor de salida (batch, seq_len, d_model)
        """
        # Self-attention con residual connection y layer norm
        if self.pre_norm:
            # Pre-LN: Normalizar antes de la atención
            x_norm = self.norm1(x)
            attn_output, _ = self.self_attn(x_norm, x_norm, x_norm, mask)
            x = x + self.dropout(attn_output)
        else:
            # Post-LN: Atención primero, luego normalizar
            attn_output, _ = self.self_attn(x, x, x, mask)
            x = self.norm1(x + self.dropout(attn_output))
        
        # Feed-forward con residual connection y layer norm
        if self.pre_norm:
            # Pre-LN: Normalizar antes del FFN
            x_norm = self.norm2(x)
            ff_output = self.feed_forward(x_norm)
            x = x + self.dropout(ff_output)
        else:
            # Post-LN: FFN primero, luego normalizar
            ff_output = self.feed_forward(x)
            x = self.norm2(x + self.dropout(ff_output))
        
        return x


class DecoderLayer(nn.Module):
    """
    Decoder Layer - Versión Mejorada
    
    Un bloque completo del decoder que contiene:
    1. Masked Multi-Head Self-Attention (para evitar ver tokens futuros)
    2. Multi-Head Cross-Attention (con el encoder)
    3. Feed-Forward Network
    4. Residual connections y Layer Normalization
    
    Ejemplo:
        >>> decoder = DecoderLayer(d_model=512, num_heads=8, d_ff=2048)
        >>> x = torch.randn(1, 10, 512)
        >>> encoder_output = torch.randn(1, 10, 512)
        >>> output = decoder(x, encoder_output)
    """
    
    def __init__(
        self,
        d_model: int,
        num_heads: int,
        d_ff: int,
        dropout: float = 0.1,
        pre_norm: bool = True,
        activation: str = 'gelu'
    ):
        """
        Initialize Decoder Layer.
        
        Args:
            d_model: Dimensión del modelo
            num_heads: Número de cabezas de atención
            d_ff: Dimensión de la capa feed-forward
            dropout: Tasa de dropout
            pre_norm: Si usar Pre-LN (True) o Post-LN (False)
            activation: Activación para FFN
        """
        super().__init__()
        self.pre_norm = pre_norm
        
        self.self_attn = MultiHeadAttention(d_model, num_heads, dropout)
        self.cross_attn = MultiHeadAttention(d_model, num_heads, dropout)
        self.feed_forward = FeedForward(d_model, d_ff, dropout, activation)
        self.norm1 = nn.LayerNorm(d_model)
        self.norm2 = nn.LayerNorm(d_model)
        self.norm3 = nn.LayerNorm(d_model)
        self.dropout = nn.Dropout(dropout)
    
    def forward(
        self,
        x: torch.Tensor,
        encoder_output: torch.Tensor,
        src_mask: Optional[torch.Tensor] = None,
        tgt_mask: Optional[torch.Tensor] = None
    ) -> torch.Tensor:
        """
        Forward pass del decoder layer.
        
        Args:
            x: Tensor de entrada del decoder (batch, seq_len, d_model)
            encoder_output: Salida del encoder (batch, seq_len, d_model)
            src_mask: Máscara para el encoder
            tgt_mask: Máscara causal para el decoder
            
        Returns:
            Tensor de salida (batch, seq_len, d_model)
        """
        # Masked self-attention
        if self.pre_norm:
            x_norm = self.norm1(x)
            attn_output, _ = self.self_attn(x_norm, x_norm, x_norm, tgt_mask)
            x = x + self.dropout(attn_output)
        else:
            attn_output, _ = self.self_attn(x, x, x, tgt_mask)
            x = self.norm1(x + self.dropout(attn_output))
        
        # Cross-attention con el encoder
        if self.pre_norm:
            x_norm = self.norm2(x)
            attn_output, _ = self.cross_attn(x_norm, encoder_output, encoder_output, src_mask)
            x = x + self.dropout(attn_output)
        else:
            attn_output, _ = self.cross_attn(x, encoder_output, encoder_output, src_mask)
            x = self.norm2(x + self.dropout(attn_output))
        
        # Feed-forward
        if self.pre_norm:
            x_norm = self.norm3(x)
            ff_output = self.feed_forward(x_norm)
            x = x + self.dropout(ff_output)
        else:
            ff_output = self.feed_forward(x)
            x = self.norm3(x + self.dropout(ff_output))
        
        return x


# ============================================================================
# 2. ARQUITECTURA COMPLETA MEJORADA
# ============================================================================

class TransformerEncoder(nn.Module):
    """
    Transformer Encoder - Versión Mejorada
    
    Stack de N capas de encoder.
    El encoder procesa la secuencia de entrada y produce
    representaciones enriquecidas.
    
    Mejoras:
    - Mejor inicialización
    - Soporte para diferentes configuraciones
    - Mejor manejo de errores
    - Métodos de utilidad adicionales
    
    Ejemplo:
        >>> encoder = TransformerEncoder(
        ...     vocab_size=10000,
        ...     d_model=512,
        ...     num_heads=8,
        ...     num_layers=6,
        ...     d_ff=2048,
        ...     max_seq_length=1000
        ... )
        >>> x = torch.randint(0, 10000, (1, 10))  # (batch, seq_len)
        >>> output = encoder(x)
    """
    
    def __init__(
        self,
        vocab_size: int,
        d_model: int = 512,
        num_heads: int = 8,
        num_layers: int = 6,
        d_ff: int = 2048,
        max_seq_length: int = 5000,
        dropout: float = 0.1,
        activation: str = 'gelu',
        pre_norm: bool = True,
        learned_pos: bool = True
    ):
        """
        Initialize Transformer Encoder.
        
        Args:
            vocab_size: Tamaño del vocabulario
            d_model: Dimensión del modelo
            num_heads: Número de cabezas de atención
            num_layers: Número de capas de encoder
            d_ff: Dimensión de la capa feed-forward
            max_seq_length: Longitud máxima de secuencia
            dropout: Tasa de dropout
            activation: Activación para FFN
            pre_norm: Si usar Pre-LN (True) o Post-LN (False)
            learned_pos: Si usar learned positional embeddings
        """
        super().__init__()
        
        self.d_model = d_model
        self.vocab_size = vocab_size
        self.num_layers = num_layers
        
        # Embedding de tokens
        self.token_embedding = nn.Embedding(vocab_size, d_model)
        
        # Positional encoding
        self.positional_encoding = PositionalEncoding(
            d_model, max_seq_length, dropout, learned=learned_pos
        )
        
        # Stack de capas de encoder
        self.layers = nn.ModuleList([
            EncoderLayer(d_model, num_heads, d_ff, dropout, pre_norm, activation)
            for _ in range(num_layers)
        ])
        
        self.norm = nn.LayerNorm(d_model) if pre_norm else None
        self.dropout = nn.Dropout(dropout)
        
        # Inicialización mejorada
        self._init_weights()
    
    def _init_weights(self):
        """Inicialización mejorada de pesos."""
        # Embeddings: inicialización normal
        nn.init.normal_(self.token_embedding.weight, mean=0.0, std=0.02)
        
        # Capas lineales: inicialización Xavier
        for module in self.modules():
            if isinstance(module, nn.Linear):
                nn.init.xavier_uniform_(module.weight)
                if module.bias is not None:
                    nn.init.constant_(module.bias, 0.0)
    
    def forward(
        self,
        x: torch.Tensor,
        mask: Optional[torch.Tensor] = None
    ) -> torch.Tensor:
        """
        Forward pass del encoder.
        
        Args:
            x: Tensor de índices de tokens (batch, seq_len)
            mask: Máscara opcional
            
        Returns:
            Tensor de salida (batch, seq_len, d_model)
        """
        # Embedding de tokens
        x = self.token_embedding(x) * math.sqrt(self.d_model)
        
        # Añadir positional encoding
        x = self.positional_encoding(x)
        
        # Pasar por todas las capas
        for layer in self.layers:
            x = layer(x, mask)
        
        # Layer normalization final (solo si Pre-LN)
        if self.norm is not None:
            x = self.norm(x)
        
        return x
    
    def get_num_parameters(self) -> Dict[str, int]:
        """
        Obtiene el número de parámetros del modelo.
        
        Returns:
            Diccionario con conteo de parámetros
        """
        total = sum(p.numel() for p in self.parameters())
        trainable = sum(p.numel() for p in self.parameters() if p.requires_grad)
        
        return {
            "total": total,
            "trainable": trainable,
            "non_trainable": total - trainable,
            "millions": total / 1e6,
            "billions": total / 1e9
        }


class TransformerDecoder(nn.Module):
    """
    Transformer Decoder - Versión Mejorada
    
    Stack de N capas de decoder.
    El decoder genera la secuencia de salida token por token,
    usando la información del encoder.
    
    Ejemplo:
        >>> decoder = TransformerDecoder(
        ...     vocab_size=10000,
        ...     d_model=512,
        ...     num_heads=8,
        ...     num_layers=6,
        ...     d_ff=2048,
        ...     max_seq_length=1000
        ... )
        >>> x = torch.randint(0, 10000, (1, 10))
        >>> encoder_output = torch.randn(1, 10, 512)
        >>> output = decoder(x, encoder_output)
    """
    
    def __init__(
        self,
        vocab_size: int,
        d_model: int = 512,
        num_heads: int = 8,
        num_layers: int = 6,
        d_ff: int = 2048,
        max_seq_length: int = 5000,
        dropout: float = 0.1,
        activation: str = 'gelu',
        pre_norm: bool = True,
        learned_pos: bool = True
    ):
        """
        Initialize Transformer Decoder.
        
        Args:
            vocab_size: Tamaño del vocabulario
            d_model: Dimensión del modelo
            num_heads: Número de cabezas de atención
            num_layers: Número de capas de decoder
            d_ff: Dimensión de la capa feed-forward
            max_seq_length: Longitud máxima de secuencia
            dropout: Tasa de dropout
            activation: Activación para FFN
            pre_norm: Si usar Pre-LN
            learned_pos: Si usar learned positional embeddings
        """
        super().__init__()
        
        self.d_model = d_model
        self.vocab_size = vocab_size
        self.num_layers = num_layers
        
        # Embedding de tokens
        self.token_embedding = nn.Embedding(vocab_size, d_model)
        
        # Positional encoding
        self.positional_encoding = PositionalEncoding(
            d_model, max_seq_length, dropout, learned=learned_pos
        )
        
        # Stack de capas de decoder
        self.layers = nn.ModuleList([
            DecoderLayer(d_model, num_heads, d_ff, dropout, pre_norm, activation)
            for _ in range(num_layers)
        ])
        
        self.norm = nn.LayerNorm(d_model) if pre_norm else None
        self.dropout = nn.Dropout(dropout)
        
        # Inicialización
        self._init_weights()
    
    def _init_weights(self):
        """Inicialización de pesos."""
        nn.init.normal_(self.token_embedding.weight, mean=0.0, std=0.02)
        
        for module in self.modules():
            if isinstance(module, nn.Linear):
                nn.init.xavier_uniform_(module.weight)
                if module.bias is not None:
                    nn.init.constant_(module.bias, 0.0)
    
    def forward(
        self,
        x: torch.Tensor,
        encoder_output: torch.Tensor,
        src_mask: Optional[torch.Tensor] = None,
        tgt_mask: Optional[torch.Tensor] = None
    ) -> torch.Tensor:
        """
        Forward pass del decoder.
        
        Args:
            x: Tensor de índices de tokens (batch, seq_len)
            encoder_output: Salida del encoder (batch, seq_len, d_model)
            src_mask: Máscara para el encoder
            tgt_mask: Máscara causal para el decoder
            
        Returns:
            Tensor de salida (batch, seq_len, d_model)
        """
        # Embedding de tokens
        x = self.token_embedding(x) * math.sqrt(self.d_model)
        
        # Añadir positional encoding
        x = self.positional_encoding(x)
        
        # Pasar por todas las capas
        for layer in self.layers:
            x = layer(x, encoder_output, src_mask, tgt_mask)
        
        # Layer normalization final
        if self.norm is not None:
            x = self.norm(x)
        
        return x
    
    def get_num_parameters(self) -> Dict[str, int]:
        """Obtiene el número de parámetros."""
        total = sum(p.numel() for p in self.parameters())
        trainable = sum(p.numel() for p in self.parameters() if p.requires_grad)
        
        return {
            "total": total,
            "trainable": trainable,
            "non_trainable": total - trainable,
            "millions": total / 1e6,
            "billions": total / 1e9
        }


class Transformer(nn.Module):
    """
    Transformer Completo (Encoder-Decoder) - Versión Mejorada
    
    Arquitectura completa de Transformer como se describe en
    "Attention Is All You Need" (Vaswani et al., 2017).
    
    Componentes principales:
    1. Encoder: Procesa la secuencia de entrada
    2. Decoder: Genera la secuencia de salida
    3. Output projection: Proyección final al vocabulario
    
    Mejoras:
    - Mejor inicialización
    - Soporte para weight tying (compartir embeddings)
    - Métodos de utilidad
    - Mejor manejo de máscaras
    
    Ejemplo:
        >>> transformer = Transformer(
        ...     src_vocab_size=10000,
        ...     tgt_vocab_size=10000,
        ...     d_model=512,
        ...     num_heads=8,
        ...     num_encoder_layers=6,
        ...     num_decoder_layers=6,
        ...     d_ff=2048
        ... )
        >>> src = torch.randint(0, 10000, (1, 10))
        >>> tgt = torch.randint(0, 10000, (1, 10))
        >>> output = transformer(src, tgt)
    """
    
    def __init__(
        self,
        src_vocab_size: int,
        tgt_vocab_size: int,
        d_model: int = 512,
        num_heads: int = 8,
        num_encoder_layers: int = 6,
        num_decoder_layers: int = 6,
        d_ff: int = 2048,
        max_seq_length: int = 5000,
        dropout: float = 0.1,
        activation: str = 'gelu',
        pre_norm: bool = True,
        learned_pos: bool = True,
        tie_weights: bool = False
    ):
        """
        Initialize Transformer.
        
        Args:
            src_vocab_size: Tamaño del vocabulario fuente
            tgt_vocab_size: Tamaño del vocabulario destino
            d_model: Dimensión del modelo
            num_heads: Número de cabezas de atención
            num_encoder_layers: Número de capas de encoder
            num_decoder_layers: Número de capas de decoder
            d_ff: Dimensión de la capa feed-forward
            max_seq_length: Longitud máxima de secuencia
            dropout: Tasa de dropout
            activation: Activación para FFN
            pre_norm: Si usar Pre-LN
            learned_pos: Si usar learned positional embeddings
            tie_weights: Si compartir pesos entre embedding y output (si vocab igual)
        """
        super().__init__()
        
        self.encoder = TransformerEncoder(
            vocab_size=src_vocab_size,
            d_model=d_model,
            num_heads=num_heads,
            num_layers=num_encoder_layers,
            d_ff=d_ff,
            max_seq_length=max_seq_length,
            dropout=dropout,
            activation=activation,
            pre_norm=pre_norm,
            learned_pos=learned_pos
        )
        
        self.decoder = TransformerDecoder(
            vocab_size=tgt_vocab_size,
            d_model=d_model,
            num_heads=num_heads,
            num_layers=num_decoder_layers,
            d_ff=d_ff,
            max_seq_length=max_seq_length,
            dropout=dropout,
            activation=activation,
            pre_norm=pre_norm,
            learned_pos=learned_pos
        )
        
        # Proyección final al vocabulario
        self.fc_out = nn.Linear(d_model, tgt_vocab_size)
        
        # Weight tying (compartir pesos entre embedding y output)
        if tie_weights and src_vocab_size == tgt_vocab_size:
            self.fc_out.weight = self.decoder.token_embedding.weight
        
        # Inicialización
        nn.init.xavier_uniform_(self.fc_out.weight)
        if self.fc_out.bias is not None:
            nn.init.constant_(self.fc_out.bias, 0.0)
    
    def forward(
        self,
        src: torch.Tensor,
        tgt: torch.Tensor,
        src_mask: Optional[torch.Tensor] = None,
        tgt_mask: Optional[torch.Tensor] = None
    ) -> torch.Tensor:
        """
        Forward pass del Transformer.
        
        Args:
            src: Secuencia fuente (batch, src_len)
            tgt: Secuencia destino (batch, tgt_len)
            src_mask: Máscara para el encoder
            tgt_mask: Máscara causal para el decoder
            
        Returns:
            Logits para cada token en el vocabulario (batch, tgt_len, tgt_vocab_size)
        """
        # Encoder
        encoder_output = self.encoder(src, src_mask)
        
        # Decoder
        decoder_output = self.decoder(tgt, encoder_output, src_mask, tgt_mask)
        
        # Proyección final
        output = self.fc_out(decoder_output)
        
        return output
    
    def generate_causal_mask(self, seq_len: int, device: torch.device) -> torch.Tensor:
        """
        Genera máscara causal para evitar que el decoder vea tokens futuros.
        
        Args:
            seq_len: Longitud de la secuencia
            device: Device del tensor
            
        Returns:
            Máscara causal (seq_len, seq_len)
        """
        mask = torch.triu(torch.ones(seq_len, seq_len, device=device), diagonal=1)
        return mask.masked_fill(mask == 1, float('-inf'))
    
    def get_num_parameters(self) -> Dict[str, float]:
        """Obtiene el número de parámetros del modelo completo."""
        encoder_params = self.encoder.get_num_parameters()
        decoder_params = self.decoder.get_num_parameters()
        
        # Contar output projection
        output_params = sum(p.numel() for p in self.fc_out.parameters())
        
        total = encoder_params["total"] + decoder_params["total"] + output_params
        
        return {
            "total": total,
            "encoder": encoder_params["total"],
            "decoder": decoder_params["total"],
            "output": output_params,
            "millions": total / 1e6,
            "billions": total / 1e9
        }


# ============================================================================
# 3. TRANSFORMER CAUSAL (GPT-STYLE) - NUEVO
# ============================================================================

class CausalTransformerBlock(nn.Module):
    """
    Bloque de Transformer Causal (GPT-style).
    
    Diferencia con encoder-decoder:
    - Solo tiene self-attention (no cross-attention)
    - Usa máscara causal para autoregresión
    - Más simple y eficiente para generación
    
    Ejemplo:
        >>> block = CausalTransformerBlock(d_model=512, num_heads=8, d_ff=2048)
        >>> x = torch.randn(1, 10, 512)
        >>> output = block(x)
    """
    
    def __init__(
        self,
        d_model: int,
        num_heads: int,
        d_ff: int,
        dropout: float = 0.1,
        pre_norm: bool = True,
        activation: str = 'gelu'
    ):
        """
        Initialize Causal Transformer Block.
        
        Args:
            d_model: Dimensión del modelo
            num_heads: Número de cabezas de atención
            d_ff: Dimensión de la capa feed-forward
            dropout: Tasa de dropout
            pre_norm: Si usar Pre-LN
            activation: Activación para FFN
        """
        super().__init__()
        self.pre_norm = pre_norm
        
        self.attention = MultiHeadAttention(d_model, num_heads, dropout)
        self.feed_forward = FeedForward(d_model, d_ff, dropout, activation)
        self.norm1 = nn.LayerNorm(d_model)
        self.norm2 = nn.LayerNorm(d_model)
        self.dropout = nn.Dropout(dropout)
    
    def forward(
        self,
        x: torch.Tensor,
        mask: Optional[torch.Tensor] = None
    ) -> torch.Tensor:
        """
        Forward pass del bloque causal.
        
        Args:
            x: Tensor de entrada (batch, seq_len, d_model)
            mask: Máscara causal opcional
            
        Returns:
            Tensor de salida (batch, seq_len, d_model)
        """
        # Self-attention con residual
        if self.pre_norm:
            x_norm = self.norm1(x)
            attn_output, _ = self.attention(x_norm, x_norm, x_norm, mask)
            x = x + self.dropout(attn_output)
        else:
            attn_output, _ = self.attention(x, x, x, mask)
            x = self.norm1(x + self.dropout(attn_output))
        
        # Feed-forward con residual
        if self.pre_norm:
            x_norm = self.norm2(x)
            ff_output = self.feed_forward(x_norm)
            x = x + self.dropout(ff_output)
        else:
            ff_output = self.feed_forward(x)
            x = self.norm2(x + self.dropout(ff_output))
        
        return x


class CausalTransformer(nn.Module):
    """
    Transformer Causal Completo (GPT-style).
    
    Modelo autoregresivo para generación de lenguaje.
    Usado en GPT, ChatGPT, etc.
    
    Ejemplo:
        >>> model = CausalTransformer(
        ...     vocab_size=10000,
        ...     d_model=512,
        ...     num_heads=8,
        ...     num_layers=6,
        ...     d_ff=2048,
        ...     max_seq_length=1024
        ... )
        >>> tokens = torch.randint(0, 10000, (1, 10))
        >>> logits = model(tokens)
    """
    
    def __init__(
        self,
        vocab_size: int,
        d_model: int = 512,
        num_heads: int = 8,
        num_layers: int = 6,
        d_ff: int = 2048,
        max_seq_length: int = 512,
        dropout: float = 0.1,
        activation: str = 'gelu',
        pre_norm: bool = True,
        learned_pos: bool = True,
        tie_weights: bool = True
    ):
        """
        Initialize Causal Transformer.
        
        Args:
            vocab_size: Tamaño del vocabulario
            d_model: Dimensión del modelo
            num_heads: Número de cabezas de atención
            num_layers: Número de capas
            d_ff: Dimensión de la capa feed-forward
            max_seq_length: Longitud máxima de secuencia
            dropout: Tasa de dropout
            activation: Activación para FFN
            pre_norm: Si usar Pre-LN
            learned_pos: Si usar learned positional embeddings
            tie_weights: Si compartir pesos entre embedding y output
        """
        super().__init__()
        
        self.d_model = d_model
        self.vocab_size = vocab_size
        self.num_layers = num_layers
        
        # Token embeddings
        self.token_embedding = nn.Embedding(vocab_size, d_model)
        
        # Positional encoding
        self.positional_encoding = PositionalEncoding(
            d_model, max_seq_length, dropout, learned=learned_pos
        )
        
        # Stack de bloques causales
        self.blocks = nn.ModuleList([
            CausalTransformerBlock(d_model, num_heads, d_ff, dropout, pre_norm, activation)
            for _ in range(num_layers)
        ])
        
        # Layer normalization final
        self.ln_final = nn.LayerNorm(d_model) if pre_norm else None
        
        # Output projection
        self.output_projection = nn.Linear(d_model, vocab_size)
        
        # Weight tying
        if tie_weights:
            self.output_projection.weight = self.token_embedding.weight
        
        # Inicialización
        self._init_weights()
    
    def _init_weights(self):
        """Inicialización mejorada."""
        nn.init.normal_(self.token_embedding.weight, mean=0.0, std=0.02)
        
        for module in self.modules():
            if isinstance(module, nn.Linear):
                nn.init.normal_(module.weight, mean=0.0, std=0.02)
                if module.bias is not None:
                    nn.init.constant_(module.bias, 0.0)
    
    def forward(
        self,
        token_ids: torch.Tensor,
        mask: Optional[torch.Tensor] = None
    ) -> torch.Tensor:
        """
        Forward pass del modelo causal.
        
        Args:
            token_ids: IDs de tokens (batch, seq_len)
            mask: Máscara causal opcional
            
        Returns:
            Logits (batch, seq_len, vocab_size)
        """
        batch_size, seq_len = token_ids.shape
        
        # Token embeddings
        x = self.token_embedding(token_ids) * math.sqrt(self.d_model)
        
        # Positional encoding
        x = self.positional_encoding(x)
        
        # Crear máscara causal si no se proporciona
        if mask is None:
            mask = self.generate_causal_mask(seq_len, x.device)
        
        # Pasar por todos los bloques
        for block in self.blocks:
            x = block(x, mask)
        
        # Layer normalization final
        if self.ln_final is not None:
            x = self.ln_final(x)
        
        # Proyección a vocabulario
        logits = self.output_projection(x)
        
        return logits
    
    def generate_causal_mask(self, seq_len: int, device: torch.device) -> torch.Tensor:
        """
        Genera máscara causal.
        
        Args:
            seq_len: Longitud de la secuencia
            device: Device del tensor
            
        Returns:
            Máscara causal (seq_len, seq_len)
        """
        mask = torch.triu(torch.ones(seq_len, seq_len, device=device), diagonal=1)
        return mask.masked_fill(mask == 1, float('-inf'))
    
    def get_num_parameters(self) -> Dict[str, float]:
        """Obtiene el número de parámetros."""
        total = sum(p.numel() for p in self.parameters())
        trainable = sum(p.numel() for p in self.parameters() if p.requires_grad)
        
        return {
            "total": total,
            "trainable": trainable,
            "non_trainable": total - trainable,
            "millions": total / 1e6,
            "billions": total / 1e9
        }


# ============================================================================
# 4. UTILIDADES Y FUNCIONES DE AYUDA MEJORADAS
# ============================================================================

def create_padding_mask(seq: torch.Tensor, pad_idx: int = 0) -> torch.Tensor:
    """
    Crea máscara de padding para evitar atención a tokens de padding.
    
    Args:
        seq: Tensor de secuencia (batch, seq_len)
        pad_idx: Índice del token de padding
        
    Returns:
        Máscara (batch, 1, 1, seq_len) donde 1 = válido, 0 = padding
    """
    mask = (seq != pad_idx).unsqueeze(1).unsqueeze(2)
    return mask.float()


def create_causal_mask(seq_len: int, device: torch.device = None) -> torch.Tensor:
    """
    Crea máscara causal para el decoder (máscara look-ahead).
    
    Args:
        seq_len: Longitud de la secuencia
        device: Device del tensor
        
    Returns:
        Máscara causal (seq_len, seq_len)
    """
    if device is None:
        device = torch.device('cpu')
    mask = torch.triu(torch.ones(seq_len, seq_len, device=device), diagonal=1)
    return mask.masked_fill(mask == 1, float('-inf'))


def visualize_attention_weights(
    attention_weights: torch.Tensor,
    tokens: List[str],
    head_idx: int = 0,
    save_path: Optional[str] = None
) -> None:
    """
    Visualiza los pesos de atención para una cabeza específica.
    
    Args:
        attention_weights: Pesos de atención (batch, num_heads, seq_len, seq_len)
        tokens: Lista de tokens para etiquetar
        head_idx: Índice de la cabeza a visualizar
        save_path: Ruta opcional para guardar la imagen
    """
    try:
        import matplotlib.pyplot as plt
        
        # Obtener pesos de la primera muestra y cabeza especificada
        weights = attention_weights[0, head_idx].detach().cpu().numpy()
        
        # Crear visualización
        plt.figure(figsize=(12, 10))
        plt.imshow(weights, cmap='Blues', aspect='auto')
        plt.colorbar(label='Attention Weight')
        plt.xlabel('Key Position')
        plt.ylabel('Query Position')
        plt.title(f'Attention Weights - Head {head_idx}')
        
        if tokens:
            plt.xticks(range(len(tokens)), tokens, rotation=45, ha='right')
            plt.yticks(range(len(tokens)), tokens)
        
        plt.tight_layout()
        
        if save_path:
            plt.savefig(save_path, dpi=300, bbox_inches='tight')
            print(f"Visualización guardada en: {save_path}")
        else:
            plt.show()
    except ImportError:
        print("matplotlib no está instalado. Instalar con: pip install matplotlib")


def estimate_model_size(
    vocab_size: int,
    d_model: int,
    num_heads: int,
    num_layers: int,
    d_ff: int,
    max_seq_length: int = 512
) -> Dict[str, float]:
    """
    Estima el tamaño del modelo en parámetros y memoria.
    
    Args:
        vocab_size: Tamaño del vocabulario
        d_model: Dimensión del modelo
        num_heads: Número de cabezas
        num_layers: Número de capas
        d_ff: Dimensión de FFN
        max_seq_length: Longitud máxima de secuencia
        
    Returns:
        Diccionario con estimaciones
    """
    # Embeddings
    embedding_params = vocab_size * d_model
    
    # Positional encoding (learned)
    pos_params = max_seq_length * d_model
    
    # Por capa
    # Attention: Q, K, V, O
    attn_params = 4 * (d_model * d_model)
    
    # FFN: 2 capas lineales
    ffn_params = 2 * (d_model * d_ff)
    
    # LayerNorm: 2 por capa (gamma, beta)
    ln_params = 2 * (2 * d_model)  # 2 LayerNorms por capa
    
    params_per_layer = attn_params + ffn_params + ln_params
    
    # Total
    total_params = embedding_params + pos_params + (num_layers * params_per_layer)
    
    # Memoria (asumiendo float32 = 4 bytes)
    memory_mb = (total_params * 4) / (1024 * 1024)
    memory_gb = memory_mb / 1024
    
    return {
        "total_parameters": int(total_params),
        "parameters_millions": total_params / 1e6,
        "parameters_billions": total_params / 1e9,
        "memory_mb": memory_mb,
        "memory_gb": memory_gb,
        "embedding_params": int(embedding_params),
        "params_per_layer": int(params_per_layer),
        "layers_params": int(num_layers * params_per_layer)
    }


