# ============================================================================

def example_usage():
    """
    Ejemplo completo de uso del Transformer mejorado.
    """
    print("=" * 80)
    print("EJEMPLO: Uso del Transformer Mejorado")
    print("=" * 80)
    
    # Configuración
    src_vocab_size = 10000
    tgt_vocab_size = 10000
    d_model = 512
    num_heads = 8
    num_layers = 6
    batch_size = 2
    src_len = 10
    tgt_len = 12
    
    print(f"\n📊 CONFIGURACIÓN:")
    print(f"   - Vocabulario fuente: {src_vocab_size}")
    print(f"   - Vocabulario destino: {tgt_vocab_size}")
    print(f"   - d_model: {d_model}")
    print(f"   - Número de heads: {num_heads}")
    print(f"   - Número de capas: {num_layers}")
    
    # Crear modelo
    model = Transformer(
        src_vocab_size=src_vocab_size,
        tgt_vocab_size=tgt_vocab_size,
        d_model=d_model,
        num_heads=num_heads,
        num_encoder_layers=num_layers,
        num_decoder_layers=num_layers,
        d_ff=2048
    )
    
    # Obtener información del modelo
    params = model.get_num_parameters()
    print(f"\n✅ Modelo creado:")
    print(f"   - Parámetros totales: {params['total']:,.0f}")
    print(f"   - Parámetros (millones): {params['millions']:.2f}M")
    print(f"   - Parámetros encoder: {params['encoder']:,.0f}")
    print(f"   - Parámetros decoder: {params['decoder']:,.0f}")
    
    # Crear datos de ejemplo
    src = torch.randint(1, src_vocab_size, (batch_size, src_len))
    tgt = torch.randint(1, tgt_vocab_size, (batch_size, tgt_len))
    
    print(f"\n📊 Datos de entrada:")
    print(f"   - Source shape: {src.shape}")
    print(f"   - Target shape: {tgt.shape}")
    
    # Crear máscaras
    src_mask = create_padding_mask(src, pad_idx=0)
    tgt_mask = create_causal_mask(tgt_len, src.device)
    
    # Forward pass
    print(f"\n🚀 Forward pass...")
    output = model(src, tgt, src_mask, tgt_mask)
    
    print(f"\n✅ Salida generada:")
    print(f"   - Output shape: {output.shape}")
    print(f"   - Expected: (batch={batch_size}, seq_len={tgt_len}, vocab_size={tgt_vocab_size})")
    
    # Calcular probabilidades
    probs = F.softmax(output, dim=-1)
    predicted_tokens = torch.argmax(probs, dim=-1)
    
    print(f"\n📝 Predicciones:")
    print(f"   - Predicted tokens shape: {predicted_tokens.shape}")
    print(f"   - Sample predictions (batch 0): {predicted_tokens[0, :5].tolist()}")


def example_causal_transformer():
    """
    Ejemplo de uso del Transformer Causal (GPT-style).
    """
    print("\n" + "=" * 80)
    print("EJEMPLO: Transformer Causal (GPT-style)")
    print("=" * 80)
    
    vocab_size = 10000
    d_model = 512
    num_heads = 8
    num_layers = 6
    batch_size = 2
    seq_len = 20
    
    # Crear modelo causal
    model = CausalTransformer(
        vocab_size=vocab_size,
        d_model=d_model,
        num_heads=num_heads,
        num_layers=num_layers,
        d_ff=2048,
        max_seq_length=512
    )
    
    # Obtener información
    params = model.get_num_parameters()
    size_est = estimate_model_size(
        vocab_size, d_model, num_heads, num_layers, 2048
    )
    
    print(f"\n✅ Modelo Causal creado:")
    print(f"   - Parámetros: {params['millions']:.2f}M")
    print(f"   - Memoria estimada: {size_est['memory_gb']:.2f} GB")
    
    # Crear datos
    tokens = torch.randint(1, vocab_size, (batch_size, seq_len))
    print(f"\n📊 Input tokens: {tokens.shape}")
    
    # Forward pass
    logits = model(tokens)
    print(f"✅ Output logits: {logits.shape}")
    
    # Predicciones
    probs = F.softmax(logits, dim=-1)
    predicted = torch.argmax(probs, dim=-1)
    print(f"📝 Predicted next tokens shape: {predicted.shape}")


# ============================================================================
# 6. EXPLICACIÓN CONCEPTUAL MEJORADA
# ============================================================================

def print_architecture_explanation():
    """
    Imprime una explicación conceptual mejorada de la arquitectura Transformer.
    """
    explanation = """
    ============================================================================
    EXPLICACIÓN DE LA ARQUITECTURA TRANSFORMER - VERSIÓN MEJORADA
    ============================================================================
    
    1. PROBLEMA QUE RESUELVE
    -------------------------
    Los modelos anteriores (RNN, LSTM) procesan secuencias de forma secuencial,
    lo que es lento y dificulta el paralelismo. Los Transformers procesan toda
    la secuencia en paralelo usando atención, permitiendo:
    - Entrenamiento más rápido (paralelización)
    - Mejor captura de dependencias a larga distancia
    - Escalabilidad a modelos muy grandes
    
    2. COMPONENTES PRINCIPALES
    --------------------------
    
    A. MULTI-HEAD ATTENTION
       - Permite al modelo enfocarse en diferentes partes de la secuencia
       - Múltiples "cabezas" permiten diferentes tipos de relaciones
       - Fórmula: Attention(Q,K,V) = softmax(QK^T / √d_k) V
       - Cada head aprende diferentes patrones (sintácticos, semánticos, etc.)
    
    B. POSITIONAL ENCODING
       - Añade información sobre la posición de cada token
       - Dos tipos: Sinusoidal (fijo) y Learned (aprendido)
       - Learned es más común en modelos modernos (GPT, BERT)
       - Permite al modelo entender el orden sin recurrencia
    
    C. FEED-FORWARD NETWORK
       - Red neuronal simple aplicada a cada posición
       - Añade no-linealidad y capacidad de representación
       - Típicamente: d_model → 4×d_model → d_model
       - Activaciones: ReLU (original) o GELU (moderno)
    
    D. LAYER NORMALIZATION
       - Normaliza las activaciones en cada capa
       - Facilita el entrenamiento y mejora la estabilidad
       - Tipos: Pre-LN (antes de subcapa) o Post-LN (después)
       - Pre-LN es más común en modelos modernos
    
    E. RESIDUAL CONNECTIONS
       - Conexiones que suman la entrada a la salida
       - Facilitan el flujo de gradientes en redes profundas
       - Fórmula: output = input + sublayer(input)
       - Permiten que el modelo aprenda refinamientos incrementales
    
    3. TIPOS DE TRANSFORMERS
    ------------------------
    
    A. ENCODER-DECODER (Original Transformer)
       - Usado para tareas seq2seq (traducción)
       - Encoder procesa entrada, Decoder genera salida
       - Cross-attention conecta encoder y decoder
    
    B. ENCODER-ONLY (BERT)
       - Solo encoder, procesa toda la secuencia
       - Atención bidireccional (sin máscara causal)
       - Usado para comprensión de lenguaje
    
    C. DECODER-ONLY (GPT)
       - Solo decoder con máscara causal
       - Generación autoregresiva
       - Usado para generación de lenguaje
    
    4. FLUJO DE DATOS
    -----------------
    
    ENCODER (BERT-style):
    1. Token Embeddings + Positional Encoding
    2. N × (Self-Attention → Layer Norm → FFN → Layer Norm)
    3. Representaciones enriquecidas de la entrada
    
    DECODER (GPT-style):
    1. Token Embeddings + Positional Encoding
    2. N × (Masked Self-Attention → Layer Norm → FFN → Layer Norm)
    3. Proyección al vocabulario
    
    ENCODER-DECODER (Transformer original):
    1. Encoder procesa entrada
    2. Decoder usa salida del encoder + su propia entrada
    3. Cross-attention conecta ambos
    
    5. VENTAJAS
    -----------
    ✅ Paralelización: Procesa toda la secuencia en paralelo
    ✅ Atención: Puede relacionar tokens distantes directamente
    ✅ Escalabilidad: Funciona bien con grandes cantidades de datos
    ✅ Flexibilidad: Arquitectura base para muchos modelos
    ✅ Eficiencia: Más rápido que RNNs para secuencias largas
    
    6. LIMITACIONES Y SOLUCIONES
    ----------------------------
    
    LIMITACIÓN: Complejidad O(n²) en atención
    SOLUCIÓN: Flash Attention, Sparse Attention
    
    LIMITACIÓN: Memoria O(n²) para attention weights
    SOLUCIÓN: Gradient Checkpointing, Mixed Precision
    
    LIMITACIÓN: No puede extrapolar a secuencias más largas
    SOLUCIÓN: RoPE (Rotary Positional Embedding)
    
    7. VARIANTES MODERNAS
    --------------------
    - BERT: Solo encoder, pre-entrenamiento bidireccional
    - GPT: Solo decoder, generación autoregresiva
    - T5: Encoder-decoder, texto-a-texto
    - Vision Transformers: Aplicación a imágenes
    - LLaMA: Optimizaciones de arquitectura (RoPE, SwiGLU)
    
    ============================================================================
    """
    print(explanation)


