def troubleshooting_comun():
    """
    Soluciones a problemas comunes al trabajar con transformers.
    """
    print("\n" + "="*70)
    print("TROUBLESHOOTING: PROBLEMAS COMUNES Y SOLUCIONES")
    print("="*70)
    
    troubleshooting = """
    ┌─────────────────────────────────────────────────────────────────────┐
    │ PROBLEMA: Out of Memory (OOM)                                      │
    └─────────────────────────────────────────────────────────────────────┘
    
    SÍNTOMAS:
    - RuntimeError: CUDA out of memory
    - No hay suficiente memoria GPU
    
    SOLUCIONES:
    1. Reducir batch_size
    2. Reducir seq_len (longitud de secuencia)
    3. Usar gradient checkpointing
    4. Usar mixed precision (float16)
    5. Usar gradient accumulation
    6. Reducir d_model o número de bloques
    7. Usar Flash Attention
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ PROBLEMA: Loss no disminuye (NaN o Inf)                             │
    └─────────────────────────────────────────────────────────────────────┘
    
    SÍNTOMAS:
    - Loss = NaN o Inf
    - Modelo no aprende
    
    SOLUCIONES:
    1. Verificar inicialización de pesos
    2. Reducir learning rate
    3. Verificar gradient clipping
    4. Verificar que no hay división por cero
    5. Verificar que inputs están normalizados
    6. Usar Pre-LN en lugar de Post-LN
    7. Añadir warmup al learning rate
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ PROBLEMA: Modelo genera texto repetitivo                             │
    └─────────────────────────────────────────────────────────────────────┘
    
    SÍNTOMAS:
    - Genera las mismas palabras/frases
    - Falta de diversidad
    
    SOLUCIONES:
    1. Aumentar temperature en sampling
    2. Usar top-k o top-p sampling
    3. Añadir penalización de repetición
    4. Mejorar diversidad en entrenamiento
    5. Ajustar length penalty
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ PROBLEMA: Generación muy lenta                                     │
    └─────────────────────────────────────────────────────────────────────┘
    
    SÍNTOMAS:
    - Tarda mucho en generar cada token
    - No aprovecha GPU completamente
    
    SOLUCIONES:
    1. Usar KV-cache para evitar recalcular atención
    2. Generar en batch (múltiples secuencias)
    3. Usar torch.compile() para optimización
    4. Reducir tamaño del modelo si es posible
    5. Usar cuantización (INT8, FP16)
    6. Optimizar código de generación
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ PROBLEMA: Overfitting                                               │
    └─────────────────────────────────────────────────────────────────────┘
    
    SÍNTOMAS:
    - Loss de entrenamiento baja, loss de validación alta
    - Modelo memoriza datos de entrenamiento
    
    SOLUCIONES:
    1. Aumentar dropout
    2. Aumentar weight decay
    3. Usar más datos de entrenamiento
    4. Añadir regularización (label smoothing)
    5. Reducir capacidad del modelo
    6. Usar early stopping
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ PROBLEMA: Gradientes que se desvanecen o explotan                  │
    └─────────────────────────────────────────────────────────────────────┘
    
    SÍNTOMAS:
    - Gradientes muy pequeños (vanishing)
    - Gradientes muy grandes (exploding)
    
    SOLUCIONES:
    1. Usar residual connections (ya incluido)
    2. Usar Pre-LN (ya incluido)
    3. Gradient clipping
    4. Learning rate más bajo
    5. Inicialización cuidadosa de pesos
    6. Warmup de learning rate
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ PROBLEMA: Modelo no converge                                       │
    └─────────────────────────────────────────────────────────────────────┘
    
    SÍNTOMAS:
    - Loss no disminuye
    - Modelo no mejora
    
    SOLUCIONES:
    1. Verificar que datos están correctos
    2. Verificar que learning rate es apropiado
    3. Verificar que arquitectura es correcta
    4. Verificar que optimizador está configurado bien
    5. Probar con modelo más pequeño primero
    6. Verificar que hay suficientes datos
    7. Usar transfer learning (fine-tuning)
    """
    
    print(troubleshooting)


