class GradientMonitor:
    """
    Monitor de gradientes para debugging y análisis del entrenamiento.
    """
    
    @staticmethod
    def log_gradient_stats(model: nn.Module, step: int, writer=None):
        """
        Registra estadísticas de gradientes.
        
        :param model: Modelo a monitorear
        :param step: Paso actual de entrenamiento
        :param writer: TensorBoard writer (opcional)
        """
        grad_stats = {}
        
        for name, param in model.named_parameters():
            if param.grad is not None:
                grad_norm = param.grad.norm().item()
                grad_mean = param.grad.mean().item()
                grad_std = param.grad.std().item()
                grad_max = param.grad.max().item()
                grad_min = param.grad.min().item()
                
                grad_stats[name] = {
                    'norm': grad_norm,
                    'mean': grad_mean,
                    'std': grad_std,
                    'max': grad_max,
                    'min': grad_min
                }
                
                if writer:
                    writer.add_scalar(f'grad/norm/{name}', grad_norm, step)
                    writer.add_scalar(f'grad/mean/{name}', grad_mean, step)
                    writer.add_histogram(f'grad/hist/{name}', param.grad, step)
        
        return grad_stats
    
    @staticmethod
    def check_gradient_flow(model: nn.Module) -> dict:
        """
        Verifica el flujo de gradientes en el modelo.
        
        :param model: Modelo a verificar
        :return: Diccionario con estadísticas de gradientes
        """
        total_norm = 0.0
        param_count = 0
        zero_grad_count = 0
        
        for name, param in model.named_parameters():
            if param.requires_grad:
                param_count += 1
                if param.grad is not None:
                    param_norm = param.grad.data.norm(2)
                    total_norm += param_norm.item() ** 2
                else:
                    zero_grad_count += 1
        
        total_norm = total_norm ** (1. / 2)
        
        return {
            'total_norm': total_norm,
            'param_count': param_count,
            'zero_grad_count': zero_grad_count,
            'gradient_flow_healthy': zero_grad_count == 0 and total_norm > 0
        }


class ModelPruner:
    """
    Utilidad para podar (prune) modelos y reducir su tamaño.
    """
    
    @staticmethod
    def magnitude_pruning(
        model: nn.Module,
        pruning_ratio: float = 0.1,
        exclude_modules: Optional[list] = None
    ):
        """
        Poda basada en magnitud de pesos.
        
        :param model: Modelo a podar
        :param pruning_ratio: Ratio de pesos a eliminar (0.1 = 10%)
        :param exclude_modules: Módulos a excluir de la poda
        """
        if exclude_modules is None:
            exclude_modules = ['embedding', 'layer_norm', 'bias']
        
        pruned_count = 0
        total_params = 0
        
        for name, param in model.named_parameters():
            # Excluir módulos específicos
            if any(exclude in name for exclude in exclude_modules):
                continue
            
            if len(param.shape) >= 2:  # Solo matrices (no biases)
                total_params += param.numel()
                
                # Calcular threshold
                flat_param = param.data.abs().flatten()
                threshold = torch.quantile(flat_param, pruning_ratio)
                
                # Crear máscara
                mask = param.data.abs() > threshold
                param.data *= mask.float()
                
                pruned_count += (~mask).sum().item()
        
        print(f"✅ Poda completada: {pruned_count:,} pesos eliminados de {total_params:,} totales")
        print(f"   Ratio de poda: {pruned_count/total_params*100:.2f}%")
        
        return pruned_count, total_params


class WeightQuantizer:
    """
    Utilidad para cuantizar pesos del modelo (reducir precisión).
    """
    
    @staticmethod
    def quantize_to_int8(model: nn.Module):
        """
        Cuantiza pesos a int8.
        
        :param model: Modelo a cuantizar
        """
        for name, param in model.named_parameters():
            if len(param.shape) >= 2:  # Solo matrices
                # Calcular escala
                scale = param.data.abs().max() / 127.0
                
                # Cuantizar
                quantized = torch.round(param.data / scale).clamp(-128, 127)
                
                # Dequantizar (simular)
                param.data = quantized * scale
    
    @staticmethod
    def quantize_to_int4(model: nn.Module):
        """
        Cuantiza pesos a int4.
        
        :param model: Modelo a cuantizar
        """
        for name, param in model.named_parameters():
            if len(param.shape) >= 2:  # Solo matrices
                # Calcular escala
                scale = param.data.abs().max() / 7.0
                
                # Cuantizar
                quantized = torch.round(param.data / scale).clamp(-8, 7)
                
                # Dequantizar (simular)
                param.data = quantized * scale


class ModelDistiller:
    """
    Utilidad para distilling (distillation) de modelos grandes a pequeños.
    """
    
    @staticmethod
    def distillation_loss(
        student_logits: torch.Tensor,
        teacher_logits: torch.Tensor,
        temperature: float = 3.0,
        alpha: float = 0.5
    ) -> torch.Tensor:
        """
        Calcula loss de distillation.
        
        :param student_logits: Logits del estudiante
        :param teacher_logits: Logits del profesor
        :param temperature: Temperatura para softmax
        :param alpha: Peso entre distillation y hard loss
        :return: Loss combinado
        """
        # Softmax con temperatura
        student_probs = F.log_softmax(student_logits / temperature, dim=-1)
        teacher_probs = F.softmax(teacher_logits / temperature, dim=-1)
        
        # KL divergence
        distillation_loss = F.kl_div(student_probs, teacher_probs, reduction='batchmean')
        
        # Escalar por temperatura^2
        distillation_loss = distillation_loss * (temperature ** 2)
        
        return distillation_loss


class DataAugmentation:
    """
    Utilidades para augmentación de datos para transformers.
    """
    
    @staticmethod
    def random_token_masking(
        token_ids: torch.Tensor,
        mask_ratio: float = 0.15,
        mask_token_id: int = 50256,  # GPT-2 mask token
        vocab_size: int = 50257
    ) -> torch.Tensor:
        """
        Enmascara tokens aleatoriamente (similar a BERT).
        
        :param token_ids: IDs de tokens
        :param mask_ratio: Ratio de tokens a enmascarar
        :param mask_token_id: ID del token de máscara
        :param vocab_size: Tamaño del vocabulario
        :return: Tokens con máscara aplicada
        """
        masked = token_ids.clone()
        batch_size, seq_len = token_ids.shape
        
        # Seleccionar tokens aleatoriamente
        num_mask = int(seq_len * mask_ratio)
        for i in range(batch_size):
            mask_indices = torch.randperm(seq_len)[:num_mask]
            masked[i, mask_indices] = mask_token_id
        
        return masked
    
    @staticmethod
    def random_token_replacement(
        token_ids: torch.Tensor,
        replace_ratio: float = 0.1,
        vocab_size: int = 50257
    ) -> torch.Tensor:
        """
        Reemplaza tokens aleatoriamente.
        
        :param token_ids: IDs de tokens
        :param replace_ratio: Ratio de tokens a reemplazar
        :param vocab_size: Tamaño del vocabulario
        :return: Tokens con reemplazos
        """
        replaced = token_ids.clone()
        batch_size, seq_len = token_ids.shape
        
        num_replace = int(seq_len * replace_ratio)
        for i in range(batch_size):
            replace_indices = torch.randperm(seq_len)[:num_replace]
            random_tokens = torch.randint(0, vocab_size, (num_replace,))
            replaced[i, replace_indices] = random_tokens
        
        return replaced
    
    @staticmethod
    def sequence_shuffling(
        token_ids: torch.Tensor,
        shuffle_ratio: float = 0.1
    ) -> torch.Tensor:
        """
        Reordena secuencias aleatoriamente.
        
        :param token_ids: IDs de tokens
        :param shuffle_ratio: Ratio de secuencias a reordenar
        :return: Secuencias reordenadas
        """
        shuffled = token_ids.clone()
        batch_size, seq_len = token_ids.shape
        
        num_shuffle = int(batch_size * shuffle_ratio)
        shuffle_indices = torch.randperm(batch_size)[:num_shuffle]
        
        for idx in shuffle_indices:
            # Reordenar aleatoriamente dentro de la secuencia
            perm = torch.randperm(seq_len)
            shuffled[idx] = shuffled[idx][perm]
        
        return shuffled


class ModelCompressor:
    """
    Utilidad para comprimir modelos de diferentes formas.
    """
    
    @staticmethod
    def compress_with_svd(
        linear_layer: nn.Linear,
        rank: Optional[int] = None,
        compression_ratio: float = 0.5
    ) -> Tuple[nn.Linear, nn.Linear]:
        """
        Comprime una capa lineal usando SVD.
        
        :param linear_layer: Capa lineal a comprimir
        :param rank: Rango objetivo (opcional)
        :param compression_ratio: Ratio de compresión
        :return: Tuple de (U, V) capas lineales
        """
        weight = linear_layer.weight.data
        
        # SVD
        U, S, V = torch.svd(weight)
        
        # Determinar rango
        if rank is None:
            rank = int(weight.shape[0] * compression_ratio)
        
        # Truncar
        U_trunc = U[:, :rank]
        S_trunc = S[:rank]
        V_trunc = V[:, :rank]
        
        # Crear nuevas capas
        U_layer = nn.Linear(weight.shape[1], rank, bias=False)
        V_layer = nn.Linear(rank, weight.shape[0], bias=False)
        
        U_layer.weight.data = (U_trunc @ torch.diag(S_trunc)).T
        V_layer.weight.data = V_trunc.T
        
        return U_layer, V_layer
    
    @staticmethod
    def calculate_compression_ratio(
        original_params: int,
        compressed_params: int
    ) -> dict:
        """
        Calcula ratio de compresión.
        
        :param original_params: Número original de parámetros
        :param compressed_params: Número de parámetros comprimidos
        :return: Diccionario con estadísticas
        """
        ratio = compressed_params / original_params
        reduction = 1.0 - ratio
        
        return {
            'original_params': original_params,
            'compressed_params': compressed_params,
            'compression_ratio': ratio,
            'reduction_percentage': reduction * 100,
            'size_reduction': reduction
        }


class LearningRateFinder:
    """
    Utilidad para encontrar el learning rate óptimo.
    """
    
    @staticmethod
    def find_lr(
        model: CausalTransformer,
        train_loader,
        criterion,
        init_lr: float = 1e-8,
        final_lr: float = 1.0,
        num_iterations: int = 100,
        device: str = 'cpu'
    ) -> Tuple[list, list]:
        """
        Encuentra el learning rate óptimo usando el método de Smith.
        
        :param model: Modelo a entrenar
        :param train_loader: DataLoader de entrenamiento
        :param criterion: Función de pérdida
        :param init_lr: Learning rate inicial
        :param final_lr: Learning rate final
        :param num_iterations: Número de iteraciones
        :param device: Device para cómputo
        :return: Tuple de (learning_rates, losses)
        """
        model.train()
        model = model.to(device)
        
        # Guardar estado original
        original_state = {name: param.clone() for name, param in model.named_parameters()}
        
        optimizer = torch.optim.SGD(model.parameters(), lr=init_lr)
        scheduler = torch.optim.lr_scheduler.ExponentialLR(optimizer, gamma=(final_lr/init_lr)**(1/num_iterations))
        
        learning_rates = []
        losses = []
        
        data_iter = iter(train_loader)
        
        for i in range(num_iterations):
            try:
                batch = next(data_iter)
            except StopIteration:
                data_iter = iter(train_loader)
                batch = next(data_iter)
            
            inputs = batch['input_ids'].to(device)
            targets = batch['labels'].to(device)
            
            optimizer.zero_grad()
            logits = model(inputs)
            logits_flat = logits.view(-1, logits.size(-1))
            targets_flat = targets.view(-1)
            loss = criterion(logits_flat, targets_flat)
            
            loss.backward()
            optimizer.step()
            scheduler.step()
            
            learning_rates.append(optimizer.param_groups[0]['lr'])
            losses.append(loss.item())
        
        # Restaurar estado original
        for name, param in model.named_parameters():
            param.data.copy_(original_state[name])
        
        return learning_rates, losses


def create_training_script_example():
    """
    Crea un ejemplo completo de script de entrenamiento.
    
    :return: String con el código de ejemplo
    """
    example = '''
# ============================================================================
# EJEMPLO COMPLETO DE ENTRENAMIENTO
# ============================================================================

import torch
from torch.utils.data import Dataset, DataLoader
from transformer_architecture_explanation import (
    CausalTransformer,
    ModelTrainer,
    ModelEvaluator,
    TextGenerator,
    save_model_checkpoint,
    load_model_checkpoint
)

# 1. Crear dataset
class TextDataset(Dataset):
    def __init__(self, texts, tokenizer, max_length=128):
        self.texts = texts
        self.tokenizer = tokenizer
        self.max_length = max_length
    
    def __len__(self):
        return len(self.texts)
    
    def __getitem__(self, idx):
        text = self.texts[idx]
        tokens = self.tokenizer.encode(text)
        
        # Padding/truncate
        if len(tokens) > self.max_length:
            tokens = tokens[:self.max_length]
        else:
            tokens = tokens + [0] * (self.max_length - len(tokens))
        
        input_ids = torch.tensor(tokens[:-1])
        labels = torch.tensor(tokens[1:])
        
        return {'input_ids': input_ids, 'labels': labels}

# 2. Crear modelo
model = CausalTransformer(
    vocab_size=10000,
    d_model=512,
    n_heads=8,
    n_layers=6,
    d_ff=2048,
    max_seq_len=512,
    dropout=0.1
)

# 3. Crear optimizador y scheduler
optimizer = ModelTrainer.create_optimizer(
    model,
    lr=3e-4,
    optimizer_type='adamw'
)

scheduler = ModelTrainer.create_scheduler(
    optimizer,
    num_warmup_steps=1000,
    num_training_steps=10000,
    scheduler_type='cosine'
)

# 4. Criterio de pérdida
criterion = torch.nn.CrossEntropyLoss(ignore_index=-1)

# 5. DataLoader
train_dataset = TextDataset(train_texts, tokenizer)
train_loader = DataLoader(train_dataset, batch_size=32, shuffle=True)

# 6. Loop de entrenamiento
device = 'cuda' if torch.cuda.is_available() else 'cpu'
model = model.to(device)

for epoch in range(num_epochs):
    # Entrenar
    stats = ModelTrainer.train_epoch(
        model,
        train_loader,
        optimizer,
        criterion,
        device=device,
        gradient_clip=1.0,
        accumulation_steps=4
    )
    
    print(f"Epoch {epoch}: Loss={stats['loss']:.4f}, Perplexity={stats['perplexity']:.2f}")
    
    # Guardar checkpoint
    if (epoch + 1) % 10 == 0:
        save_model_checkpoint(
            model,
            optimizer,
            epoch,
            stats['loss'],
            f'checkpoint_epoch_{epoch}.pt'
        )
    
    # Actualizar learning rate
    scheduler.step()

# 7. Evaluar
eval_stats = ModelEvaluator.calculate_perplexity(model, eval_loader, device)
print(f"Perplexity en evaluación: {eval_stats:.2f}")

# 8. Generar texto
generator = TextGenerator(model)
prompt = torch.randint(0, 10000, (1, 10))
generated = generator.generate(
    prompt,
    max_length=100,
    temperature=0.8,
    top_k=50,
    top_p=0.9
)
'''
    
    return example


