def patrones_diseno_comunes():
    """
    Patrones de diseño comunes para transformers.
    """
    print("\n" + "="*70)
    print("PATRONES DE DISEÑO COMUNES")
    print("="*70)
    
    patrones = """
    ┌─────────────────────────────────────────────────────────────────────┐
    │ 1. MODEL FACTORY PATTERN                                            │
    └─────────────────────────────────────────────────────────────────────┘
    
    PROPÓSITO:
    - Crear modelos con diferentes configuraciones
    - Simplificar creación de modelos similares
    
    IMPLEMENTACIÓN:
    ```python
    class ModelFactory:
        @staticmethod
        def create_model(model_type: str, **kwargs):
            configs = {
                'small': {'d_model': 256, 'num_layers': 4, 'num_heads': 4},
                'medium': {'d_model': 512, 'num_layers': 6, 'num_heads': 8},
                'large': {'d_model': 1024, 'num_layers': 12, 'num_heads': 16}
            }
            config = configs.get(model_type, configs['medium'])
            config.update(kwargs)
            return CausalTransformer(**config)
    
    # Uso
    model = ModelFactory.create_model('small', vocab_size=10000)
    ```
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ 2. BUILDER PATTERN                                                   │
    └─────────────────────────────────────────────────────────────────────┘
    
    PROPÓSITO:
    - Construir modelos complejos paso a paso
    - Flexibilidad en configuración
    
    IMPLEMENTACIÓN:
    ```python
    class ModelBuilder:
        def __init__(self):
            self.reset()
        
        def reset(self):
            self.config = {}
            return self
        
        def with_vocab_size(self, size: int):
            self.config['vocab_size'] = size
            return self
        
        def with_d_model(self, d_model: int):
            self.config['d_model'] = d_model
            return self
        
        def with_layers(self, num_layers: int):
            self.config['num_layers'] = num_layers
            return self
        
        def build(self):
            return CausalTransformer(**self.config)
    
    # Uso
    model = (ModelBuilder()
             .with_vocab_size(10000)
             .with_d_model(512)
             .with_layers(6)
             .build())
    ```
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ 3. STRATEGY PATTERN                                                  │
    └─────────────────────────────────────────────────────────────────────┘
    
    PROPÓSITO:
    - Intercambiar algoritmos de generación
    - Flexibilidad en estrategias de sampling
    
    IMPLEMENTACIÓN:
    ```python
    class SamplingStrategy:
        def sample(self, logits, temperature=1.0):
            raise NotImplementedError
    
    class GreedySampling(SamplingStrategy):
        def sample(self, logits, temperature=1.0):
            return torch.argmax(logits, dim=-1)
    
    class TemperatureSampling(SamplingStrategy):
        def sample(self, logits, temperature=1.0):
            probs = F.softmax(logits / temperature, dim=-1)
            return torch.multinomial(probs, 1)
    
    class TopKSampling(SamplingStrategy):
        def sample(self, logits, temperature=1.0, k=50):
            top_k_logits, top_k_indices = torch.topk(logits, k, dim=-1)
            probs = F.softmax(top_k_logits / temperature, dim=-1)
            return torch.multinomial(probs, 1)
    
    # Uso
    strategy = TemperatureSampling()
    next_token = strategy.sample(logits, temperature=0.8)
    ```
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ 4. OBSERVER PATTERN                                                 │
    └─────────────────────────────────────────────────────────────────────┘
    
    PROPÓSITO:
    - Notificar cambios durante entrenamiento
    - Callbacks y logging
    
    IMPLEMENTACIÓN:
    ```python
    class TrainingObserver:
        def on_epoch_start(self, epoch):
            pass
        
        def on_epoch_end(self, epoch, loss):
            pass
        
        def on_batch_end(self, batch, loss):
            pass
    
    class LossLogger(TrainingObserver):
        def on_batch_end(self, batch, loss):
            print(f"Batch {batch}: Loss = {loss:.4f}")
    
    class ModelCheckpointer(TrainingObserver):
        def on_epoch_end(self, epoch, loss):
            torch.save(model.state_dict(), f"checkpoint_epoch_{epoch}.pt")
    
    # Uso
    observers = [LossLogger(), ModelCheckpointer()]
    for observer in observers:
        observer.on_epoch_start(epoch)
    ```
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ 5. DECORATOR PATTERN                                                │
    └─────────────────────────────────────────────────────────────────────┘
    
    PROPÓSITO:
    - Añadir funcionalidad a modelos sin modificar código
    - Wrappers para optimización
    
    IMPLEMENTACIÓN:
    ```python
    def torch_compile_decorator(model):
        return torch.compile(model, mode='reduce-overhead')
    
    def fp16_decorator(model):
        return model.half()
    
    def quantize_decorator(model):
        return torch.quantization.quantize_dynamic(
            model, {torch.nn.Linear}, dtype=torch.qint8
        )
    
    # Uso
    model = CausalTransformer(...)
    model = torch_compile_decorator(fp16_decorator(model))
    ```
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ 6. ADAPTER PATTERN                                                  │
    └─────────────────────────────────────────────────────────────────────┘
    
    PROPÓSITO:
    - Adaptar diferentes interfaces
    - Compatibilidad entre frameworks
    
    IMPLEMENTACIÓN:
    ```python
    class HuggingFaceAdapter:
        def __init__(self, model):
            self.model = model
        
        def generate(self, input_ids, **kwargs):
            # Adaptar nuestra interfaz a HF
            outputs = self.model(input_ids)
            return outputs.logits
    
    class ONNXAdapter:
        def __init__(self, model_path):
            self.session = ort.InferenceSession(model_path)
        
        def __call__(self, input_ids):
            # Adaptar a ONNX Runtime
            inputs = {self.session.get_inputs()[0].name: input_ids.numpy()}
            outputs = self.session.run(None, inputs)
            return torch.tensor(outputs[0])
    ```
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ 7. SINGLETON PATTERN                                                │
    └─────────────────────────────────────────────────────────────────────┘
    
    PROPÓSITO:
    - Una sola instancia de modelo cargado
    - Ahorrar memoria y tiempo de carga
    
    IMPLEMENTACIÓN:
    ```python
    class ModelSingleton:
        _instance = None
        _model = None
        
        def __new__(cls):
            if cls._instance is None:
                cls._instance = super().__new__(cls)
            return cls._instance
        
        def get_model(self):
            if self._model is None:
                self._model = CausalTransformer(...)
                self._model.load_state_dict(torch.load('model.pt'))
            return self._model
    
    # Uso
    model1 = ModelSingleton().get_model()
    model2 = ModelSingleton().get_model()  # Misma instancia
    ```
    """
    print(patrones)


def optimizaciones_por_hardware():
    """
    Optimizaciones específicas por hardware.
    """
    print("\n" + "="*70)
