def guia_migracion():
    """
    Guía de migración entre versiones y frameworks.
    """
    print("\n" + "="*70)
    print("GUÍA DE MIGRACIÓN")
    print("="*70)
    
    migracion = """
    ┌─────────────────────────────────────────────────────────────────────┐
    │ MIGRACIÓN: PYTORCH 1.x → 2.x                                       │
    └─────────────────────────────────────────────────────────────────────┘
    
    CAMBIOS PRINCIPALES:
    1. torch.compile() disponible
    2. Mejoras en DataLoader
    3. Cambios en nn.Module
    
    PASOS:
    ```python
    # ANTES (PyTorch 1.x)
    model = CausalTransformer(...)
    
    # DESPUÉS (PyTorch 2.x)
    model = CausalTransformer(...)
    model = torch.compile(model, mode='reduce-overhead')  # Nuevo
    ```
    
    COMPATIBILIDAD:
    - Código 1.x funciona en 2.x (backward compatible)
    - Usar torch.compile() para mejor rendimiento
    - Verificar que todas las operaciones soportadas
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ MIGRACIÓN: CUSTOM MODEL → HUGGING FACE                            │
    └─────────────────────────────────────────────────────────────────────┘
    
    PASOS:
    1. Crear configuración HF:
    ```python
    from transformers import GPT2Config, GPT2LMHeadModel
    
    config = GPT2Config(
        vocab_size=10000,
        n_positions=512,
        n_embd=512,
        n_layer=6,
        n_head=8,
        n_inner=2048
    )
    ```
    
    2. Mapear pesos:
    ```python
    def map_weights(custom_state_dict, hf_model):
        mapping = {
            'embedding.weight': 'transformer.wte.weight',
            'pos_encoding.weight': 'transformer.wpe.weight',
            # ... más mapeos
        }
        
        hf_state_dict = {}
        for custom_key, custom_value in custom_state_dict.items():
            hf_key = mapping.get(custom_key, custom_key)
            hf_state_dict[hf_key] = custom_value
        
        hf_model.load_state_dict(hf_state_dict)
        return hf_model
    ```
    
    3. Guardar en formato HF:
    ```python
    hf_model.save_pretrained('./hf_model')
    tokenizer.save_pretrained('./hf_model')
    ```
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ MIGRACIÓN: FP32 → FP16                                             │
    └─────────────────────────────────────────────────────────────────────┘
    
    PASOS:
    1. Convertir modelo:
    ```python
    model_fp16 = model.half()
    ```
    
    2. Usar autocast (recomendado):
    ```python
    from torch.cuda.amp import autocast
    
    with autocast():
        outputs = model(inputs)
    ```
    
    3. Verificar compatibilidad:
    - Algunas operaciones no soportan FP16
    - Usar autocast para conversión automática
    - GradScaler para evitar underflow
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ MIGRACIÓN: CPU → GPU                                                │
    └─────────────────────────────────────────────────────────────────────┘
    
    PASOS:
    1. Verificar disponibilidad:
    ```python
    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    ```
    
    2. Mover modelo y datos:
    ```python
    model = model.to(device)
    inputs = inputs.to(device)
    ```
    
    3. Verificar uso de GPU:
    ```python
    print(f"GPU: {torch.cuda.get_device_name(0)}")
    print(f"Memory: {torch.cuda.memory_allocated() / 1e9:.2f} GB")
    ```
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ MIGRACIÓN: PYTORCH → ONNX                                          │
    └─────────────────────────────────────────────────────────────────────┘
    
    PASOS:
    1. Exportar a ONNX:
    ```python
    from transformer_architecture_explanation import ModelExporter
    
    ModelExporter.export_to_onnx(
        model,
        'model.onnx',
        input_shape=(1, 512),
        dynamic_axes={'input_ids': {0: 'batch_size', 1: 'sequence_length'}}
    )
    ```
    
    2. Cargar en ONNX Runtime:
    ```python
    import onnxruntime as ort
    
    session = ort.InferenceSession('model.onnx')
    inputs = {session.get_inputs()[0].name: input_ids.numpy()}
    outputs = session.run(None, inputs)
    ```
    
    3. Verificar equivalencia:
    - Comparar outputs PyTorch vs ONNX
    - Tolerancia pequeña para diferencias numéricas
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ CHECKLIST DE MIGRACIÓN                                              │
    └─────────────────────────────────────────────────────────────────────┘
    
    ANTES DE MIGRAR:
    ☐ Backup del código y modelo actual
    ☐ Documentar configuración actual
    ☐ Entender cambios en nueva versión
    ☐ Leer changelog y breaking changes
    
    DURANTE MIGRACIÓN:
    ☐ Migrar paso a paso
    ☐ Probar cada cambio
    ☐ Verificar outputs equivalentes
    ☐ Documentar cambios realizados
    
    DESPUÉS DE MIGRAR:
    ☐ Ejecutar tests completos
    ☐ Verificar rendimiento
    ☐ Monitorear en producción
    ☐ Actualizar documentación
    """
    print(migracion)


def troubleshooting_especifico():
    """
    Troubleshooting específico para problemas comunes.
    """
    print("\n" + "="*70)
    print("TROUBLESHOOTING ESPECÍFICO")
    print("="*70)
    
    troubleshooting = """
    ┌─────────────────────────────────────────────────────────────────────┐
    │ PROBLEMA: CUDA OUT OF MEMORY                                        │
    └─────────────────────────────────────────────────────────────────────┘
    
    SÍNTOMAS:
    - RuntimeError: CUDA out of memory
    - GPU memory usage al 100%
    
    SOLUCIONES (en orden de prioridad):
    1. Reducir batch_size
       ```python
       dataloader = DataLoader(dataset, batch_size=8)  # Reducir de 32
       ```
    
    2. Usar gradient accumulation
       ```python
       accumulation_steps = 4
       for i, batch in enumerate(dataloader):
           loss = loss / accumulation_steps
           loss.backward()
           if (i + 1) % accumulation_steps == 0:
               optimizer.step()
               optimizer.zero_grad()
       ```
    
    3. Usar FP16
       ```python
       from torch.cuda.amp import autocast, GradScaler
       scaler = GradScaler()
       with autocast():
           outputs = model(inputs)
       ```
    
    4. Gradient checkpointing
       ```python
       from torch.utils.checkpoint import checkpoint
       outputs = checkpoint(model, inputs)
       ```
    
    5. Reducir sequence length
       ```python
       max_seq_length = 256  # Reducir de 512
       ```
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ PROBLEMA: LOSS NO DISMINUYE                                         │
    └─────────────────────────────────────────────────────────────────────┘
    
    SÍNTOMAS:
    - Loss constante o aumentando
    - Modelo no aprende
    
    DIAGNÓSTICO:
    1. Verificar learning rate
       ```python
       print(f"LR: {optimizer.param_groups[0]['lr']}")
       # Debería estar entre 1e-5 y 1e-3
       ```
    
    2. Verificar gradientes
       ```python
       for name, param in model.named_parameters():
           if param.grad is not None:
               print(f"{name}: {param.grad.norm().item()}")
       # Deberían ser > 1e-6 y < 10
       ```
    
    3. Verificar datos
       ```python
       print(f"Input range: [{inputs.min()}, {inputs.max()}]")
       print(f"Target range: [{targets.min()}, {targets.max()}]")
       ```
    
    SOLUCIONES:
    1. Ajustar learning rate
       ```python
       optimizer = torch.optim.AdamW(model.parameters(), lr=3e-4)
       ```
    
    2. Añadir warmup
       ```python
       scheduler = get_linear_schedule_with_warmup(
           optimizer, warmup_steps=1000, total_steps=10000
       )
       ```
    
    3. Verificar formato de datos
       - Targets deben ser inputs[:, 1:]
       - Loss debe ser CrossEntropyLoss
    
    4. Revisar inicialización
       ```python
       # Usar inicialización estándar
       for module in model.modules():
           if isinstance(module, nn.Linear):
               nn.init.xavier_uniform_(module.weight)
       ```
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ PROBLEMA: GENERACIÓN REPETITIVA                                    │
    └─────────────────────────────────────────────────────────────────────┘
    
    SÍNTOMAS:
    - Mismo texto generado repetidamente
    - Falta de diversidad
    
    SOLUCIONES:
    1. Aumentar temperature
       ```python
       temperature = 1.0  # Aumentar de 0.7
       probs = torch.softmax(logits / temperature, dim=-1)
       ```
    
    2. Usar top-k sampling
       ```python
       top_k = 50
       top_k_logits, top_k_indices = torch.topk(logits, top_k, dim=-1)
       probs = torch.softmax(top_k_logits / temperature, dim=-1)
       ```
    
    3. Usar nucleus sampling
       ```python
       top_p = 0.9
       sorted_logits, sorted_indices = torch.sort(logits, descending=True)
       cumulative_probs = torch.cumsum(torch.softmax(sorted_logits, dim=-1), dim=-1)
       sorted_indices_to_remove = cumulative_probs > top_p
       ```
    
    4. Añadir penalización por repetición
       ```python
       def apply_repetition_penalty(logits, prev_tokens, penalty=1.2):
           for token in prev_tokens:
               logits[token] /= penalty
           return logits
       ```
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ PROBLEMA: MODELO MUY LENTO                                          │
    └─────────────────────────────────────────────────────────────────────┘
    
    SÍNTOMAS:
    - Inferencia muy lenta
    - Entrenamiento muy lento
    
    DIAGNÓSTICO:
    1. Profiling
       ```python
       from torch.profiler import profile
       with profile() as prof:
           outputs = model(inputs)
       print(prof.key_averages().table())
       ```
    
    2. Verificar uso de GPU
       ```python
       print(f"GPU utilization: {get_gpu_utilization()}%")
       # Debería ser > 80%
       ```
    
    SOLUCIONES:
    1. Usar torch.compile()
       ```python
       model = torch.compile(model, mode='reduce-overhead')
       ```
    
    2. Optimizar DataLoader
       ```python
       dataloader = DataLoader(
           dataset,
           batch_size=32,
           num_workers=4,  # Paralelizar carga
           pin_memory=True  # Transferencia rápida a GPU
       )
       ```
    
    3. Usar FP16
       ```python
       model = model.half()
       ```
    
    4. Batch más grande
       ```python
       batch_size = 64  # Aumentar si memoria permite
       ```
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ PROBLEMA: VALORES NaN EN LOSS                                      │
    └─────────────────────────────────────────────────────────────────────┘
    
    SÍNTOMAS:
    - loss.item() es NaN
    - Modelo no entrena
    
    DIAGNÓSTICO:
    1. Verificar inputs
       ```python
       if torch.isnan(inputs).any():
           print("NaN en inputs")
       if torch.isinf(inputs).any():
           print("Inf en inputs")
       ```
    
    2. Verificar activaciones
       ```python
       def check_activations(model, inputs):
           for name, module in model.named_modules():
               if isinstance(module, nn.Linear):
                   output = module(inputs)
                   if torch.isnan(output).any():
                       print(f"NaN en {name}")
       ```
    
    SOLUCIONES:
    1. Gradient clipping
       ```python
       torch.nn.utils.clip_grad_norm_(model.parameters(), 1.0)
       ```
    
    2. Reducir learning rate
       ```python
       optimizer = torch.optim.AdamW(model.parameters(), lr=1e-4)
       ```
    
    3. Verificar datos
       - Remover NaN/Inf de dataset
       - Normalizar inputs si necesario
    
    4. Usar GradScaler con FP16
       ```python
       scaler = GradScaler()
       scaler.scale(loss).backward()
       scaler.step(optimizer)
       scaler.update()
       ```
    """
    print(troubleshooting)


