    class AutoRollback:
        def __init__(self, threshold_error_rate=0.05):
            self.threshold_error_rate = threshold_error_rate
            self.monitoring_window = 60  # 60 segundos
        
        def check_health(self):
            # Obtener métricas de últimos 60 segundos
            error_rate = get_error_rate(self.monitoring_window)
            
            if error_rate > self.threshold_error_rate:
                self.trigger_rollback()
        
        def trigger_rollback(self):
            # Obtener versión anterior
            previous_version = get_previous_version()
            
            # Rollback
            kubectl.rollback('transformer', previous_version)
            
            # Notificar
            send_alert(f"Auto-rollback triggered to {previous_version}")
