def tecnicas_avanzadas_entrenamiento():
    """
    Técnicas avanzadas de entrenamiento para transformers.
    """
    print("\n" + "="*70)
    print("TÉCNICAS AVANZADAS DE ENTRENAMIENTO")
    print("="*70)
    
    tecnicas = """
    ┌─────────────────────────────────────────────────────────────────────┐
    │ 1. DISTILLATION (KNOWLEDGE DISTILLATION)                           │
    └─────────────────────────────────────────────────────────────────────┘
    
    CONCEPTO:
    - Entrenar modelo pequeño (estudiante) con modelo grande (maestro)
    - Transferir conocimiento del maestro al estudiante
    - Modelo pequeño más eficiente pero con mejor calidad
    
    IMPLEMENTACIÓN:
    ```python
    class KnowledgeDistiller:
        def __init__(self, teacher_model, student_model, temperature=3.0):
            self.teacher = teacher_model
            self.student = student_model
            self.temperature = temperature
        
        def distill_loss(self, student_logits, teacher_logits, targets, alpha=0.5):
            # Soft targets del maestro
            soft_targets = F.softmax(teacher_logits / self.temperature, dim=-1)
            soft_prob = F.log_softmax(student_logits / self.temperature, dim=-1)
            
            # Soft loss (distillation)
            soft_loss = F.kl_div(soft_prob, soft_targets, reduction='batchmean')
            soft_loss *= (self.temperature ** 2)
            
            # Hard loss (ground truth)
            hard_loss = F.cross_entropy(student_logits, targets)
            
            # Combinar
            return alpha * soft_loss + (1 - alpha) * hard_loss
        
        def train_distillation(self, dataloader, optimizer):
            self.teacher.eval()
            self.student.train()
            
            for batch in dataloader:
                with torch.no_grad():
                    teacher_logits = self.teacher(batch)
                
                student_logits = self.student(batch)
                loss = self.distill_loss(student_logits, teacher_logits, batch.targets)
                
                optimizer.zero_grad()
                loss.backward()
                optimizer.step()
    ```
    
    BENEFICIOS:
    ✅ Modelo 10-100x más pequeño
    ✅ Inferencia 5-10x más rápida
    ✅ Calidad cercana al maestro
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ 2. CURRICULUM LEARNING                                              │
    └─────────────────────────────────────────────────────────────────────┘
    
    CONCEPTO:
    - Entrenar con ejemplos fáciles primero
    - Gradualmente aumentar dificultad
    - Mejor convergencia y generalización
    
    IMPLEMENTACIÓN:
    ```python
    class CurriculumLearning:
        def __init__(self, difficulty_fn):
            self.difficulty_fn = difficulty_fn  # Función que calcula dificultad
        
        def get_training_order(self, dataset):
            # Calcular dificultad de cada ejemplo
            difficulties = [(i, self.difficulty_fn(ex)) for i, ex in enumerate(dataset)]
            
            # Ordenar por dificultad
            difficulties.sort(key=lambda x: x[1])
            
            # Retornar índices ordenados
            return [idx for idx, _ in difficulties]
        
        def schedule_difficulty(self, epoch, max_epochs):
            # Aumentar dificultad gradualmente
            progress = epoch / max_epochs
            max_difficulty = 1.0
            current_difficulty = progress * max_difficulty
            return current_difficulty
        
        def filter_dataset(self, dataset, current_difficulty):
            # Filtrar ejemplos por dificultad actual
            filtered = [
                ex for ex in dataset
                if self.difficulty_fn(ex) <= current_difficulty
            ]
            return filtered
    
    # Uso
    def calculate_difficulty(example):
        # Ejemplo: longitud del texto
        return len(example['text'].split()) / 1000.0
    
    curriculum = CurriculumLearning(calculate_difficulty)
    for epoch in range(num_epochs):
        difficulty = curriculum.schedule_difficulty(epoch, num_epochs)
        filtered_dataset = curriculum.filter_dataset(dataset, difficulty)
        train_epoch(model, filtered_dataset)
    ```
    
    BENEFICIOS:
    ✅ Convergencia más rápida
    ✅ Mejor generalización
    ✅ Más estable
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ 3. MIXUP Y CUTMIX                                                    │
    └─────────────────────────────────────────────────────────────────────┘
    
    CONCEPTO:
    - Mezclar ejemplos de entrenamiento
    - Crear nuevos ejemplos sintéticos
    - Mejor regularización
    
    IMPLEMENTACIÓN:
    ```python
    class MixupAugmentation:
        def __init__(self, alpha=0.2):
            self.alpha = alpha
        
        def mixup_data(self, x, y):
            if self.alpha > 0:
                lam = np.random.beta(self.alpha, self.alpha)
            else:
                lam = 1
            
            batch_size = x.size(0)
            index = torch.randperm(batch_size).to(x.device)
            
            mixed_x = lam * x + (1 - lam) * x[index, :]
            y_a, y_b = y, y[index]
            return mixed_x, y_a, y_b, lam
        
        def mixup_criterion(self, criterion, pred, y_a, y_b, lam):
            return lam * criterion(pred, y_a) + (1 - lam) * criterion(pred, y_b)
    
    # Uso
    mixup = MixupAugmentation(alpha=0.2)
    for batch in dataloader:
        x, y = batch
        mixed_x, y_a, y_b, lam = mixup.mixup_data(x, y)
        outputs = model(mixed_x)
        loss = mixup.mixup_criterion(criterion, outputs, y_a, y_b, lam)
    ```
    
    BENEFICIOS:
    ✅ Mejor regularización
    ✅ Más robusto
    ✅ Menos overfitting
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ 4. SWA (STOCHASTIC WEIGHT AVERAGING)                                │
    └─────────────────────────────────────────────────────────────────────┘
    
    CONCEPTO:
    - Promediar pesos de múltiples checkpoints
    - Mejor generalización
    - Más estable
    
    IMPLEMENTACIÓN:
    ```python
    class SWA:
        def __init__(self, model):
            self.model = model
            self.swa_model = copy.deepcopy(model)
            self.n_averaged = 0
        
        def update(self, epoch, start_epoch=160):
            if epoch >= start_epoch:
                # Promediar pesos
                for swa_param, param in zip(self.swa_model.parameters(), self.model.parameters()):
                    swa_param.data = (self.n_averaged * swa_param.data + param.data) / (self.n_averaged + 1)
                self.n_averaged += 1
        
        def swap_weights(self):
            # Intercambiar pesos para evaluación
            for swa_param, param in zip(self.swa_model.parameters(), self.model.parameters()):
                param.data, swa_param.data = swa_param.data, param.data
        
        def reset_bn_stats(self, dataloader):
            # Recalcular BatchNorm stats con SWA model
            self.swa_model.train()
            for batch in dataloader:
                _ = self.swa_model(batch)
    
    # Uso
    swa = SWA(model)
    for epoch in range(num_epochs):
        train_epoch(model, dataloader)
        swa.update(epoch, start_epoch=num_epochs * 0.75)
    
    # Evaluar con SWA
    swa.swap_weights()
    swa.reset_bn_stats(val_dataloader)
    evaluate(model, val_dataloader)
    ```
    
    BENEFICIOS:
    ✅ Mejor generalización
    ✅ Más estable
    ✅ Mejor test accuracy
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ 5. ADVERSARIAL TRAINING                                             │
    └─────────────────────────────────────────────────────────────────────┘
    
    CONCEPTO:
    - Entrenar con ejemplos adversarios
    - Mejor robustez
    - Más resistente a ataques
    
    IMPLEMENTACIÓN:
    ```python
    class AdversarialTraining:
        def __init__(self, model, epsilon=0.01):
            self.model = model
            self.epsilon = epsilon
        
        def generate_adversarial(self, x, y):
            # Calcular perturbación adversaria
            x.requires_grad = True
            outputs = self.model(x)
            loss = F.cross_entropy(outputs, y)
            loss.backward()
            
            # Perturbación
            perturbation = self.epsilon * x.grad.sign()
            x_adv = x + perturbation
            
            return x_adv.detach()
        
        def train_adversarial(self, dataloader, optimizer):
            for batch in dataloader:
                x, y = batch
                
                # Ejemplos normales
                outputs_normal = self.model(x)
                loss_normal = F.cross_entropy(outputs_normal, y)
                
                # Ejemplos adversarios
                x_adv = self.generate_adversarial(x, y)
                outputs_adv = self.model(x_adv)
                loss_adv = F.cross_entropy(outputs_adv, y)
                
                # Combinar
                total_loss = loss_normal + 0.5 * loss_adv
                
                optimizer.zero_grad()
                total_loss.backward()
                optimizer.step()
    ```
    
    BENEFICIOS:
    ✅ Más robusto
    ✅ Resistente a ataques
    ✅ Mejor generalización
    """
    print(tecnicas)


