    def benchmark_scalability(model, batch_sizes=[1, 8, 16, 32, 64]):
        """Benchmark con diferentes batch sizes"""
        results = {}
        
        for batch_size in batch_sizes:
            inputs = torch.randn(batch_size, 512).to('cuda')
            
            # Latency
            start = time.time()
            with torch.no_grad():
                _ = model(inputs)
            torch.cuda.synchronize()
            latency = (time.time() - start) * 1000
            
            # Throughput
            throughput = batch_size / (latency / 1000)
            
            results[batch_size] = {
                'latency_ms': latency,
                'throughput_samples_per_sec': throughput
            }
        
        return results
    
    # Analizar
    scalability_results = benchmark_scalability(model)
    for batch_size, metrics in scalability_results.items():
        print(f"Batch {batch_size}: {metrics['throughput_samples_per_sec']:.2f} samples/sec")
