    def benchmark_cost(model, num_requests, gpu_cost_per_hour=3.0):
        """Calcular costo de inferencia"""
        # Benchmark throughput
        throughput = benchmark_throughput(model, (1, 512), duration=60)
        
        # Tiempo total
        total_time_hours = num_requests / throughput / 3600
        
        # Costo
        total_cost = total_time_hours * gpu_cost_per_hour
        cost_per_request = total_cost / num_requests
        
