        # Visualizar
        plt.hist(all_probs.max(dim=-1)[0].numpy(), bins=50)
        plt.xlabel('Confidence')
        plt.ylabel('Frequency')
        plt.title('Output Confidence Distribution')
        plt.show()
        
        return stats
