    import logging
    import json
    from datetime import datetime
    
    class ProductionLogger:
        def __init__(self, log_file='production.log'):
            self.logger = logging.getLogger('production')
            self.logger.setLevel(logging.INFO)
            
            handler = logging.FileHandler(log_file)
            formatter = logging.Formatter(
                '%(asctime)s - %(name)s - %(levelname)s - %(message)s'
            )
            handler.setFormatter(formatter)
            self.logger.addHandler(handler)
        
        def log_request(self, request_id, input_text, output_text, metadata):
            """Log request completo"""
            log_entry = {
                'request_id': request_id,
                'timestamp': datetime.now().isoformat(),
                'input': input_text,
                'output': output_text,
                'metadata': metadata
            }
            
            self.logger.info(json.dumps(log_entry))
        
        def log_error(self, request_id, error, traceback):
            """Log error"""
            log_entry = {
                'request_id': request_id,
                'timestamp': datetime.now().isoformat(),
                'error': str(error),
                'traceback': traceback
            }
            
            self.logger.error(json.dumps(log_entry))
        
        def log_metrics(self, metrics):
            """Log métricas"""
            log_entry = {
                'timestamp': datetime.now().isoformat(),
                'metrics': metrics
            }
            
