    class AlertSystem:
        def __init__(self):
            self.alert_rules = []
            self.notification_channels = []
        
        def add_alert_rule(self, condition, severity='warning'):
            """Añadir regla de alerta"""
            self.alert_rules.append({
                'condition': condition,
                'severity': severity
            })
        
        def check_alerts(self, metrics):
            """Verificar alertas"""
            triggered_alerts = []
            
            for rule in self.alert_rules:
                if rule['condition'](metrics):
                    alert = {
                        'rule': rule,
                        'timestamp': datetime.now(),
                        'metrics': metrics
                    }
                    triggered_alerts.append(alert)
                    self.send_notification(alert)
            
            return triggered_alerts
        
        def send_notification(self, alert):
            """Enviar notificación"""
            message = f"Alert: {alert['rule']['severity'].upper()}\\n"
            message += f"Time: {alert['timestamp']}\\n"
            message += f"Metrics: {alert['metrics']}"
            
            for channel in self.notification_channels:
                channel.send(message)
        
        # Ejemplo de reglas
        def setup_default_rules(self):
            """Configurar reglas por defecto"""
            # Alta latencia
            self.add_alert_rule(
                lambda m: m.get('latency_p95', 0) > 1000,  # > 1s
                severity='critical'
            )
            
            # Alta tasa de error
            self.add_alert_rule(
                lambda m: m.get('error_rate', 0) > 0.05,  # > 5%
                severity='critical'
            )
            
            # Alta memoria
            self.add_alert_rule(
                lambda m: m.get('memory_usage', 0) > 90,  # > 90%
                severity='warning'
            )
