    class CombinedCompression:
        def compress_pipeline(self, model, dataloader):
            """Pipeline de compresión combinada"""
            # 1. Pruning
            pruner = MagnitudePruning(sparsity=0.5)
            model = pruner.prune_model(model)
            
            # 2. Fine-tune
            self.fine_tune(model, dataloader, epochs=5)
            
            # 3. Low-rank factorization
            factorizer = LowRankFactorization()
            model = factorizer.compress_model(model, rank_ratio=0.5)
            
            # 4. Fine-tune again
            self.fine_tune(model, dataloader, epochs=5)
            
            # 5. Quantization
            quantizer = PostTrainingQuantization()
            model = quantizer.quantize_model(model, dataloader)
            
            return model
