    class SentenceShuffling:
        def shuffle_sentences(self, text):
            """Mezclar oraciones"""
            sentences = text.split('.')
            sentences = [s.strip() for s in sentences if s.strip()]
            
            # Mezclar
            random.shuffle(sentences)
            
            return '. '.join(sentences) + '.'
