    class AdversarialAugmentation:
        def __init__(self, model):
            self.model = model
        
        def generate_adversarial_examples(self, text, label):
            """Generar ejemplos adversarios"""
            # Tokenizar
            tokens = tokenizer.encode(text)
            tokens_tensor = torch.tensor([tokens]).requires_grad_(True)
            
            # Forward
            outputs = self.model(tokens_tensor)
            loss = criterion(outputs, label)
            
            # Backward
            loss.backward()
            
            # Perturbación
            perturbation = tokens_tensor.grad.sign() * epsilon
            adversarial_tokens = tokens_tensor + perturbation
            
            # Decodificar
            adversarial_text = tokenizer.decode(adversarial_tokens[0])
            
            return adversarial_text
