    class ModelABTesting:
        def __init__(self):
            self.active_models = {}
        
        def deploy_ab_test(self, model_a, model_b, traffic_split=0.5):
            """Desplegar A/B test"""
            self.active_models = {
                'A': {
                    'model': model_a,
                    'traffic': traffic_split,
                    'metrics': []
                },
                'B': {
                    'model': model_b,
                    'traffic': 1 - traffic_split,
                    'metrics': []
                }
            }
        
        def route_request(self, request):
            """Enrutar request a modelo"""
            rand = random.random()
            
            if rand < self.active_models['A']['traffic']:
                model = self.active_models['A']['model']
                variant = 'A'
            else:
                model = self.active_models['B']['model']
                variant = 'B'
            
            # Procesar
            result = model(request)
            
            # Log métricas
            self.log_metrics(variant, result)
            
            return result
        
        def analyze_results(self):
            """Analizar resultados de A/B test"""
            metrics_a = self.active_models['A']['metrics']
            metrics_b = self.active_models['B']['metrics']
            
            # Comparar métricas
            comparison = {
                'accuracy': {
                    'A': np.mean([m['accuracy'] for m in metrics_a]),
                    'B': np.mean([m['accuracy'] for m in metrics_b])
                },
                'latency': {
                    'A': np.mean([m['latency'] for m in metrics_a]),
                    'B': np.mean([m['latency'] for m in metrics_b])
                }
            }
            
            return comparison
