    def get_warmup_lr(step, warmup_steps, base_lr):
        if step < warmup_steps:
            return base_lr * (step / warmup_steps)
        return base_lr
    
    lr = get_warmup_lr(current_step, warmup_steps=1000, base_lr=2e-5)
