    # 1. Crear modelo handler
    class TransformerHandler(BaseHandler):
        def initialize(self, context):
            self.model = load_model('model.pt')
            self.tokenizer = load_tokenizer()
            self.device = 'cuda' if torch.cuda.is_available() else 'cpu'
            self.model.to(self.device)
            self.model.eval()
        
        def preprocess(self, requests):
            """Preprocesar requests"""
            texts = [req['body']['text'] for req in requests]
            inputs = self.tokenizer(
                texts,
                padding=True,
                truncation=True,
                return_tensors='pt'
            )
            return inputs.to(self.device)
        
        def inference(self, inputs):
            """Inferencia"""
            with torch.no_grad():
                outputs = self.model(**inputs)
            return outputs
        
        def postprocess(self, outputs):
            """Postprocesar outputs"""
            predictions = outputs.logits.argmax(dim=-1)
            return [{'prediction': pred.item()} for pred in predictions]
    
    # 2. Crear .mar file
