    class HealthChecker:
        def __init__(self, model):
            self.model = model
            self.last_check = time.time()
            self.healthy = True
        
        def check_health(self):
            """Verificar salud del sistema"""
            checks = {
                'model_loaded': self.model is not None,
                'gpu_available': torch.cuda.is_available(),
                'memory_ok': self._check_memory(),
                'model_responsive': self._check_model_responsive()
            }
            
            self.healthy = all(checks.values())
            self.last_check = time.time()
            
            return {
                'healthy': self.healthy,
                'checks': checks,
                'timestamp': self.last_check
            }
        
        def _check_memory(self):
            """Verificar memoria"""
            if torch.cuda.is_available():
                allocated = torch.cuda.memory_allocated() / 1e9
                reserved = torch.cuda.memory_reserved() / 1e9
                return allocated < 10 and reserved < 12  # GB
            return True
        
        def _check_model_responsive(self):
            """Verificar que modelo responde"""
            try:
                test_input = torch.randn(1, 10)
                with torch.no_grad():
                    _ = self.model(test_input)
                return True
            except:
                return False
