    class CPUOffloader:
        def __init__(self, model):
            self.model = model
            # Mover capas inferiores a CPU
            self.cpu_layers = model.layers[:6]
            self.gpu_layers = model.layers[6:]
            
            for layer in self.cpu_layers:
                layer.cpu()
            for layer in self.gpu_layers:
                layer.cuda()
        
        def forward(self, x):
            # Forward en CPU
            for layer in self.cpu_layers:
                x = layer(x.cpu()).cuda()
            
            # Forward en GPU
            for layer in self.gpu_layers:
                x = layer(x)
            
            return x
