    def speculative_decode(draft_model, target_model, prompt, gamma=4):
        """Decodificación especulativa"""
        # Generar gamma tokens con draft
        draft_tokens = draft_model.generate(prompt, num_tokens=gamma)
        
        # Verificar con target
        verified = []
        for token in draft_tokens:
            if verify_token(target_model, prompt + verified, token):
                verified.append(token)
            else:
                # Rechazar y muestrear nuevo
                verified.append(sample_token(target_model, prompt + verified))
                break
        
