    class InferenceCostCalculator:
        def __init__(self, gpu_cost_per_hour=3.0):
            self.gpu_cost_per_hour = gpu_cost_per_hour
        
        def calculate_inference_cost(self, num_requests, avg_latency_ms, 
                                    batch_size=1, gpu_utilization=0.8):
            """Calcular costo de inferencia"""
            # Tiempo total de GPU
            total_time_seconds = (num_requests * avg_latency_ms / 1000) / batch_size
            total_gpu_hours = total_time_seconds / 3600 / gpu_utilization
            
            # Costo
            total_cost = total_gpu_hours * self.gpu_cost_per_hour
            cost_per_request = total_cost / num_requests
            
            return {
                'total_gpu_hours': total_gpu_hours,
                'total_cost_usd': total_cost,
                'cost_per_request': cost_per_request,
                'requests_per_dollar': 1 / cost_per_request if cost_per_request > 0 else float('inf')
            }
        
        def optimize_batch_size(self, model, input_shape, max_batch_size=64):
            """Encontrar batch size óptimo para costo"""
            best_batch_size = 1
            best_cost_per_request = float('inf')
            
            for batch_size in range(1, max_batch_size + 1):
                try:
                    # Medir latencia
                    inputs = torch.randn(batch_size, *input_shape).cuda()
                    latency = self.measure_latency(model, inputs)
                    
                    # Calcular costo
                    cost = self.calculate_inference_cost(
                        1000, latency, batch_size
                    )
                    
                    if cost['cost_per_request'] < best_cost_per_request:
                        best_cost_per_request = cost['cost_per_request']
                        best_batch_size = batch_size
                except RuntimeError:
                    # Out of memory
                    break
            
            return best_batch_size, best_cost_per_request
