    def select_cost_effective_model(task_complexity, budget, latency_requirement):
        """Seleccionar modelo balanceando costo y calidad"""
        models = {
            'small': {
                'cost_per_hour': 0.5,
                'quality_score': 0.7,
                'latency_ms': 50
            },
            'medium': {
                'cost_per_hour': 2.0,
                'quality_score': 0.85,
                'latency_ms': 100
            },
            'large': {
                'cost_per_hour': 5.0,
                'quality_score': 0.95,
                'latency_ms': 200
            }
        }
        
        # Filtrar por requisitos
        viable = [
            (name, specs) for name, specs in models.items()
            if specs['latency_ms'] <= latency_requirement
        ]
        
        # Seleccionar mejor relación calidad/costo
        best = max(viable, key=lambda x: x[1]['quality_score'] / x[1]['cost_per_hour'])
        
        return best[0]
