    class ROIAnalysis:
        def calculate_roi(self, training_cost, inference_cost_per_month, 
                         monthly_revenue, months=12):
            """Calcular ROI"""
            total_inference_cost = inference_cost_per_month * months
            total_cost = training_cost + total_inference_cost
            
            total_revenue = monthly_revenue * months
            profit = total_revenue - total_cost
            roi = (profit / total_cost) * 100 if total_cost > 0 else 0
            
            return {
                'total_cost': total_cost,
                'total_revenue': total_revenue,
                'profit': profit,
                'roi_percent': roi,
                'payback_months': total_cost / monthly_revenue if monthly_revenue > 0 else float('inf')
            }
        
        def compare_models_roi(self, models):
            """Comparar ROI de diferentes modelos"""
            results = {}
            for name, model_specs in models.items():
                roi = self.calculate_roi(
                    model_specs['training_cost'],
                    model_specs['monthly_inference_cost'],
                    model_specs['monthly_revenue']
                )
                results[name] = roi
            
            return results
