            """Detectar degradación en performance"""
            if len(self.evaluation_history) < 2:
                return False
            
            recent = self.evaluation_history[-1]['results']
            previous = self.evaluation_history[-2]['results']
            
            # Degradación si accuracy baja > 5%
            if recent['accuracy'] < previous['accuracy'] * 0.95:
                return True
            
            return False
        
