    class ModelRegistry:
        def __init__(self):
            self.registry = {}
        
        def register_model(self, model_name, version, model_path, 
                          metrics, metadata):
            """Registrar modelo en registry"""
            self.registry[f"{model_name}:{version}"] = {
                'model_path': model_path,
                'metrics': metrics,
                'metadata': metadata,
                'timestamp': datetime.now(),
                'status': 'staging'
            }
        
        def promote_model(self, model_name, version, target_status='production'):
            """Promover modelo a producción"""
            key = f"{model_name}:{version}"
            if key in self.registry:
                # Deprecar modelo anterior
                self.deprecate_current_production(model_name)
                
                # Promover nuevo modelo
                self.registry[key]['status'] = target_status
                self.registry[key]['promoted_at'] = datetime.now()
        
        def get_production_model(self, model_name):
            """Obtener modelo en producción"""
            for key, model_info in self.registry.items():
                if key.startswith(model_name) and model_info['status'] == 'production':
                    return model_info
            
            return None
