    class ModelMonitoring:
        def __init__(self, model, reference_data):
            self.model = model
            self.reference_data = reference_data
            self.baseline_metrics = self.calculate_baseline()
        
        def monitor_drift(self, new_data):
            """Monitorear data drift"""
            new_metrics = self.calculate_metrics(new_data)
            
            drift_score = self.calculate_drift_score(
                self.baseline_metrics,
                new_metrics
            )
            
            if drift_score > 0.1:  # Threshold
                return {
                    'drift_detected': True,
                    'drift_score': drift_score,
                    'alert': True
                }
            
            return {
                'drift_detected': False,
                'drift_score': drift_score,
                'alert': False
            }
        
        def monitor_performance(self, predictions, actuals):
            """Monitorear performance"""
            current_accuracy = self.calculate_accuracy(predictions, actuals)
            baseline_accuracy = self.baseline_metrics['accuracy']
            
            degradation = baseline_accuracy - current_accuracy
            
            if degradation > 0.05:  # 5% degradación
                return {
                    'degradation_detected': True,
                    'degradation': degradation,
                    'alert': True
                }
            
            return {
                'degradation_detected': False,
                'degradation': degradation,
                'alert': False
            }
