def guia_arquitecturas_especializadas():
    """
    Guía de arquitecturas especializadas de transformers.
    """
    print("\n" + "="*70)
    print("GUÍA DE ARQUITECTURAS ESPECIALIZADAS")
    print("="*70)
    
    arquitecturas = """
    ┌─────────────────────────────────────────────────────────────────────┐
    │ 1. LONG-FORMER (LONG CONTEXT)                                      │
    └─────────────────────────────────────────────────────────────────────┘
    
    CONCEPTO:
    - Atención con sliding window
    - Maneja secuencias muy largas (hasta 4096 tokens)
    - Atención local + global
    
    IMPLEMENTACIÓN:
    ```python
    class LongformerAttention(nn.Module):
        def __init__(self, d_model, num_heads, window_size=512):
            super().__init__()
            self.d_model = d_model
            self.num_heads = num_heads
            self.window_size = window_size
        
        def forward(self, q, k, v, attention_mask=None):
            # Sliding window attention
            # Cada token atiende a window_size tokens a cada lado
            
            seq_len = q.size(1)
            attention_scores = torch.zeros(
                seq_len, seq_len, device=q.device
            )
            
            for i in range(seq_len):
                # Window alrededor de posición i
                start = max(0, i - self.window_size // 2)
                end = min(seq_len, i + self.window_size // 2)
                
                # Calcular atención solo en window
                window_scores = torch.matmul(
                    q[:, i:i+1], k[:, start:end].transpose(-2, -1)
                ) / math.sqrt(self.d_model)
                
                attention_scores[i, start:end] = window_scores.squeeze()
            
            # Aplicar mask
            if attention_mask is not None:
                attention_scores = attention_scores.masked_fill(
                    attention_mask == 0, float('-inf')
                )
            
            attention_weights = F.softmax(attention_scores, dim=-1)
            output = torch.matmul(attention_weights, v)
            
            return output
    ```
    
    BENEFICIOS:
    ✅ Maneja secuencias muy largas
    ✅ Complejidad O(n) en lugar de O(n²)
    ✅ Eficiente en memoria
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ 2. BIGBIRD (SPARSE ATTENTION)                                      │
    └─────────────────────────────────────────────────────────────────────┘
    
    CONCEPTO:
    - Atención sparse con patrones específicos
    - Random + Window + Global attention
    - Maneja secuencias de hasta 4096+ tokens
    
    IMPLEMENTACIÓN:
    ```python
    class BigBirdAttention(nn.Module):
        def __init__(self, d_model, num_heads, num_random=3, window_size=3, num_global=2):
            super().__init__()
            self.num_random = num_random
            self.window_size = window_size
            self.num_global = num_global
        
        def forward(self, q, k, v):
            seq_len = q.size(1)
            
            # 1. Window attention (local)
            window_attention = self.window_attention(q, k, v)
            
            # 2. Random attention (sparse)
            random_attention = self.random_attention(q, k, v, self.num_random)
            
            # 3. Global attention (special tokens)
            global_attention = self.global_attention(q, k, v, self.num_global)
            
            # Combinar
            output = window_attention + random_attention + global_attention
            
            return output
    ```
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ 3. PERCEIVER (CROSS-ATTENTION)                                      │
    └─────────────────────────────────────────────────────────────────────┘
    
    CONCEPTO:
    - Cross-attention para procesar inputs muy grandes
    - Latent array de tamaño fijo
    - Escala a inputs arbitrariamente grandes
    
    IMPLEMENTACIÓN:
    ```python
    class PerceiverBlock(nn.Module):
        def __init__(self, d_model, d_latent, num_heads):
            super().__init__()
            self.cross_attention = nn.MultiheadAttention(
                d_model, num_heads, batch_first=True
            )
            self.self_attention = nn.MultiheadAttention(
                d_latent, num_heads, batch_first=True
            )
            self.feed_forward = nn.Sequential(
                nn.Linear(d_latent, d_latent * 4),
                nn.GELU(),
                nn.Linear(d_latent * 4, d_latent)
            )
        
        def forward(self, inputs, latents):
            # Cross-attention: latents atienden a inputs
            latents, _ = self.cross_attention(latents, inputs, inputs)
            
            # Self-attention en latents
            latents, _ = self.self_attention(latents, latents, latents)
            
            # Feed-forward
            latents = latents + self.feed_forward(latents)
            
            return latents
    ```
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ 4. LINFORMER (LOW-RANK PROJECTION)                                  │
    └─────────────────────────────────────────────────────────────────────┘
    
    CONCEPTO:
    - Proyectar K y V a dimensión más baja
    - Reducir complejidad de O(n²) a O(n)
    - Mantener calidad similar
    
    IMPLEMENTACIÓN:
    ```python
    class LinformerAttention(nn.Module):
        def __init__(self, d_model, num_heads, projection_dim=256):
            super().__init__()
            self.d_model = d_model
            self.num_heads = num_heads
            self.projection_dim = projection_dim
            
            # Proyecciones de bajo rango
            self.k_projection = nn.Linear(d_model, projection_dim)
            self.v_projection = nn.Linear(d_model, projection_dim)
        
        def forward(self, q, k, v):
            # Proyectar K y V a dimensión más baja
            k_proj = self.k_projection(k)  # [batch, seq_len, projection_dim]
            v_proj = self.v_projection(v)
            
            # Atención con proyecciones
            scores = torch.matmul(q, k_proj.transpose(-2, -1)) / math.sqrt(self.d_model)
            attention_weights = F.softmax(scores, dim=-1)
            output = torch.matmul(attention_weights, v_proj)
            
            return output
    ```
    
    BENEFICIOS:
    ✅ O(n) complejidad
    ✅ Menor uso de memoria
    ✅ Más rápido
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ 5. REFORMER (LSH ATTENTION)                                         │
    └─────────────────────────────────────────────────────────────────────┘
    
    CONCEPT:
    - Locality-Sensitive Hashing para atención
    - Solo calcular atención entre tokens similares
    - O(n log n) complejidad
    
    IMPLEMENTACIÓN:
    ```python
    class ReformerAttention(nn.Module):
        def __init__(self, d_model, num_heads, num_hashes=4):
            super().__init__()
            self.num_hashes = num_hashes
            self.lsh = LocalitySensitiveHashing(d_model, num_hashes)
        
        def forward(self, q, k, v):
            # Hash Q y K
            q_hashes = self.lsh.hash(q)
            k_hashes = self.lsh.hash(k)
            
            # Agrupar por hash buckets
            buckets = self.group_by_buckets(q, k, q_hashes, k_hashes)
            
            # Calcular atención solo dentro de buckets
            output = self.bucket_attention(buckets, q, k, v)
            
            return output
    ```
    
    
    ┌─────────────────────────────────────────────────────────────────────┐
    │ 6. SWITCH TRANSFORMER (MIXTURE OF EXPERTS)                          │
    └─────────────────────────────────────────────────────────────────────┘
    
    CONCEPTO:
    - Múltiples expertos (feed-forward networks)
    - Router selecciona expertos por token
    - Escala parámetros sin aumentar cómputo
    
    IMPLEMENTACIÓN:
    ```python
    class SwitchTransformerBlock(nn.Module):
        def __init__(self, d_model, num_experts=8, num_selected=1):
            super().__init__()
            self.num_experts = num_experts
            self.num_selected = num_selected
            
            # Expertos
            self.experts = nn.ModuleList([
                nn.Sequential(
                    nn.Linear(d_model, d_model * 4),
                    nn.GELU(),
                    nn.Linear(d_model * 4, d_model)
                ) for _ in range(num_experts)
            ])
            
            # Router
            self.router = nn.Linear(d_model, num_experts)
        
        def forward(self, x):
            # Router decide qué expertos usar
            router_logits = self.router(x)
            router_probs = F.softmax(router_logits, dim=-1)
            
            # Seleccionar top-k expertos
            top_k_probs, top_k_indices = torch.topk(
                router_probs, self.num_selected, dim=-1
            )
            
            # Aplicar expertos seleccionados
            output = torch.zeros_like(x)
            for i in range(self.num_selected):
                expert_idx = top_k_indices[:, :, i]
                expert_output = self.apply_expert(x, expert_idx)
                output += top_k_probs[:, :, i:i+1] * expert_output
            
            return output
    ```
    
    BENEFICIOS:
    ✅ Escala parámetros sin aumentar cómputo
    ✅ Especialización de expertos
    ✅ Más eficiente
    """
    print(arquitecturas)


