    class FeatureImportance:
        def __init__(self, model):
            self.model = model
        
        def calculate_importance(self, input_text, target_class):
            """Calcular importancia de features"""
            tokens = tokenizer.encode(input_text)
            input_ids = torch.tensor([tokens]).requires_grad_(True)
            
            # Forward
            outputs = self.model(input_ids)
            logits = outputs.logits
            
            # Backward
            target_logit = logits[0, target_class]
            target_logit.backward()
            
            # Gradientes como importancia
            importance = input_ids.grad.abs().squeeze()
            
            return importance.cpu().numpy()
        
        def visualize_importance(self, text, importance_scores):
            """Visualizar importancia de tokens"""
            tokens = tokenizer.encode(text)
            
            # Normalizar
            importance_norm = importance_scores / importance_scores.max()
            
            # Crear visualización
            fig, ax = plt.subplots(figsize=(12, 2))
            
            colors = plt.cm.Reds(importance_norm)
            ax.barh(range(len(tokens)), importance_norm, color=colors)
            ax.set_yticks(range(len(tokens)))
            ax.set_yticklabels(tokens)
            ax.set_xlabel('Importance')
            ax.set_title('Token Importance')
            
            plt.tight_layout()
