    class ControlledGeneration:
        def __init__(self, model, tokenizer):
            self.model = model
            self.tokenizer = tokenizer
        
        def generate_with_control(self, prompt, control_attributes):
            """Generar con atributos controlados"""
            # Attributes: sentiment, topic, style, length, etc.
            
            tokens = self.tokenizer.encode(prompt)
            
            for _ in range(control_attributes.get('max_length', 100)):
                input_ids = torch.tensor([tokens])
                
                with torch.no_grad():
                    outputs = self.model(input_ids)
                    logits = outputs.logits[0, -1, :]
                
                # Ajustar logits según atributos
                logits = self.adjust_logits_for_attributes(
                    logits,
                    control_attributes
                )
                
                # Muestrear
                next_token = torch.multinomial(F.softmax(logits, dim=-1), 1)
                tokens.append(next_token.item())
                
                if next_token.item() == self.tokenizer.eos_token_id:
                    break
            
            return self.tokenizer.decode(tokens)
        
        def adjust_logits_for_attributes(self, logits, attributes):
            """Ajustar logits según atributos"""
