    class ModelAccessControl:
        def __init__(self):
            self.permissions = {}
            self.access_log = []
        
        def grant_permission(self, user_id, model_id, permission_type):
            """Otorgar permiso"""
            key = f"{user_id}:{model_id}"
            if key not in self.permissions:
                self.permissions[key] = []
            
            self.permissions[key].append({
                'type': permission_type,
                'granted_at': datetime.now()
            })
        
        def check_permission(self, user_id, model_id, action):
            """Verificar permiso"""
            key = f"{user_id}:{model_id}"
            user_permissions = self.permissions.get(key, [])
            
            # Verificar si tiene permiso para acción
            required_permission = self.get_required_permission(action)
            
            for perm in user_permissions:
                if perm['type'] == required_permission:
                    return True
            
            return False
        
        def log_access(self, user_id, model_id, action):
            """Log acceso"""
            self.access_log.append({
                'user_id': user_id,
                'model_id': model_id,
                'action': action,
                'timestamp': datetime.now(),
                'allowed': self.check_permission(user_id, model_id, action)
            })
