    class DataLineage:
        def __init__(self):
            self.lineage_graph = {}
        
        def track_data_flow(self, model_id, input_data, output_data):
            """Rastrear flujo de datos"""
            if model_id not in self.lineage_graph:
                self.lineage_graph[model_id] = {
                    'inputs': [],
                    'outputs': [],
                    'transformations': []
                }
            
            self.lineage_graph[model_id]['inputs'].append({
                'data_id': input_data['id'],
                'source': input_data['source'],
                'timestamp': datetime.now()
            })
            
            self.lineage_graph[model_id]['outputs'].append({
                'data_id': output_data['id'],
                'destination': output_data['destination'],
                'timestamp': datetime.now()
            })
        
        def trace_data_origin(self, output_data_id):
            """Rastrear origen de datos"""
            origins = []
            
            for model_id, graph in self.lineage_graph.items():
                for output in graph['outputs']:
                    if output['data_id'] == output_data_id:
                        # Encontrar inputs correspondientes
                        origins.extend(graph['inputs'])
            
            return origins
        
        def get_data_lineage_graph(self):
            """Obtener grafo completo de lineage"""
            return self.lineage_graph
