class InferenceOptimizer:
    """
    Utilidad para optimizar modelos para inferencia.
    """
    
    @staticmethod
    def fuse_layers(model: nn.Module):
        """
        Fusiona capas para acelerar inferencia.
        
        :param model: Modelo a optimizar
        """
        # Fusionar LayerNorm + Linear cuando sea posible
        # Esto es una simplificación - en producción usar torch.jit.script
        print("⚠️ Para optimización real, usa torch.jit.script o torch.compile()")
        return model
    
    @staticmethod
    def optimize_for_onnx(model: CausalTransformer):
        """
        Optimiza el modelo para exportación ONNX.
        
        :param model: Modelo a optimizar
        """
        # Asegurar que el modelo esté en modo evaluación
        model.eval()
        
        # Deshabilitar dropout para inferencia determinista
        for module in model.modules():
            if isinstance(module, nn.Dropout):
                module.p = 0.0
        
        return model
    
    @staticmethod
    def enable_torch_compile(model: nn.Module, mode: str = "reduce-overhead"):
        """
        Habilita torch.compile() para acelerar el modelo (PyTorch 2.0+).
        
        :param model: Modelo a compilar
        :param mode: Modo de compilación ('default', 'reduce-overhead', 'max-autotune')
        :return: Modelo compilado
        """
        try:
            import torch._dynamo
            compiled_model = torch.compile(model, mode=mode)
            print(f"✅ Modelo compilado con torch.compile() en modo '{mode}'")
            return compiled_model
        except Exception as e:
            print(f"⚠️ torch.compile() no disponible: {e}")
            return model


class BatchInference:
    """
    Utilidad para inferencia por lotes optimizada.
    """
    
    @staticmethod
    @torch.no_grad()
    def generate_batch(
        generator: TextGenerator,
        prompts: list,
        max_length: int = 100,
        batch_size: int = 8,
        **generation_kwargs
    ) -> list:
        """
        Genera texto para múltiples prompts en batch.
        
        :param generator: Generador de texto
        :param prompts: Lista de prompts
        :param max_length: Longitud máxima de generación
        :param batch_size: Tamaño del batch
        :param generation_kwargs: Argumentos adicionales para generación
        :return: Lista de textos generados
        """
        results = []
        
        for i in range(0, len(prompts), batch_size):
            batch_prompts = prompts[i:i+batch_size]
            
            # Convertir a tensor batch
            batch_tensor = torch.stack([torch.tensor(p) for p in batch_prompts])
            
            # Generar
            generated = generator.generate(
                batch_tensor,
                max_length=max_length,
                **generation_kwargs
            )
            
            results.extend([g.tolist() for g in generated])
        
        return results
    
    @staticmethod
    @torch.no_grad()
    def process_sequences(
        model: CausalTransformer,
        sequences: torch.Tensor,
        batch_size: int = 32
    ) -> torch.Tensor:
        """
        Procesa múltiples secuencias en batch.
        
        :param model: Modelo
        :param sequences: Tensor de secuencias
        :param batch_size: Tamaño del batch
        :return: Logits procesados
        """
        model.eval()
        all_logits = []
        
        for i in range(0, sequences.shape[0], batch_size):
            batch = sequences[i:i+batch_size]
            logits = model(batch)
            all_logits.append(logits)
        
        return torch.cat(all_logits, dim=0)


class MultiGPUInference:
    """
    Utilidad para inferencia multi-GPU.
    """
    
    @staticmethod
    def setup_model_parallel(model: nn.Module, device_ids: list):
        """
        Configura modelo para paralelismo de datos.
        
        :param model: Modelo
        :param device_ids: Lista de IDs de dispositivos
        :return: Modelo paralelo
        """
        if len(device_ids) > 1:
            model = nn.DataParallel(model, device_ids=device_ids)
            print(f"✅ Modelo configurado para {len(device_ids)} GPUs")
        return model
    
    @staticmethod
    def setup_model_sharding(model: nn.Module, device_ids: list):
        """
        Configura sharding del modelo (cada capa en diferente GPU).
        
        :param model: Modelo
        :param device_ids: Lista de IDs de dispositivos
        :return: Modelo con sharding
        """
        if not isinstance(model, CausalTransformer):
            print("⚠️ Sharding solo soportado para CausalTransformer")
            return model
        
        # Mover diferentes bloques a diferentes GPUs
        n_gpus = len(device_ids)
        n_layers = len(model.blocks)
        
        layers_per_gpu = n_layers // n_gpus
        
        for i, block in enumerate(model.blocks):
            gpu_idx = min(i // layers_per_gpu, n_gpus - 1)
            block = block.to(f'cuda:{device_ids[gpu_idx]}')
        
        print(f"✅ Modelo shardeado en {n_gpus} GPUs")
        return model


class ModelExporter:
    """
    Utilidad para exportar modelos a diferentes formatos.
    """
    
    @staticmethod
    def export_to_onnx(
        model: CausalTransformer,
        filepath: str,
        batch_size: int = 1,
        seq_len: int = 128,
        vocab_size: int = 1000,
        opset_version: int = 17,
        dynamic_axes: bool = True
    ):
        """
        Exporta modelo a formato ONNX.
        
        :param model: Modelo a exportar
        :param filepath: Ruta donde guardar
        :param batch_size: Tamaño del batch para ejemplo
        :param seq_len: Longitud de secuencia para ejemplo
        :param vocab_size: Tamaño del vocabulario
        :param opset_version: Versión de opset de ONNX
        :param dynamic_axes: Si True, permite dimensiones dinámicas
        """
        model.eval()
        model = InferenceOptimizer.optimize_for_onnx(model)
        
        dummy_input = torch.randint(0, vocab_size, (batch_size, seq_len))
        
        try:
            if dynamic_axes:
                torch.onnx.export(
                    model,
                    dummy_input,
                    filepath,
                    export_params=True,
                    opset_version=opset_version,
                    do_constant_folding=True,
                    input_names=['token_ids'],
                    output_names=['logits'],
                    dynamic_axes={
                        'token_ids': {0: 'batch_size', 1: 'seq_len'},
                        'logits': {0: 'batch_size', 1: 'seq_len'}
                    },
                    verbose=False
                )
            else:
                torch.onnx.export(
                    model,
                    dummy_input,
                    filepath,
                    export_params=True,
                    opset_version=opset_version,
                    do_constant_folding=True,
                    input_names=['token_ids'],
                    output_names=['logits'],
                    verbose=False
                )
            
            print(f"✅ Modelo exportado a ONNX: {filepath}")
        except Exception as e:
            print(f"❌ Error al exportar a ONNX: {e}")
    
    @staticmethod
    def export_to_torchscript(
        model: CausalTransformer,
        filepath: str,
        method: str = 'script'  # 'script' o 'trace'
    ):
        """
        Exporta modelo a TorchScript.
        
        :param model: Modelo a exportar
        :param filepath: Ruta donde guardar
        :param method: Método de exportación ('script' o 'trace')
        """
        model.eval()
        
        try:
            if method == 'script':
                # torch.jit.script - más flexible pero requiere código compatible
                scripted_model = torch.jit.script(model)
                scripted_model.save(filepath)
            else:
                # torch.jit.trace - más simple pero menos flexible
                dummy_input = torch.randint(0, model.vocab_size, (1, 128))
                traced_model = torch.jit.trace(model, dummy_input)
                traced_model.save(filepath)
            
            print(f"✅ Modelo exportado a TorchScript: {filepath}")
        except Exception as e:
            print(f"❌ Error al exportar a TorchScript: {e}")


class AttentionOptimizer:
    """
    Utilidades para optimizar el mecanismo de atención.
    """
    
    @staticmethod
    def implement_sparse_attention(
        Q: torch.Tensor,
        K: torch.Tensor,
        V: torch.Tensor,
        window_size: int = 64,
        causal: bool = True
    ) -> torch.Tensor:
        """
        Implementa atención dispersa (local window).
        
        :param Q: Queries
        :param K: Keys
        :param V: Values
        :param window_size: Tamaño de la ventana local
        :param causal: Si True, aplica máscara causal
        :return: Output de atención
        """
        batch_size, n_heads, seq_len, d_k = Q.shape
        
        # Para simplificar, implementamos atención local
        # En producción usar implementaciones optimizadas como Flash Attention
        output = torch.zeros_like(Q)
        
        for i in range(seq_len):
            start = max(0, i - window_size) if causal else 0
            end = i + 1 if causal else min(seq_len, i + window_size + 1)
            
            # Atención sobre ventana local
            Q_i = Q[:, :, i:i+1, :]  # (batch, heads, 1, d_k)
            K_window = K[:, :, start:end, :]  # (batch, heads, window_size, d_k)
            V_window = V[:, :, start:end, :]
            
            scores = torch.matmul(Q_i, K_window.transpose(-2, -1)) / math.sqrt(d_k)
            attn_weights = F.softmax(scores, dim=-1)
            attn_output = torch.matmul(attn_weights, V_window)
            
            output[:, :, i, :] = attn_output.squeeze(2)
        
        return output
    
    @staticmethod
    def calculate_attention_complexity(
        seq_len: int,
        d_model: int,
        n_heads: int,
        sparse: bool = False,
        window_size: Optional[int] = None
    ) -> dict:
        """
        Calcula complejidad computacional de atención.
        
        :param seq_len: Longitud de secuencia
        :param d_model: Dimensión del modelo
        :param n_heads: Número de heads
        :param sparse: Si True, calcula para atención dispersa
        :param window_size: Tamaño de ventana para atención dispersa
        :return: Diccionario con estadísticas de complejidad
        """
        d_k = d_model // n_heads
        
        if sparse and window_size:
            # Atención dispersa: O(n * w * d) donde w es window_size
            ops = seq_len * window_size * d_k * n_heads
            memory = seq_len * window_size * n_heads
        else:
            # Atención completa: O(n² * d)
            ops = seq_len * seq_len * d_k * n_heads
            memory = seq_len * seq_len * n_heads
        
        return {
            'operations': ops,
            'memory_elements': memory,
            'memory_mb': memory * 4 / (1024 * 1024),  # Asumiendo float32
            'sparse': sparse,
            'complexity': f"O({seq_len}*{window_size if sparse else seq_len}*{d_k})" if sparse else f"O({seq_len}²*{d_k})"
        }


class FineTuningUtilities:
    """
    Utilidades para fine-tuning de modelos.
    """
    
    @staticmethod
    def freeze_layers(model: nn.Module, freeze_ratio: float = 0.5):
        """
        Congela una proporción de capas del modelo.
        
        :param model: Modelo
        :param freeze_ratio: Ratio de capas a congelar (0.5 = 50%)
        """
        if not isinstance(model, CausalTransformer):
            print("⚠️ Freeze solo soportado para CausalTransformer")
            return
        
        n_layers = len(model.blocks)
        n_freeze = int(n_layers * freeze_ratio)
        
        # Congelar embeddings y primeras capas
        for param in model.token_embedding.parameters():
            param.requires_grad = False
        
        for i in range(n_freeze):
            for param in model.blocks[i].parameters():
                param.requires_grad = False
        
        print(f"✅ {n_freeze} de {n_layers} capas congeladas")
    
    @staticmethod
    def add_lora_adapters(
        linear_layer: nn.Linear,
        rank: int = 8,
        alpha: float = 16.0
    ) -> Tuple[nn.Linear, nn.Linear, nn.Parameter]:
        """
        Agrega adaptadores LoRA (Low-Rank Adaptation) a una capa lineal.
        
        :param linear_layer: Capa lineal
        :param rank: Rango de la adaptación
        :param alpha: Factor de escalado
        :return: Tuple de (A, B, scaling) adaptadores
        """
        in_features = linear_layer.in_features
        out_features = linear_layer.out_features
        
        # Adaptadores LoRA
        A = nn.Linear(in_features, rank, bias=False)
        B = nn.Linear(rank, out_features, bias=False)
        
        # Inicializar B con zeros y A con normal
        nn.init.zeros_(B.weight)
        nn.init.normal_(A.weight, std=0.02)
        
        # Scaling factor
        scaling = nn.Parameter(torch.tensor(alpha / rank))
        
        return A, B, scaling
    
    @staticmethod
    def apply_lora_forward(
        x: torch.Tensor,
        linear_layer: nn.Linear,
        lora_A: nn.Linear,
        lora_B: nn.Linear,
        scaling: nn.Parameter
    ) -> torch.Tensor:
        """
        Aplica forward pass con LoRA.
        
        :param x: Input
        :param linear_layer: Capa original
        :param lora_A: Adaptador A
        :param lora_B: Adaptador B
        :param scaling: Factor de escalado
        :return: Output
        """
        # Forward original
        original_output = linear_layer(x)
        
        # Forward LoRA
        lora_output = lora_B(lora_A(x)) * scaling
        
        return original_output + lora_output


class AdvancedMetrics:
    """
    Métricas avanzadas para evaluación de modelos.
    """
    
    @staticmethod
    def calculate_bleu_score(
        predictions: list,
        references: list,
        n_gram: int = 4
    ) -> float:
        """
        Calcula BLEU score.
        
        :param predictions: Lista de predicciones
        :param references: Lista de referencias
        :param n_gram: N-gram máximo
        :return: BLEU score
        """
        try:
            from nltk.translate.bleu_score import sentence_bleu, SmoothingFunction
        except ImportError:
            print("⚠️ nltk no está instalado. Instala con: pip install nltk")
            return 0.0
        
        smoothing = SmoothingFunction().method1
        
        scores = []
        for pred, ref in zip(predictions, references):
            score = sentence_bleu([ref], pred, smoothing_function=smoothing)
            scores.append(score)
        
        return np.mean(scores)
    
    @staticmethod
    def calculate_rouge_score(
        predictions: list,
        references: list,
        rouge_type: str = 'rouge-l'
    ) -> dict:
        """
        Calcula ROUGE score.
        
        :param predictions: Lista de predicciones
        :param references: Lista de referencias
        :param rouge_type: Tipo de ROUGE ('rouge-l', 'rouge-1', 'rouge-2')
        :return: Diccionario con scores
        """
        try:
            from rouge_score import rouge_scorer
        except ImportError:
            print("⚠️ rouge_score no está instalado. Instala con: pip install rouge-score")
            return {'rouge-l': {'f': 0.0}}
        
        scorer = rouge_scorer.RougeScorer([rouge_type], use_stemmer=True)
        scores = []
        
        for pred, ref in zip(predictions, references):
            score = scorer.score(' '.join(ref), ' '.join(pred))
            scores.append(score[rouge_type].fmeasure)
        
        return {
            rouge_type: {
                'f': np.mean(scores),
                'p': np.mean([scorer.score(' '.join(ref), ' '.join(pred))[rouge_type].precision 
                              for pred, ref in zip(predictions, references)]),
                'r': np.mean([scorer.score(' '.join(ref), ' '.join(pred))[rouge_type].recall 
                             for pred, ref in zip(predictions, references)])
            }
        }
    
    @staticmethod
    def calculate_diversity_metrics(generated_texts: list) -> dict:
        """
        Calcula métricas de diversidad en textos generados.
        
        :param generated_texts: Lista de textos generados
        :return: Diccionario con métricas
        """
        all_tokens = []
        unique_tokens = set()
        
        for text in generated_texts:
            tokens = text.split() if isinstance(text, str) else text
            all_tokens.extend(tokens)
            unique_tokens.update(tokens)
        
        # Tipo-token ratio
        ttr = len(unique_tokens) / len(all_tokens) if all_tokens else 0.0
        
        # Entropía de unigramas
        from collections import Counter
        token_counts = Counter(all_tokens)
        probs = [count / len(all_tokens) for count in token_counts.values()]
        entropy = -sum(p * np.log2(p) for p in probs if p > 0)
        
        return {
            'type_token_ratio': ttr,
            'unique_tokens': len(unique_tokens),
            'total_tokens': len(all_tokens),
            'entropy': entropy,
            'vocabulary_size': len(unique_tokens)
        }


class ModelDebugger:
    """
    Utilidad para debugging avanzado de modelos.
    """
    
    @staticmethod
    def check_for_nan(model: nn.Module, input_tensor: torch.Tensor) -> dict:
        """
        Verifica si hay NaN en el modelo.
        
        :param model: Modelo
        :param input_tensor: Tensor de entrada
        :return: Diccionario con resultados
        """
        model.eval()
        
        with torch.no_grad():
            output = model(input_tensor)
        
        has_nan = torch.isnan(output).any().item()
        has_inf = torch.isinf(output).any().item()
        
        # Verificar parámetros
        param_nan_count = 0
        param_inf_count = 0
        
        for name, param in model.named_parameters():
            if torch.isnan(param).any():
                param_nan_count += 1
            if torch.isinf(param).any():
                param_inf_count += 1
        
        return {
            'output_has_nan': has_nan,
            'output_has_inf': has_inf,
            'params_with_nan': param_nan_count,
            'params_with_inf': param_inf_count,
            'is_healthy': not (has_nan or has_inf or param_nan_count > 0 or param_inf_count > 0)
        }
    
    @staticmethod
    def profile_model(
        model: nn.Module,
        input_tensor: torch.Tensor,
        num_runs: int = 10
    ) -> dict:
        """
        Hace profiling del modelo.
        
        :param model: Modelo
        :param input_tensor: Tensor de entrada
        :param num_runs: Número de runs
        :return: Diccionario con estadísticas
        """
        try:
            from torch.profiler import profile, record_function, ProfilerActivity
        except ImportError:
            print("⚠️ torch.profiler no disponible")
            return {}
        
        model.eval()
        
        activities = [ProfilerActivity.CPU]
        if torch.cuda.is_available():
            activities.append(ProfilerActivity.CUDA)
        
        with torch.no_grad():
            with profile(activities=activities, record_shapes=True) as prof:
                with record_function("model_inference"):
                    for _ in range(num_runs):
                        _ = model(input_tensor)
        
        return {
            'profiler': prof,
            'key_averages': prof.key_averages().table(sort_by="cuda_time_total" if torch.cuda.is_available() else "cpu_time_total")
        }


