def create_complete_usage_example():
    """
    Crea un ejemplo completo de uso end-to-end.
    """
    example = """
# ============================================================================
# EJEMPLO COMPLETO END-TO-END: ENTRENAMIENTO, EVALUACIÓN Y DEPLOYMENT
# ============================================================================

import torch
from transformer_architecture_explanation import (
    CausalTransformer,
    TextGenerator,
    ModelTrainer,
    ModelEvaluator,
    ModelBenchmark,
    InferenceOptimizer,
    ModelExporter,
    FineTuningUtilities,
    AdvancedMetrics,
    save_model_checkpoint,
    load_model_checkpoint
)

# ===== 1. CREAR Y CONFIGURAR MODELO =====
model = CausalTransformer(
    vocab_size=10000,
    d_model=512,
    n_heads=8,
    n_layers=6,
    d_ff=2048,
    max_seq_len=512,
    dropout=0.1
)

# ===== 2. ENTRENAR MODELO =====
optimizer = ModelTrainer.create_optimizer(model, lr=3e-4)
scheduler = ModelTrainer.create_scheduler(optimizer, num_warmup_steps=1000, num_training_steps=10000)
criterion = torch.nn.CrossEntropyLoss(ignore_index=-1)

# Loop de entrenamiento
for epoch in range(num_epochs):
    stats = ModelTrainer.train_epoch(
        model, train_loader, optimizer, criterion,
        device='cuda', gradient_clip=1.0, accumulation_steps=4
    )
    scheduler.step()
    
    if (epoch + 1) % 10 == 0:
        save_model_checkpoint(model, optimizer, epoch, stats['loss'], f'checkpoint_{epoch}.pt')

# ===== 3. EVALUAR MODELO =====
perplexity = ModelEvaluator.calculate_perplexity(model, eval_loader, device='cuda')
accuracy = ModelEvaluator.calculate_accuracy(model, eval_loader, device='cuda')
print(f"Perplexity: {perplexity:.2f}, Accuracy: {accuracy:.4f}")

# ===== 4. BENCHMARK =====
benchmark = ModelBenchmark.benchmark_forward_pass(
    model, batch_size=1, seq_len=128, vocab_size=10000, device='cuda'
)
print(f"Throughput: {benchmark['tokens_per_second']:.2f} tokens/sec")

# ===== 5. OPTIMIZAR PARA INFERENCIA =====
model = InferenceOptimizer.optimize_for_onnx(model)
model = InferenceOptimizer.enable_torch_compile(model, mode='reduce-overhead')

# ===== 6. GENERAR TEXTO =====
generator = TextGenerator(model)
prompt = torch.randint(0, 10000, (1, 10)).to('cuda')
generated = generator.generate(prompt, max_length=100, temperature=0.8, top_k=50)

# ===== 7. EVALUAR GENERACIÓN =====
# Calcular métricas de calidad
diversity = AdvancedMetrics.calculate_diversity_metrics([generated[0].tolist()])
print(f"Diversity TTR: {diversity['type_token_ratio']:.4f}")

# ===== 8. EXPORTAR PARA DEPLOYMENT =====
ModelExporter.export_to_onnx(model, 'model.onnx', dynamic_axes=True)
ModelExporter.export_to_torchscript(model, 'model.pt', method='trace')

# ===== 9. FINE-TUNING =====
# Cargar modelo pre-entrenado
pretrained_model, _ = load_model_checkpoint('pretrained_model.pt', device='cuda')

# Congelar capas iniciales
FineTuningUtilities.freeze_layers(pretrained_model, freeze_ratio=0.5)

# Fine-tune solo las últimas capas
# ... entrenamiento con dataset específico ...

print("✅ Pipeline completo ejecutado exitosamente")
"""
    return example


