class AdvancedTesting:
    """
    Utilidades avanzadas para testing de modelos.
    """
    
    @staticmethod
    def test_forward_backward(model: nn.Module, input_tensor: torch.Tensor, device: str = 'cpu') -> dict:
        """
        Prueba forward y backward pass del modelo.
        
        :param model: Modelo a probar
        :param input_tensor: Tensor de entrada
        :param device: Device
        :return: Diccionario con resultados
        """
        model = model.to(device)
        model.train()
        input_tensor = input_tensor.to(device)
        
        results = {
            'forward_success': False,
            'backward_success': False,
            'forward_error': None,
            'backward_error': None
        }
        
        # Test forward
        try:
            output = model(input_tensor)
            results['forward_success'] = True
            results['output_shape'] = list(output.shape)
        except Exception as e:
            results['forward_error'] = str(e)
        
        # Test backward
        if results['forward_success']:
            try:
                # Crear targets dummy
                if isinstance(model, CausalTransformer):
                    targets = torch.randint(0, model.vocab_size, output.shape[:2]).to(device)
                    loss = F.cross_entropy(output.view(-1, output.size(-1)), targets.view(-1))
                else:
                    loss = output.mean()
                
                loss.backward()
                results['backward_success'] = True
                results['loss_value'] = loss.item()
            except Exception as e:
                results['backward_error'] = str(e)
        
        return results
    
    @staticmethod
    def test_gradient_flow(model: nn.Module, input_tensor: torch.Tensor) -> dict:
        """
        Prueba el flujo de gradientes en el modelo.
        
        :param model: Modelo
        :param input_tensor: Tensor de entrada
        :return: Diccionario con resultados
        """
        model.train()
        
        # Forward y backward
        output = model(input_tensor)
        if isinstance(model, CausalTransformer):
            targets = torch.randint(0, model.vocab_size, output.shape[:2])
            loss = F.cross_entropy(output.view(-1, output.size(-1)), targets.view(-1))
        else:
            loss = output.mean()
        
        loss.backward()
        
        # Analizar gradientes
        grad_stats = GradientMonitor.check_gradient_flow(model)
        
        # Verificar gradientes por capa
        layer_grads = {}
        for name, param in model.named_parameters():
            if param.grad is not None:
                layer_grads[name] = {
                    'norm': param.grad.norm().item(),
                    'mean': param.grad.mean().item(),
                    'std': param.grad.std().item(),
                    'max': param.grad.max().item(),
                    'min': param.grad.min().item()
                }
        
        return {
            'gradient_flow_healthy': grad_stats['gradient_flow_healthy'],
            'total_norm': grad_stats['total_norm'],
            'zero_grad_count': grad_stats['zero_grad_count'],
            'layer_grads': layer_grads
        }
    
    @staticmethod
    def test_model_consistency(model: nn.Module, input_tensor: torch.Tensor, num_runs: int = 5) -> dict:
        """
        Prueba consistencia del modelo (mismo input debe dar mismo output).
        
        :param model: Modelo
        :param input_tensor: Tensor de entrada
        :param num_runs: Número de runs
        :return: Diccionario con resultados
        """
        model.eval()
        
        outputs = []
        with torch.no_grad():
            for _ in range(num_runs):
                output = model(input_tensor)
                outputs.append(output)
        
        # Verificar que todos los outputs sean iguales
        first_output = outputs[0]
        all_equal = all(torch.allclose(first_output, out, atol=1e-6) for out in outputs[1:])
        
        # Calcular variación
        if all_equal:
            max_diff = 0.0
        else:
            max_diff = max(torch.abs(first_output - out).max().item() for out in outputs[1:])
        
        return {
            'is_consistent': all_equal,
            'max_difference': max_diff,
            'num_runs': num_runs,
            'outputs_shape': list(first_output.shape)
        }


class ModelLogger:
    """
    Utilidad para logging avanzado de entrenamiento y evaluación.
    """
    
    def __init__(self, log_dir: str = './logs', use_tensorboard: bool = True):
        """
        :param log_dir: Directorio para logs
        :param use_tensorboard: Si True, usa TensorBoard
        """
        self.log_dir = log_dir
        self.use_tensorboard = use_tensorboard
        self.writer = None
        
        if use_tensorboard:
            try:
                from torch.utils.tensorboard import SummaryWriter
                self.writer = SummaryWriter(log_dir=log_dir)
                print(f"✅ TensorBoard logging habilitado en: {log_dir}")
            except ImportError:
                print("⚠️ TensorBoard no disponible. Instala con: pip install tensorboard")
                self.use_tensorboard = False
    
    def log_training_step(
        self,
        step: int,
        loss: float,
        learning_rate: float,
        perplexity: Optional[float] = None,
        grad_norm: Optional[float] = None
    ):
        """
        Log de un paso de entrenamiento.
        
        :param step: Paso actual
        :param loss: Pérdida
        :param learning_rate: Learning rate actual
        :param perplexity: Perplexity (opcional)
        :param grad_norm: Norma de gradientes (opcional)
        """
        if self.writer:
            self.writer.add_scalar('train/loss', loss, step)
            self.writer.add_scalar('train/learning_rate', learning_rate, step)
            if perplexity:
                self.writer.add_scalar('train/perplexity', perplexity, step)
            if grad_norm:
                self.writer.add_scalar('train/grad_norm', grad_norm, step)
    
    def log_evaluation(
        self,
        epoch: int,
        eval_loss: float,
        eval_perplexity: float,
        eval_accuracy: Optional[float] = None
    ):
        """
        Log de evaluación.
        
        :param epoch: Época
        :param eval_loss: Pérdida de evaluación
        :param eval_perplexity: Perplexity de evaluación
        :param eval_accuracy: Accuracy (opcional)
        """
        if self.writer:
            self.writer.add_scalar('eval/loss', eval_loss, epoch)
            self.writer.add_scalar('eval/perplexity', eval_perplexity, epoch)
            if eval_accuracy:
                self.writer.add_scalar('eval/accuracy', eval_accuracy, epoch)
    
    def log_model_graph(self, model: nn.Module, input_tensor: torch.Tensor):
        """
        Log del grafo del modelo.
        
        :param model: Modelo
        :param input_tensor: Tensor de entrada
        """
        if self.writer:
            try:
                self.writer.add_graph(model, input_tensor)
                print("✅ Grafo del modelo agregado a TensorBoard")
            except Exception as e:
                print(f"⚠️ Error al agregar grafo: {e}")
    
    def log_attention_weights(self, attention_weights: torch.Tensor, step: int, layer_idx: int = 0, head_idx: int = 0):
        """
        Log de pesos de atención.
        
        :param attention_weights: Pesos de atención
        :param step: Paso actual
        :param layer_idx: Índice de capa
        :param head_idx: Índice de head
        """
        if self.writer:
            # Extraer pesos del head específico
            if attention_weights.dim() == 4:
                attn = attention_weights[0, head_idx].cpu()
            else:
                attn = attention_weights[0].cpu()
            
            # Agregar como imagen
            self.writer.add_image(
                f'attention/layer_{layer_idx}/head_{head_idx}',
                attn.unsqueeze(0),
                step,
                dataformats='CHW'
            )
    
    def close(self):
        """Cierra el writer."""
        if self.writer:
            self.writer.close()
            print("✅ Logger cerrado")


class ModelSecurity:
    """
    Utilidades de seguridad para modelos.
    """
    
    @staticmethod
    def sanitize_input(token_ids: torch.Tensor, vocab_size: int, max_seq_len: int) -> torch.Tensor:
        """
        Sanitiza input del modelo.
        
        :param token_ids: IDs de tokens
        :param vocab_size: Tamaño del vocabulario
        :param max_seq_len: Longitud máxima de secuencia
        :return: Tensor sanitizado
        """
        # Clamp valores fuera del rango válido
        token_ids = torch.clamp(token_ids, 0, vocab_size - 1)
        
        # Truncar si es muy largo
        if token_ids.shape[1] > max_seq_len:
            token_ids = token_ids[:, :max_seq_len]
        
        # Verificar NaN/Inf
        token_ids = torch.where(torch.isnan(token_ids) | torch.isinf(token_ids), 
                               torch.zeros_like(token_ids), token_ids)
        
        return token_ids
    
    @staticmethod
    def validate_output(logits: torch.Tensor) -> dict:
        """
        Valida output del modelo.
        
        :param logits: Logits del modelo
        :return: Diccionario con resultados de validación
        """
        has_nan = torch.isnan(logits).any().item()
        has_inf = torch.isinf(logits).any().item()
        has_extreme = (torch.abs(logits) > 100).any().item()
        
        return {
            'has_nan': has_nan,
            'has_inf': has_inf,
            'has_extreme_values': has_extreme,
            'is_valid': not (has_nan or has_inf or has_extreme),
            'mean': logits.mean().item() if not has_nan else None,
            'std': logits.std().item() if not has_nan else None,
            'min': logits.min().item() if not has_nan else None,
            'max': logits.max().item() if not has_nan else None
        }


class ModelOptimizer:
    """
    Utilidad para optimización avanzada de modelos.
    """
    
    @staticmethod
    def apply_mixed_precision(model: nn.Module, enabled: bool = True):
        """
        Aplica mixed precision training.
        
        :param model: Modelo
        :param enabled: Si True, habilita mixed precision
        :return: GradScaler si está habilitado
        """
        if enabled and torch.cuda.is_available():
            from torch.cuda.amp import GradScaler, autocast
            scaler = GradScaler()
            print("✅ Mixed precision training habilitado")
            return scaler, autocast
        else:
            print("⚠️ Mixed precision no disponible o deshabilitado")
            return None, None
    
    @staticmethod
    def apply_gradient_checkpointing(model: nn.Module, enabled: bool = True):
        """
        Aplica gradient checkpointing para reducir memoria.
        
        :param model: Modelo
        :param enabled: Si True, habilita gradient checkpointing
        """
        if enabled:
            # En producción, usar torch.utils.checkpoint
            try:
                # Marcar bloques para checkpointing
                if isinstance(model, CausalTransformer):
                    for block in model.blocks:
                        # Esto es una simplificación
                        # En producción usar torch.utils.checkpoint.checkpoint()
                        pass
                print("✅ Gradient checkpointing configurado")
            except Exception as e:
                print(f"⚠️ Error al configurar gradient checkpointing: {e}")
    
    @staticmethod
    def optimize_model_for_inference(model: nn.Module) -> nn.Module:
        """
        Optimiza modelo para inferencia (fusiona capas, elimina dropout, etc.).
        
        :param model: Modelo
        :return: Modelo optimizado
        """
        model.eval()
        
        # Deshabilitar dropout
        for module in model.modules():
            if isinstance(module, nn.Dropout):
                module.p = 0.0
        
        # Fusionar LayerNorm cuando sea posible
        # (En producción usar torch.jit.script o torch.compile)
        
        print("✅ Modelo optimizado para inferencia")
        return model


class BatchProcessor:
    """
    Utilidad para procesamiento eficiente de batches.
    """
    
    @staticmethod
    def create_dynamic_batches(
        sequences: list,
        max_seq_len: int,
        batch_size: int,
        pad_token_id: int = 0
    ) -> list:
        """
        Crea batches dinámicos optimizados.
        
        :param sequences: Lista de secuencias
        :param max_seq_len: Longitud máxima
        :param batch_size: Tamaño del batch
        :param pad_token_id: ID del token de padding
        :return: Lista de batches
        """
        # Ordenar por longitud para mejor eficiencia
        sequences = sorted(sequences, key=len, reverse=True)
        
        batches = []
        for i in range(0, len(sequences), batch_size):
            batch_seqs = sequences[i:i+batch_size]
            
            # Encontrar longitud máxima en el batch
            max_len = min(max(len(seq) for seq in batch_seqs), max_seq_len)
            
            # Padding
            padded_batch = []
            for seq in batch_seqs:
                if len(seq) > max_len:
                    padded = seq[:max_len]
                else:
                    padded = seq + [pad_token_id] * (max_len - len(seq))
                padded_batch.append(padded)
            
            batches.append(torch.tensor(padded_batch))
        
        return batches
    
    @staticmethod
    def create_attention_mask(token_ids: torch.Tensor, pad_token_id: int = 0) -> torch.Tensor:
        """
        Crea máscara de atención para padding.
        
        :param token_ids: IDs de tokens
        :param pad_token_id: ID del token de padding
        :return: Máscara de atención
        """
        mask = (token_ids != pad_token_id).long()
        return mask


class ModelConverter:
    """
    Utilidad para convertir entre diferentes formatos y configuraciones.
    """
    
    @staticmethod
    def convert_to_half_precision(model: nn.Module) -> nn.Module:
        """
        Convierte modelo a half precision (float16).
        
        :param model: Modelo
        :return: Modelo en float16
        """
        model = model.half()
        print("✅ Modelo convertido a float16")
        return model
    
    @staticmethod
    def convert_to_double_precision(model: nn.Module) -> nn.Module:
        """
        Convierte modelo a double precision (float64).
        
        :param model: Modelo
        :return: Modelo en float64
        """
        model = model.double()
        print("✅ Modelo convertido a float64")
        return model
    
    @staticmethod
    def convert_model_config(
        old_config: dict,
        target_size: str = 'medium'
    ) -> dict:
        """
        Convierte configuración de modelo a otro tamaño.
        
        :param old_config: Configuración antigua
        :param target_size: Tamaño objetivo ('tiny', 'small', 'medium', 'large', 'xl')
        :return: Nueva configuración
        """
        new_config = ConfigManager.create_config_from_preset(target_size)
        
        # Mantener vocab_size si es razonable
        if 'vocab_size' in old_config:
            new_config['vocab_size'] = old_config['vocab_size']
        
        return new_config


class ExperimentTracker:
    """
    Utilidad para rastrear experimentos.
    """
    
    def __init__(self, experiment_name: str, log_dir: str = './experiments'):
        """
        :param experiment_name: Nombre del experimento
        :param log_dir: Directorio para logs
        """
        self.experiment_name = experiment_name
        self.log_dir = log_dir
        self.metrics = {}
        self.config = {}
        
        import os
        os.makedirs(log_dir, exist_ok=True)
    
    def log_config(self, config: dict):
        """
        Registra configuración del experimento.
        
        :param config: Configuración
        """
        self.config = config
        import json
        config_path = f"{self.log_dir}/{self.experiment_name}_config.json"
        with open(config_path, 'w') as f:
            json.dump(config, f, indent=2)
        print(f"✅ Configuración guardada en: {config_path}")
    
    def log_metrics(self, metrics: dict, step: int):
        """
        Registra métricas.
        
        :param metrics: Diccionario de métricas
        :param step: Paso actual
        """
        if step not in self.metrics:
            self.metrics[step] = {}
        self.metrics[step].update(metrics)
    
    def save_results(self):
        """
        Guarda resultados del experimento.
        """
        import json
        results_path = f"{self.log_dir}/{self.experiment_name}_results.json"
        with open(results_path, 'w') as f:
            json.dump({
                'experiment_name': self.experiment_name,
                'config': self.config,
                'metrics': self.metrics
            }, f, indent=2)
        print(f"✅ Resultados guardados en: {results_path}")


class ModelEnsemble:
    """
    Utilidad para crear ensembles de modelos.
    """
    
    @staticmethod
    def ensemble_predict(models: list, input_tensor: torch.Tensor, method: str = 'mean') -> torch.Tensor:
        """
        Combina predicciones de múltiples modelos.
        
        :param models: Lista de modelos
        :param input_tensor: Tensor de entrada
        :param method: Método de combinación ('mean', 'max', 'voting')
        :return: Predicción combinada
        """
        predictions = []
        
        for model in models:
            model.eval()
            with torch.no_grad():
                logits = model(input_tensor)
                predictions.append(logits)
        
        predictions = torch.stack(predictions)  # (n_models, batch, seq, vocab)
        
        if method == 'mean':
            ensemble_logits = predictions.mean(dim=0)
        elif method == 'max':
            ensemble_logits = predictions.max(dim=0)[0]
        elif method == 'voting':
            # Voting basado en argmax
            votes = torch.argmax(predictions, dim=-1)  # (n_models, batch, seq)
            ensemble_logits = predictions[0]  # Usar primera como base
            # En producción, implementar voting más sofisticado
        else:
            raise ValueError(f"Método {method} no soportado")
        
        return ensemble_logits


