class ConfigManager:
    """
    Gestor de configuraciones para modelos Transformer.
    """
    
    @staticmethod
    def create_config_from_preset(preset: str = 'medium') -> dict:
        """
        Crea configuración desde un preset.
        
        :param preset: Preset ('tiny', 'small', 'medium', 'large', 'xl')
        :return: Diccionario con configuración
        """
        presets = {
            'tiny': {
                'vocab_size': 1000,
                'd_model': 128,
                'n_heads': 4,
                'n_layers': 2,
                'd_ff': 512,
                'max_seq_len': 128,
                'dropout': 0.1
            },
            'small': {
                'vocab_size': 5000,
                'd_model': 256,
                'n_heads': 8,
                'n_layers': 4,
                'd_ff': 1024,
                'max_seq_len': 256,
                'dropout': 0.1
            },
            'medium': {
                'vocab_size': 10000,
                'd_model': 512,
                'n_heads': 8,
                'n_layers': 6,
                'd_ff': 2048,
                'max_seq_len': 512,
                'dropout': 0.1
            },
            'large': {
                'vocab_size': 20000,
                'd_model': 768,
                'n_heads': 12,
                'n_layers': 12,
                'd_ff': 3072,
                'max_seq_len': 1024,
                'dropout': 0.1
            },
            'xl': {
                'vocab_size': 50000,
                'd_model': 1024,
                'n_heads': 16,
                'n_layers': 24,
                'd_ff': 4096,
                'max_seq_len': 2048,
                'dropout': 0.1
            }
        }
        
        if preset not in presets:
            raise ValueError(f"Preset '{preset}' no válido. Opciones: {list(presets.keys())}")
        
        return presets[preset].copy()
    
    @staticmethod
    def validate_config(config: dict) -> Tuple[bool, list, list]:
        """
        Valida una configuración.
        
        :param config: Configuración a validar
        :return: Tuple de (is_valid, errors, warnings)
        """
        errors = []
        warnings = []
        
        # Validar campos requeridos
        required = ['vocab_size', 'd_model', 'n_heads', 'n_layers', 'd_ff', 'max_seq_len']
        for field in required:
            if field not in config:
                errors.append(f"Campo requerido faltante: {field}")
        
        # Validar valores
        if 'vocab_size' in config and config['vocab_size'] < 100:
            errors.append("vocab_size debe ser >= 100")
        
        if 'd_model' in config:
            if config['d_model'] < 64:
                errors.append("d_model debe ser >= 64")
            if config['d_model'] % 2 != 0:
                warnings.append("d_model debería ser potencia de 2 para eficiencia GPU")
        
        if 'n_heads' in config and 'd_model' in config:
            if config['d_model'] % config['n_heads'] != 0:
                errors.append(f"d_model ({config['d_model']}) debe ser divisible por n_heads ({config['n_heads']})")
        
        if 'd_ff' in config and 'd_model' in config:
            if config['d_ff'] < config['d_model']:
                warnings.append("d_ff típicamente es >= d_model")
        
        return len(errors) == 0, errors, warnings


class ModelValidator:
    """
    Validador de modelos y configuraciones.
    """
    
    @staticmethod
    def validate_model_config(
        vocab_size: int,
        d_model: int,
        n_heads: int,
        n_layers: int,
        d_ff: int,
        max_seq_len: int,
        **kwargs
    ) -> Tuple[bool, list, list]:
        """
        Valida configuración de modelo.
        
        :param vocab_size: Tamaño del vocabulario
        :param d_model: Dimensión del modelo
        :param n_heads: Número de heads
        :param n_layers: Número de capas
        :param d_ff: Dimensión feed-forward
        :param max_seq_len: Longitud máxima de secuencia
        :param kwargs: Argumentos adicionales
        :return: Tuple de (is_valid, errors, warnings)
        """
        errors = []
        warnings = []
        
        # Validar vocab_size
        if vocab_size < 100:
            errors.append("vocab_size debe ser >= 100")
        elif vocab_size > 100000:
            warnings.append("vocab_size muy grande puede requerir mucha memoria")
        
        # Validar d_model
        if d_model < 64:
            errors.append("d_model debe ser >= 64")
        if d_model % 2 != 0:
            warnings.append("d_model debería ser par o potencia de 2")
        
        # Validar n_heads
        if n_heads < 1:
            errors.append("n_heads debe ser >= 1")
        if d_model % n_heads != 0:
            errors.append(f"d_model ({d_model}) debe ser divisible por n_heads ({n_heads})")
        
        d_k = d_model // n_heads
        if d_k < 32:
            warnings.append(f"d_k ({d_k}) es muy pequeño, considerar reducir n_heads")
        if d_k > 128:
            warnings.append(f"d_k ({d_k}) es muy grande, considerar aumentar n_heads")
        
        # Validar n_layers
        if n_layers < 1:
            errors.append("n_layers debe ser >= 1")
        if n_layers > 48:
            warnings.append("n_layers muy grande puede ser difícil de entrenar")
        
        # Validar d_ff
        if d_ff < d_model:
            warnings.append(f"d_ff ({d_ff}) típicamente es >= d_model ({d_model})")
        
        # Validar max_seq_len
        if max_seq_len < 32:
            errors.append("max_seq_len debe ser >= 32")
        if max_seq_len > 8192:
            warnings.append("max_seq_len muy grande requiere mucha memoria")
        
        return len(errors) == 0, errors, warnings
    
    @staticmethod
    def validate_model_architecture(model: CausalTransformer) -> dict:
        """
        Valida arquitectura del modelo.
        
        :param model: Modelo a validar
        :return: Diccionario con resultados de validación
        """
        errors = []
        warnings = []
        
        # Verificar que el modelo tenga los componentes necesarios
        required_components = ['token_embedding', 'pos_encoding', 'blocks', 'layer_norm', 'output_projection']
        for comp in required_components:
            if not hasattr(model, comp):
                errors.append(f"Componente faltante: {comp}")
        
        # Verificar número de bloques
        if len(model.blocks) == 0:
            errors.append("Modelo debe tener al menos un bloque")
        
        # Verificar consistencia de dimensiones
        if hasattr(model, 'blocks') and len(model.blocks) > 0:
            first_block = model.blocks[0]
            if hasattr(first_block, 'attention'):
                if hasattr(first_block.attention, 'num_heads'):
                    if model.d_model % first_block.attention.num_heads != 0:
                        errors.append("Inconsistencia en dimensiones de atención")
        
        return {
            'is_valid': len(errors) == 0,
            'errors': errors,
            'warnings': warnings
        }


class VisualizationUtilities:
    """
    Utilidades para visualización de entrenamiento y resultados.
    """
    
    @staticmethod
    def plot_training_curves(
        train_losses: list,
        eval_losses: Optional[list] = None,
        train_perplexities: Optional[list] = None,
        eval_perplexities: Optional[list] = None,
        save_path: Optional[str] = None
    ):
        """
        Plotea curvas de entrenamiento.
        
        :param train_losses: Lista de pérdidas de entrenamiento
        :param eval_losses: Lista de pérdidas de evaluación (opcional)
        :param train_perplexities: Lista de perplexities de entrenamiento (opcional)
        :param eval_perplexities: Lista de perplexities de evaluación (opcional)
        :param save_path: Ruta para guardar (opcional)
        """
        try:
            import matplotlib.pyplot as plt
        except ImportError:
            print("⚠️ matplotlib no está instalado. Instala con: pip install matplotlib")
            return
        
        fig, axes = plt.subplots(1, 2 if eval_losses else 1, figsize=(12, 4))
        if not isinstance(axes, np.ndarray):
            axes = [axes]
        
        # Plot losses
        axes[0].plot(train_losses, label='Train Loss', color='blue')
        if eval_losses:
            axes[0].plot(eval_losses, label='Eval Loss', color='red')
        axes[0].set_xlabel('Epoch')
        axes[0].set_ylabel('Loss')
        axes[0].set_title('Training Loss')
        axes[0].legend()
        axes[0].grid(True)
        
        # Plot perplexities si están disponibles
        if len(axes) > 1 and (train_perplexities or eval_perplexities):
            if train_perplexities:
                axes[1].plot(train_perplexities, label='Train Perplexity', color='blue')
            if eval_perplexities:
                axes[1].plot(eval_perplexities, label='Eval Perplexity', color='red')
            axes[1].set_xlabel('Epoch')
            axes[1].set_ylabel('Perplexity')
            axes[1].set_title('Perplexity')
            axes[1].legend()
            axes[1].grid(True)
        
        plt.tight_layout()
        
        if save_path:
            plt.savefig(save_path, dpi=300, bbox_inches='tight')
            print(f"✅ Gráfico guardado en: {save_path}")
        else:
            plt.show()
        
        plt.close()
    
    @staticmethod
    def plot_parameter_distribution(model: nn.Module, save_path: Optional[str] = None):
        """
        Plotea distribución de parámetros del modelo.
        
        :param model: Modelo
        :param save_path: Ruta para guardar (opcional)
        """
        try:
            import matplotlib.pyplot as plt
        except ImportError:
            print("⚠️ matplotlib no está instalado")
            return
        
        all_params = []
        for param in model.parameters():
            all_params.extend(param.data.cpu().numpy().flatten().tolist())
        
        plt.figure(figsize=(10, 6))
        plt.hist(all_params, bins=100, alpha=0.7, edgecolor='black')
        plt.xlabel('Valor de Parámetro')
        plt.ylabel('Frecuencia')
        plt.title('Distribución de Parámetros del Modelo')
        plt.grid(True, alpha=0.3)
        
        if save_path:
            plt.savefig(save_path, dpi=300, bbox_inches='tight')
            print(f"✅ Gráfico guardado en: {save_path}")
        else:
            plt.show()
        
        plt.close()


class ModelInspector:
    """
    Inspector de modelos para análisis detallado.
    """
    
    @staticmethod
    def inspect_layer_shapes(model: CausalTransformer, input_shape: Tuple[int, int]) -> dict:
        """
        Inspecciona formas de salida de cada capa.
        
        :param model: Modelo
        :param input_shape: Forma de entrada (batch, seq_len)
        :return: Diccionario con formas de cada capa
        """
        shapes = {}
        x = torch.randint(0, model.vocab_size, input_shape)
        
        # Embedding
        x_emb = model.token_embedding(x)
        shapes['token_embedding'] = list(x_emb.shape)
        
        # Positional encoding
        if hasattr(model, 'pos_encoding'):
            x_pos = model.pos_encoding(x_emb)
            shapes['positional_encoding'] = list(x_pos.shape)
            x = x_pos
        else:
            x = x_emb
        
        # Blocks
        for i, block in enumerate(model.blocks):
            x_before = x.clone()
            x = block(x)
            shapes[f'block_{i}_input'] = list(x_before.shape)
            shapes[f'block_{i}_output'] = list(x.shape)
        
        # Final layer norm
        if hasattr(model, 'layer_norm'):
            x = model.layer_norm(x)
            shapes['final_layer_norm'] = list(x.shape)
        
        # Output projection
        logits = model.output_projection(x)
        shapes['output_projection'] = list(logits.shape)
        
        return shapes
    
    @staticmethod
    def get_layer_statistics(model: nn.Module) -> dict:
        """
        Obtiene estadísticas de cada capa.
        
        :param model: Modelo
        :return: Diccionario con estadísticas
        """
        stats = {}
        
        for name, module in model.named_modules():
            if len(list(module.children())) == 0:  # Solo módulos hoja
                params = list(module.parameters())
                if len(params) > 0:
                    total_params = sum(p.numel() for p in params)
                    if total_params > 0:
                        stats[name] = {
                            'num_parameters': total_params,
                            'num_parameters_millions': total_params / 1e6,
                            'requires_grad': any(p.requires_grad for p in params)
                        }
        
        return stats


class PerformanceProfiler:
    """
    Profiler avanzado de rendimiento.
    """
    
    def __init__(self):
        """Inicializa el profiler."""
        self.profile_data = {}
        self.start_time = None
    
    def start(self):
        """Inicia el profiling."""
        self.start_time = time.time()
        self.profile_data = {}
    
    def profile(self, name: str):
        """
        Context manager para perfilar una sección.
        
        :param name: Nombre de la sección
        :return: Context manager
        """
        return self._ProfileContext(self, name)
    
    class _ProfileContext:
        def __init__(self, profiler, name):
            self.profiler = profiler
            self.name = name
            self.start_time = None
        
        def __enter__(self):
            self.start_time = time.time()
            return self
        
        def __exit__(self, exc_type, exc_val, exc_tb):
            elapsed = time.time() - self.start_time
            if self.name not in self.profiler.profile_data:
                self.profiler.profile_data[self.name] = []
            self.profiler.profile_data[self.name].append(elapsed)
    
    def get_report(self) -> dict:
        """
        Obtiene reporte de profiling.
        
        :return: Diccionario con estadísticas
        """
        report = {}
        
        for name, times in self.profile_data.items():
            if times:
                report[name] = {
                    'total_time': sum(times),
                    'mean_time': np.mean(times),
                    'min_time': np.min(times),
                    'max_time': np.max(times),
                    'num_calls': len(times)
                }
        
        if self.start_time:
            report['total_elapsed'] = time.time() - self.start_time
        
        return report
    
    @staticmethod
    def profile_memory_usage(
        model: nn.Module,
        input_tensor: torch.Tensor,
        device: str = 'cpu'
    ) -> dict:
        """
        Profilea uso de memoria.
        
        :param model: Modelo
        :param input_tensor: Tensor de entrada
        :param device: Device
        :return: Diccionario con estadísticas de memoria
        """
        if device == 'cpu':
            import psutil
            process = psutil.Process()
            mem_before = process.memory_info().rss / 1024 / 1024  # MB
            
            model.eval()
            with torch.no_grad():
                _ = model(input_tensor)
            
            mem_after = process.memory_info().rss / 1024 / 1024  # MB
            
            return {
                'memory_before_mb': mem_before,
                'memory_after_mb': mem_after,
                'memory_used_mb': mem_after - mem_before
            }
        else:
            # GPU memory
            if torch.cuda.is_available():
                torch.cuda.reset_peak_memory_stats()
                torch.cuda.empty_cache()
                
                model = model.to(device)
                input_tensor = input_tensor.to(device)
                
                model.eval()
                with torch.no_grad():
                    _ = model(input_tensor)
                
                peak_memory = torch.cuda.max_memory_allocated() / 1024 / 1024  # MB
                
                return {
                    'peak_memory_mb': peak_memory,
                    'device': device
                }
            else:
                return {'error': 'CUDA no disponible'}


