class FlashAttentionOptimizer:
    """
    Optimizador para implementar Flash Attention (reducción de memoria O(n²) a O(n)).
    
    Flash Attention es una optimización que reduce el uso de memoria cuadrática
    de la atención tradicional a lineal, permitiendo secuencias mucho más largas.
    """
    
    @staticmethod
    def implement_flash_attention_simple(
        Q: torch.Tensor,
        K: torch.Tensor,
        V: torch.Tensor,
        causal: bool = True,
        block_size: int = 64
    ) -> torch.Tensor:
        """
        Implementación simplificada de Flash Attention.
        
        :param Q: Queries (batch, n_heads, seq_len, d_k)
        :param K: Keys (batch, n_heads, seq_len, d_k)
        :param V: Values (batch, n_heads, seq_len, d_k)
        :param causal: Si True, aplica máscara causal
        :param block_size: Tamaño del bloque para procesamiento por chunks
        :return: Output de atención
        """
        batch_size, n_heads, seq_len, d_k = Q.shape
        
        # Dividir en bloques para procesamiento eficiente
        output = torch.zeros_like(Q)
        scale = 1.0 / math.sqrt(d_k)
        
        for i in range(0, seq_len, block_size):
            end_i = min(i + block_size, seq_len)
            Q_block = Q[:, :, i:end_i, :]  # (batch, heads, block_size, d_k)
            
            # Para cada bloque de Q, calcular atención sobre todos los K anteriores (causal)
            for j in range(0, end_i, block_size):
                end_j = min(j + block_size, end_i if causal else seq_len)
                
                if causal and end_j <= i:
                    continue  # Skip bloques futuros en causal attention
                
                K_block = K[:, :, j:end_j, :]
                V_block = V[:, :, j:end_j, :]
                
                # Calcular scores
                scores = torch.matmul(Q_block, K_block.transpose(-2, -1)) * scale
                
                # Aplicar máscara causal si es necesario
                if causal:
                    mask = torch.tril(torch.ones(end_i - i, end_j - j, device=Q.device))
                    scores = scores.masked_fill(mask == 0, float('-inf'))
                
                # Softmax
                attn_weights = F.softmax(scores, dim=-1)
                
                # Aplicar a V
                attn_output = torch.matmul(attn_weights, V_block)
                output[:, :, i:end_i, :] += attn_output
        
        return output
    
    @staticmethod
    def calculate_memory_savings(
        seq_len: int,
        d_model: int,
        n_heads: int,
        block_size: int = 64
    ) -> dict:
        """
        Calcula ahorro de memoria con Flash Attention.
        
        :param seq_len: Longitud de secuencia
        :param d_model: Dimensión del modelo
        :param n_heads: Número de heads
        :param block_size: Tamaño del bloque
        :return: Diccionario con estadísticas de memoria
        """
        d_k = d_model // n_heads
        
        # Memoria tradicional (O(n²))
        traditional_memory = seq_len * seq_len * n_heads * 4  # float32 = 4 bytes
        
        # Memoria Flash Attention (O(n))
        flash_memory = seq_len * block_size * n_heads * 4
        
        savings = traditional_memory - flash_memory
        savings_percent = (savings / traditional_memory) * 100
        
        return {
            'traditional_memory_mb': traditional_memory / (1024 * 1024),
            'flash_memory_mb': flash_memory / (1024 * 1024),
            'savings_mb': savings / (1024 * 1024),
            'savings_percent': savings_percent,
            'max_seq_len_traditional': int(8192 * 1024 * 1024 / (seq_len * n_heads * 4)),  # Asumiendo 8GB GPU
            'max_seq_len_flash': int(8192 * 1024 * 1024 / (block_size * n_heads * 4))
        }


class ArchitectureComparison:
    """
    Utilidad para comparar diferentes arquitecturas de transformers.
    """
    
    @staticmethod
    def compare_architectures(
        configs: List[dict],
        batch_size: int = 1,
        seq_len: int = 512
    ) -> dict:
        """
        Compara diferentes configuraciones de arquitectura.
        
        :param configs: Lista de configuraciones a comparar
        :param batch_size: Tamaño del batch
        :param seq_len: Longitud de secuencia
        :return: Diccionario con comparación
        """
        results = {}
        
        for i, config in enumerate(configs):
            config_name = config.get('name', f'config_{i}')
            
            # Estimar parámetros
            vocab_size = config.get('vocab_size', 10000)
            d_model = config.get('d_model', 512)
            n_heads = config.get('n_heads', 8)
            n_layers = config.get('n_layers', 6)
            d_ff = config.get('d_ff', 2048)
            
            # Calcular parámetros
            embedding_params = vocab_size * d_model
            pos_params = seq_len * d_model
            attn_params_per_layer = 4 * d_model * d_model
            ffn_params_per_layer = 2 * d_model * d_ff
            ln_params_per_layer = 2 * d_model
            output_params = d_model * vocab_size
            
            total_params = (embedding_params + pos_params + 
                          n_layers * (attn_params_per_layer + ffn_params_per_layer + ln_params_per_layer) +
                          output_params)
            
            # Estimar memoria
            memory_estimate = estimate_memory_usage(
                batch_size, seq_len, d_model, n_heads, n_layers, vocab_size
            )
            
            results[config_name] = {
                'config': config,
                'total_parameters': total_params,
                'total_parameters_millions': total_params / 1e6,
                'memory_estimate_mb': memory_estimate['total_mb'],
                'memory_estimate_gb': memory_estimate['total_gb'],
                'd_model': d_model,
                'n_layers': n_layers,
                'n_heads': n_heads,
                'd_ff': d_ff
            }
        
        return results
    
    @staticmethod
    def print_comparison_table(results: dict):
        """
        Imprime tabla de comparación de arquitecturas.
        
        :param results: Resultados de compare_architectures
        """
        print("\n" + "="*100)
        print("COMPARACIÓN DE ARQUITECTURAS")
        print("="*100)
        print(f"{'Configuración':<20} {'Parámetros (M)':<18} {'Memoria (GB)':<15} {'d_model':<10} {'Layers':<10} {'Heads':<10}")
        print("-"*100)
        
        for name, data in results.items():
            print(f"{name:<20} "
                  f"{data['total_parameters_millions']:>15.2f}M  "
                  f"{data['memory_estimate_gb']:>12.3f}  "
                  f"{data['d_model']:>8}  "
                  f"{data['n_layers']:>8}  "
                  f"{data['n_heads']:>8}")
        
        print("="*100)


class AdvancedAttentionAnalysis:
    """
    Análisis avanzado de patrones de atención.
    """
    
    @staticmethod
    def analyze_attention_heads(
        attention_weights: torch.Tensor,
        head_names: Optional[List[str]] = None
    ) -> dict:
        """
        Analiza patrones de atención por cabeza.
        
        :param attention_weights: Pesos de atención (batch, heads, seq_len, seq_len)
        :param head_names: Nombres opcionales para las cabezas
        :return: Diccionario con análisis
        """
        batch_size, n_heads, seq_len, _ = attention_weights.shape
        
        analysis = {}
        
        for head_idx in range(n_heads):
            head_name = head_names[head_idx] if head_names and head_idx < len(head_names) else f'head_{head_idx}'
            
            attn_head = attention_weights[0, head_idx]  # Primer batch
            
            # Entropía de atención (diversidad)
            probs = attn_head + 1e-9  # Evitar log(0)
            entropy = -torch.sum(probs * torch.log(probs), dim=-1).mean().item()
            
            # Promedio de atención (qué tan concentrada está)
            mean_attention = attn_head.mean().item()
            
            # Max atención (qué tan concentrada está la atención máxima)
            max_attention = attn_head.max(dim=-1)[0].mean().item()
            
            # Distancia promedio de atención (para atención causal)
            positions = torch.arange(seq_len, device=attn_head.device).float()
            attention_positions = torch.sum(attn_head * positions.unsqueeze(0), dim=-1)
            current_positions = positions.unsqueeze(0)
            avg_distance = (attention_positions - current_positions).abs().mean().item()
            
            analysis[head_name] = {
                'entropy': entropy,
                'mean_attention': mean_attention,
                'max_attention': max_attention,
                'avg_distance': avg_distance,
                'concentration': max_attention / mean_attention if mean_attention > 0 else 0
            }
        
        return analysis
    
    @staticmethod
    def identify_attention_patterns(attention_weights: torch.Tensor) -> dict:
        """
        Identifica patrones comunes de atención.
        
        :param attention_weights: Pesos de atención
        :return: Diccionario con patrones identificados
        """
        batch_size, n_heads, seq_len, _ = attention_weights.shape
        
        patterns = {
            'local_attention': 0,  # Atención a tokens cercanos
            'global_attention': 0,  # Atención amplia
            'diagonal_attention': 0,  # Atención a tokens específicos
            'uniform_attention': 0  # Atención uniforme
        }
        
        for head_idx in range(n_heads):
            attn = attention_weights[0, head_idx]
            
            # Local attention (atención a tokens dentro de ventana)
            window_size = seq_len // 4
            local_mask = torch.abs(torch.arange(seq_len).unsqueeze(0) - 
                                  torch.arange(seq_len).unsqueeze(1)) <= window_size
            local_score = (attn * local_mask.float()).sum().item() / attn.sum().item()
            
            # Global attention (atención dispersa)
            entropy = -torch.sum(attn * torch.log(attn + 1e-9), dim=-1).mean().item()
            global_score = entropy / math.log(seq_len)  # Normalizado
            
            # Diagonal attention (atención a posición específica)
            diagonal_score = torch.diagonal(attn, offset=0).mean().item()
            
            # Uniform attention
            uniform_value = 1.0 / seq_len
            uniform_score = 1.0 - torch.abs(attn.mean() - uniform_value).item()
            
            patterns['local_attention'] += local_score
            patterns['global_attention'] += global_score
            patterns['diagonal_attention'] += diagonal_score
            patterns['uniform_attention'] += uniform_score
        
        # Promediar sobre heads
        for key in patterns:
            patterns[key] /= n_heads
        
        return patterns


class ModelComparison:
    """
    Utilidad para comparar modelos entrenados.
    """
    
    @staticmethod
    def compare_models(
        models: List[CausalTransformer],
        model_names: Optional[List[str]] = None,
        test_input: Optional[torch.Tensor] = None
    ) -> dict:
        """
        Compara múltiples modelos.
        
        :param models: Lista de modelos a comparar
        :param model_names: Nombres opcionales para los modelos
        :param test_input: Input de prueba opcional
        :return: Diccionario con comparación
        """
        if model_names is None:
            model_names = [f'model_{i}' for i in range(len(models))]
        
        comparison = {}
        
        for model, name in zip(models, model_names):
            # Contar parámetros
            params = count_parameters(model)
            
            # Estimar memoria
            if test_input is not None:
                memory = estimate_memory_usage(
                    test_input.shape[0],
                    test_input.shape[1],
                    model.d_model,
                    model.blocks[0].attention.num_heads if hasattr(model.blocks[0], 'attention') else 8,
                    len(model.blocks),
                    model.vocab_size
                )
            else:
                memory = {'total_mb': 0, 'total_gb': 0}
            
            comparison[name] = {
                'parameters': params,
                'memory_estimate': memory,
                'vocab_size': model.vocab_size,
                'd_model': model.d_model,
                'n_layers': len(model.blocks),
                'n_heads': model.blocks[0].attention.num_heads if hasattr(model.blocks[0], 'attention') else 8
            }
        
        return comparison


class InteractiveExamples:
    """
    Ejemplos interactivos para demostración.
    """
    
    @staticmethod
    def demo_attention_mechanism():
        """
        Demuestra el mecanismo de atención paso a paso.
        """
        print("\n" + "="*70)
        print("DEMOSTRACIÓN: MECANISMO DE ATENCIÓN")
        print("="*70)
        
        # Crear inputs de ejemplo
        batch_size, seq_len, d_model = 1, 5, 64
        n_heads = 4
        
        Q = torch.randn(batch_size, n_heads, seq_len, d_model // n_heads)
        K = torch.randn(batch_size, n_heads, seq_len, d_model // n_heads)
        V = torch.randn(batch_size, n_heads, seq_len, d_model // n_heads)
        
        print(f"\n1. Inputs:")
        print(f"   Q shape: {Q.shape}")
        print(f"   K shape: {K.shape}")
        print(f"   V shape: {V.shape}")
        
        # Calcular scores
        scores = torch.matmul(Q, K.transpose(-2, -1)) / math.sqrt(d_model // n_heads)
        print(f"\n2. Scores (Q @ K^T / √d_k):")
        print(f"   Shape: {scores.shape}")
        print(f"   Sample scores[0, 0]:\n{scores[0, 0]}")
        
        # Aplicar softmax
        attn_weights = F.softmax(scores, dim=-1)
        print(f"\n3. Attention Weights (softmax):")
        print(f"   Shape: {attn_weights.shape}")
        print(f"   Sum per row: {attn_weights[0, 0].sum(dim=-1)}")
        print(f"   Sample weights[0, 0]:\n{attn_weights[0, 0]}")
        
        # Aplicar a V
        output = torch.matmul(attn_weights, V)
        print(f"\n4. Output (weights @ V):")
        print(f"   Shape: {output.shape}")
        print(f"   Sample output[0, 0, 0, :5]: {output[0, 0, 0, :5]}")
        
        print("\n✅ Demostración completada")
    
