class ModelAnalyzer:
    """
    Utilidad para análisis profundo de modelos.
    """
    
    @staticmethod
    def analyze_layer_importance(model: CausalTransformer, data_loader, device: str = 'cpu') -> dict:
        """
        Analiza la importancia de cada capa del modelo.
        
        :param model: Modelo a analizar
        :param data_loader: DataLoader con datos
        :param device: Device
        :return: Diccionario con importancia por capa
        """
        model.eval()
        model = model.to(device)
        
        # Obtener pérdida base
        base_loss = 0.0
        n_samples = 0
        
        with torch.no_grad():
            for batch in data_loader:
                inputs = batch['input_ids'].to(device)
                targets = batch['labels'].to(device)
                
                logits = model(inputs)
                loss = F.cross_entropy(
                    logits.view(-1, logits.size(-1)),
                    targets.view(-1),
                    ignore_index=-1
                )
                base_loss += loss.item()
                n_samples += 1
        
        base_loss /= n_samples
        
        # Analizar importancia por capa
        layer_importance = {}
        
        for i, block in enumerate(model.blocks):
            # Crear modelo sin esta capa
            temp_model = CausalTransformer(
                vocab_size=model.vocab_size,
                d_model=model.d_model,
                n_heads=model.blocks[0].attention.n_heads,
                n_layers=len(model.blocks) - 1,
                d_ff=model.blocks[0].ffn.linear1.out_features,
                max_seq_len=512
            )
            
            # Copiar pesos (excepto la capa i)
            # Esto es una simplificación - en producción usar métodos más sofisticados
            layer_importance[i] = {
                'importance_score': 1.0,  # Placeholder
                'layer_type': 'TransformerBlock'
            }
        
        return {
            'base_loss': base_loss,
            'layer_importance': layer_importance
        }
    
    @staticmethod
    def analyze_attention_patterns_by_layer(
        model: CausalTransformer,
        input_tensor: torch.Tensor,
        return_attentions: bool = True
    ) -> dict:
        """
        Analiza patrones de atención por capa.
        
        :param model: Modelo
        :param input_tensor: Tensor de entrada
        :param return_attentions: Si True, captura pesos de atención
        :return: Diccionario con análisis por capa
        """
        model.eval()
        
        # Modificar forward para capturar atención de cada capa
        attention_by_layer = []
        
        with torch.no_grad():
            # Embeddings
            x = model.token_embedding(input_tensor)
            x = model.pos_encoding(x)
            x = model.dropout(x)
            
            # Procesar cada bloque y capturar atención
            for i, block in enumerate(model.blocks):
                # Capturar atención (simplificado)
                # En producción, modificar forward para retornar atención
                x_norm = block.ln1(x)
                attn_output, attn_weights = block.attention(x_norm)
                x = x + attn_output
                
                # Analizar atención
                attn_stats = AttentionVisualizer.analyze_attention_patterns(attn_weights)
                attention_by_layer.append({
                    'layer': i,
                    'stats': attn_stats
                })
                
                # Continuar forward
                x_norm = block.ln2(x)
                ffn_output = block.ffn(x_norm)
                x = x + ffn_output
        
        return {
            'attention_by_layer': attention_by_layer,
            'num_layers': len(attention_by_layer)
        }


class MemoryOptimizer:
    """
    Utilidad para optimización avanzada de memoria.
    """
    
    @staticmethod
    def estimate_training_memory(
        model: CausalTransformer,
        batch_size: int,
        seq_len: int,
        gradient_accumulation: int = 1,
        mixed_precision: bool = False,
        gradient_checkpointing: bool = False
    ) -> dict:
        """
        Estima memoria necesaria para entrenamiento.
        
        :param model: Modelo
        :param batch_size: Tamaño del batch
        :param seq_len: Longitud de secuencia
        :param gradient_accumulation: Pasos de acumulación
        :param mixed_precision: Si True, usa float16
        :param gradient_checkpointing: Si True, usa checkpointing
        :return: Diccionario con estimaciones
        """
        dtype_bytes = 2 if mixed_precision else 4
        
        # Parámetros
        params = count_parameters(model)
        params_memory = params['total'] * dtype_bytes
        
        # Activaciones (forward)
        forward_memory = estimate_memory_usage(
            batch_size, seq_len, model.d_model,
            model.blocks[0].attention.n_heads,
            len(model.blocks),
            model.vocab_size,
            dtype_bytes
        )['activations_mb']
        
        # Gradientes
        gradients_memory = params['total'] * dtype_bytes / (1024 ** 2)
        
        # Optimizador (AdamW: 2x parámetros para momentum)
        optimizer_memory = params['total'] * 2 * dtype_bytes / (1024 ** 2)
        
        # Reducción por gradient checkpointing
        if gradient_checkpointing:
            forward_memory *= 0.5  # Aproximado
        
        total_memory = (
            params_memory / (1024 ** 2) +
            forward_memory +
            gradients_memory +
            optimizer_memory
        )
        
        return {
            'parameters_mb': params_memory / (1024 ** 2),
            'forward_activations_mb': forward_memory,
            'gradients_mb': gradients_memory,
            'optimizer_mb': optimizer_memory,
            'total_mb': total_memory,
            'total_gb': total_memory / 1024,
            'mixed_precision': mixed_precision,
            'gradient_checkpointing': gradient_checkpointing
        }
    
    @staticmethod
    def optimize_batch_size_for_memory(
        model: CausalTransformer,
        available_memory_gb: float,
        seq_len: int,
        target_batch_size: int = 32
    ) -> dict:
        """
        Encuentra el tamaño de batch óptimo para la memoria disponible.
        
        :param model: Modelo
        :param available_memory_gb: Memoria disponible en GB
        :param seq_len: Longitud de secuencia
        :param target_batch_size: Tamaño de batch objetivo
        :return: Diccionario con recomendaciones
        """
        best_batch_size = target_batch_size
        
        # Probar diferentes batch sizes
        for batch_size in [1, 2, 4, 8, 16, 32, 64, 128]:
            memory_estimate = MemoryOptimizer.estimate_training_memory(
                model, batch_size, seq_len
            )
            
            if memory_estimate['total_gb'] <= available_memory_gb:
                best_batch_size = batch_size
            else:
                break
        
        # Calcular con optimizaciones
        memory_with_mixed = MemoryOptimizer.estimate_training_memory(
            model, best_batch_size, seq_len, mixed_precision=True
        )
        
        memory_with_checkpointing = MemoryOptimizer.estimate_training_memory(
            model, best_batch_size, seq_len, gradient_checkpointing=True
        )
        
        memory_with_both = MemoryOptimizer.estimate_training_memory(
            model, best_batch_size, seq_len,
            mixed_precision=True,
            gradient_checkpointing=True
        )
        
        return {
            'recommended_batch_size': best_batch_size,
            'memory_estimate_mb': MemoryOptimizer.estimate_training_memory(
                model, best_batch_size, seq_len
            )['total_mb'],
            'with_mixed_precision_mb': memory_with_mixed['total_mb'],
            'with_checkpointing_mb': memory_with_checkpointing['total_mb'],
            'with_both_mb': memory_with_both['total_mb'],
            'recommendations': [
                'Usar mixed precision si es posible',
                'Usar gradient checkpointing para reducir memoria',
                f'Batch size recomendado: {best_batch_size}',
                f'Usar gradient accumulation si necesitas batch_size > {best_batch_size}'
            ]
        }


class ParallelTraining:
    """
    Utilidad para entrenamiento paralelo avanzado.
    """
    
    @staticmethod
    def setup_distributed_training(
        model: nn.Module,
        device_ids: Optional[list] = None,
        backend: str = 'nccl'
    ):
        """
        Configura entrenamiento distribuido.
        
        :param model: Modelo
        :param device_ids: Lista de device IDs
        :param backend: Backend ('nccl' para GPU, 'gloo' para CPU)
        :return: Modelo configurado
        """
        try:
            import torch.distributed as dist
            
            if not dist.is_available():
                print("⚠️ Distributed training no disponible")
                return model
            
            # Configurar distributed
            if device_ids is None:
                device_ids = list(range(torch.cuda.device_count()))
            
            if len(device_ids) > 1:
                model = nn.DataParallel(model, device_ids=device_ids)
                print(f"✅ Entrenamiento distribuido configurado para {len(device_ids)} GPUs")
            else:
                print("⚠️ Solo hay 1 GPU disponible, distributed training no aplica")
            
            return model
        except Exception as e:
            print(f"⚠️ Error configurando distributed training: {e}")
            return model
    
    @staticmethod
    def create_parallel_data_loader(
        dataset,
        batch_size: int,
        num_workers: int = 4,
        pin_memory: bool = True
    ):
        """
        Crea DataLoader optimizado para entrenamiento paralelo.
        
        :param dataset: Dataset
        :param batch_size: Tamaño del batch
        :param num_workers: Número de workers
        :param pin_memory: Si True, usa pin_memory
        :return: DataLoader
        """
        from torch.utils.data import DataLoader
        
        return DataLoader(
            dataset,
            batch_size=batch_size,
            shuffle=True,
            num_workers=num_workers,
            pin_memory=pin_memory,
            persistent_workers=True if num_workers > 0 else False
        )


class ModelComparison:
    """
    Utilidad para comparar múltiples modelos.
    """
    
    @staticmethod
    def compare_architectures(
        configs: list,
        test_data: torch.Tensor,
        metrics: list = ['params', 'memory', 'speed']
    ) -> dict:
        """
        Compara diferentes arquitecturas.
        
        :param configs: Lista de configuraciones
        :param test_data: Datos de prueba
        :param metrics: Métricas a comparar
        :return: Diccionario con comparación
        """
        results = {}
        
        for i, config in enumerate(configs):
            model = CausalTransformer(**config)
            
            model_results = {}
            
            if 'params' in metrics:
                params = count_parameters(model)
                model_results['params'] = params['total']
                model_results['params_millions'] = params['total_millions']
            
            if 'memory' in metrics:
                memory = estimate_memory_usage(
                    batch_size=test_data.shape[0],
                    seq_len=test_data.shape[1],
                    d_model=config['d_model'],
                    n_heads=config['n_heads'],
                    n_layers=config['n_layers'],
                    vocab_size=config['vocab_size']
                )
                model_results['memory_mb'] = memory['total_mb']
            
            if 'speed' in metrics:
                benchmark = ModelBenchmark.benchmark_forward_pass(
                    model,
                    batch_size=test_data.shape[0],
                    seq_len=test_data.shape[1],
                    vocab_size=config['vocab_size'],
                    num_runs=5
                )
                model_results['avg_time_ms'] = benchmark['avg_time_ms']
                model_results['tokens_per_second'] = benchmark['tokens_per_second']
            
            results[f'config_{i}'] = {
                'config': config,
                'results': model_results
            }
        
        return results
    
    @staticmethod
    def find_optimal_config(
        target_params: Optional[int] = None,
        target_memory_gb: Optional[float] = None,
        target_speed_tokens_per_sec: Optional[float] = None,
        vocab_size: int = 10000
    ) -> dict:
        """
        Encuentra configuración óptima basada en restricciones.
        
        :param target_params: Número objetivo de parámetros
        :param target_memory_gb: Memoria objetivo en GB
        :param target_speed_tokens_per_sec: Velocidad objetivo
        :param vocab_size: Tamaño del vocabulario
        :return: Configuración óptima
        """
        # Generar candidatos
        candidates = []
        
        for d_model in [128, 256, 512, 768, 1024]:
            for n_layers in [2, 4, 6, 12, 24]:
                for n_heads in [4, 8, 16]:
                    if d_model % n_heads != 0:
                        continue
                    
                    d_ff = 4 * d_model
                    
                    config = {
                        'vocab_size': vocab_size,
                        'd_model': d_model,
                        'n_heads': n_heads,
                        'n_layers': n_layers,
                        'd_ff': d_ff,
                        'max_seq_len': 512,
                        'dropout': 0.1
                    }
                    
                    params = (vocab_size * d_model + 
                             n_layers * (12 * d_model * d_model) +
                             vocab_size * d_model)
                    
                    # Filtrar por restricciones
                    if target_params and params > target_params * 1.2:
                        continue
                    
                    candidates.append({
                        'config': config,
                        'estimated_params': params
                    })
        
        # Ordenar y seleccionar mejor
        if target_params:
            candidates.sort(key=lambda x: abs(x['estimated_params'] - target_params))
        elif target_memory_gb:
            # Ordenar por memoria estimada
            candidates.sort(key=lambda x: estimate_memory_usage(
                batch_size=1, seq_len=128,
                d_model=x['config']['d_model'],
                n_heads=x['config']['n_heads'],
                n_layers=x['config']['n_layers'],
                vocab_size=vocab_size
            )['total_gb'])
        
        if candidates:
            return candidates[0]['config']
        else:
            # Retornar configuración por defecto
            return ConfigManager.create_config_from_preset('medium')


class AdvancedVisualization:
    """
    Utilidades avanzadas de visualización.
    """
    
    @staticmethod
    def plot_model_comparison(comparison_results: dict, save_path: Optional[str] = None):
        """
        Visualiza comparación de modelos.
        
        :param comparison_results: Resultados de comparación
        :param save_path: Ruta para guardar
        """
        try:
            import matplotlib.pyplot as plt
        except ImportError:
            print("⚠️ matplotlib no está instalado")
            return
        
        fig, axes = plt.subplots(1, 3, figsize=(18, 5))
        
        configs = list(comparison_results.keys())
        params = [comparison_results[c]['results'].get('params_millions', 0) for c in configs]
        memory = [comparison_results[c]['results'].get('memory_mb', 0) / 1024 for c in configs]
        speed = [comparison_results[c]['results'].get('tokens_per_second', 0) for c in configs]
        
        # Parámetros vs Memoria
        axes[0].scatter(params, memory, s=100, alpha=0.6)
        axes[0].set_xlabel('Parámetros (Millones)')
        axes[0].set_ylabel('Memoria (GB)')
        axes[0].set_title('Parámetros vs Memoria')
        axes[0].grid(True)
        
        # Parámetros vs Velocidad
        axes[1].scatter(params, speed, s=100, alpha=0.6)
        axes[1].set_xlabel('Parámetros (Millones)')
        axes[1].set_ylabel('Tokens/segundo')
        axes[1].set_title('Parámetros vs Velocidad')
        axes[1].grid(True)
        
        # Memoria vs Velocidad
        axes[2].scatter(memory, speed, s=100, alpha=0.6)
        axes[2].set_xlabel('Memoria (GB)')
        axes[2].set_ylabel('Tokens/segundo')
        axes[2].set_title('Memoria vs Velocidad')
        axes[2].grid(True)
        
        plt.tight_layout()
        
        if save_path:
            plt.savefig(save_path, dpi=300, bbox_inches='tight')
            print(f"✅ Comparación guardada en: {save_path}")
        else:
            plt.show()
    
    @staticmethod
    def create_architecture_diagram(model: CausalTransformer, save_path: Optional[str] = None):
        """
        Crea diagrama visual de la arquitectura.
        
        :param model: Modelo
        :param save_path: Ruta para guardar
        """
        try:
            import matplotlib.pyplot as plt
            import matplotlib.patches as mpatches
        except ImportError:
            print("⚠️ matplotlib no está instalado")
            return
        
        fig, ax = plt.subplots(figsize=(14, 10))
        
        # Dibujar arquitectura
        y_pos = 0.9
        box_height = 0.08
        
        # Input
        rect = mpatches.FancyBboxPatch(
            (0.1, y_pos - box_height/2), 0.3, box_height,
            boxstyle="round,pad=0.01",
            edgecolor='black',
            facecolor='lightblue'
        )
        ax.add_patch(rect)
        ax.text(0.25, y_pos, 'Token IDs', ha='center', va='center', fontsize=10, fontweight='bold')
        y_pos -= 0.15
        
        # Embeddings
        rect = mpatches.FancyBboxPatch(
            (0.1, y_pos - box_height/2), 0.3, box_height,
            boxstyle="round,pad=0.01",
            edgecolor='black',
            facecolor='lightgreen'
        )
        ax.add_patch(rect)
        ax.text(0.25, y_pos, 'Embeddings + PE', ha='center', va='center', fontsize=10)
        y_pos -= 0.15
        
        # Bloques Transformer
        for i in range(len(model.blocks)):
            rect = mpatches.FancyBboxPatch(
                (0.1, y_pos - box_height/2), 0.3, box_height,
                boxstyle="round,pad=0.01",
                edgecolor='black',
                facecolor='lightyellow'
            )
            ax.add_patch(rect)
            ax.text(0.25, y_pos, f'Block {i+1}', ha='center', va='center', fontsize=9)
            y_pos -= 0.12
        
        # Output
        rect = mpatches.FancyBboxPatch(
            (0.1, y_pos - box_height/2), 0.3, box_height,
            boxstyle="round,pad=0.01",
            edgecolor='black',
            facecolor='lightcoral'
        )
        ax.add_patch(rect)
        ax.text(0.25, y_pos, 'Logits', ha='center', va='center', fontsize=10, fontweight='bold')
        
        ax.set_xlim(0, 0.5)
        ax.set_ylim(0, 1)
        ax.axis('off')
        ax.set_title('Arquitectura del Modelo Transformer', fontsize=14, fontweight='bold')
        
        plt.tight_layout()
        
        if save_path:
            plt.savefig(save_path, dpi=300, bbox_inches='tight')
            print(f"✅ Diagrama guardado en: {save_path}")
        else:
            plt.show()


class HyperparameterOptimizer:
    """
    Utilidad para optimización de hiperparámetros.
    """
    
    @staticmethod
    def grid_search(
        param_grid: dict,
        train_fn,
        eval_fn,
        maximize_metric: bool = True
    ) -> dict:
        """
        Realiza búsqueda de grid sobre hiperparámetros.
        
        :param param_grid: Diccionario con rangos de parámetros
        :param train_fn: Función de entrenamiento
        :param eval_fn: Función de evaluación
        :param maximize_metric: Si True, maximiza métrica
        :return: Mejor configuración
        """
        from itertools import product
        
        # Generar todas las combinaciones
        param_names = list(param_grid.keys())
        param_values = list(param_grid.values())
        combinations = list(product(*param_values))
        
        best_score = float('-inf') if maximize_metric else float('inf')
        best_config = None
        
        results = []
        
        for combo in combinations:
            config = dict(zip(param_names, combo))
            
            # Entrenar y evaluar
            try:
                model = train_fn(config)
                score = eval_fn(model)
                
                results.append({
                    'config': config,
                    'score': score
                })
                
                if (maximize_metric and score > best_score) or \
                   (not maximize_metric and score < best_score):
                    best_score = score
                    best_config = config
                    
            except Exception as e:
                print(f"⚠️ Error con configuración {config}: {e}")
                continue
        
        return {
            'best_config': best_config,
            'best_score': best_score,
            'all_results': results
        }
    
    @staticmethod
    def random_search(
        param_distributions: dict,
        n_iter: int = 10,
        train_fn=None,
        eval_fn=None
    ) -> dict:
        """
        Realiza búsqueda aleatoria de hiperparámetros.
        
        :param param_distributions: Distribuciones de parámetros
        :param n_iter: Número de iteraciones
        :param train_fn: Función de entrenamiento
        :param eval_fn: Función de evaluación
        :return: Mejores configuraciones
        """
        import random
        
        results = []
        
        for i in range(n_iter):
            config = {}
            for param_name, dist in param_distributions.items():
                if isinstance(dist, list):
                    config[param_name] = random.choice(dist)
                elif isinstance(dist, tuple) and len(dist) == 2:
                    # Rango (min, max)
                    if isinstance(dist[0], int):
                        config[param_name] = random.randint(dist[0], dist[1])
                    else:
                        config[param_name] = random.uniform(dist[0], dist[1])
            
            if train_fn and eval_fn:
                try:
                    model = train_fn(config)
                    score = eval_fn(model)
                    results.append({
                        'config': config,
                        'score': score
                    })
                except Exception as e:
                    print(f"⚠️ Error con configuración {config}: {e}")
            else:
                results.append({'config': config})
        
        # Ordenar por score
        if results and 'score' in results[0]:
            results.sort(key=lambda x: x['score'], reverse=True)
        
        return {
            'best_config': results[0]['config'] if results else None,
            'all_results': results[:10]  # Top 10
        }


class ModelSaver:
    """
    Utilidad avanzada para guardar y cargar modelos.
    """
    
    @staticmethod
    def save_model_with_metadata(
        model: CausalTransformer,
        filepath: str,
        metadata: dict,
        include_optimizer: bool = False,
        optimizer=None
    ):
        """
        Guarda modelo con metadatos completos.
        
        :param model: Modelo
        :param filepath: Ruta donde guardar
        :param metadata: Metadatos adicionales
        :param include_optimizer: Si True, incluye optimizador
        :param optimizer: Optimizador (opcional)
        """
        checkpoint = {
            'model_state_dict': model.state_dict(),
            'model_config': {
                'vocab_size': model.vocab_size,
                'd_model': model.d_model,
                'n_heads': model.blocks[0].attention.n_heads,
                'n_layers': len(model.blocks),
                'd_ff': model.blocks[0].ffn.linear1.out_features,
                'max_seq_len': getattr(model.pos_encoding, 'max_seq_len', None) or 512
            },
            'metadata': metadata,
            'version': __version__
        }
        
        if include_optimizer and optimizer:
            checkpoint['optimizer_state_dict'] = optimizer.state_dict()
        
        torch.save(checkpoint, filepath)
        print(f"✅ Modelo guardado con metadatos en: {filepath}")
    
    @staticmethod
    def load_model_with_metadata(filepath: str, device: str = 'cpu') -> Tuple[CausalTransformer, dict]:
        """
        Carga modelo con metadatos.
        
        :param filepath: Ruta del archivo
        :param device: Device
        :return: Tuple de (modelo, metadatos)
        """
        checkpoint = torch.load(filepath, map_location=device)
        
        config = checkpoint['model_config']
        model = CausalTransformer(**config)
        model.load_state_dict(checkpoint['model_state_dict'])
        model = model.to(device)
        
        metadata = checkpoint.get('metadata', {})
        version = checkpoint.get('version', 'unknown')
        
        print(f"✅ Modelo cargado desde: {filepath}")
        print(f"   Versión: {version}")
        print(f"   Metadatos: {list(metadata.keys())}")
        
        return model, metadata


