class AdvancedQuantization:
    """
    Utilidades avanzadas de cuantización dinámica y estática.
    """
    
    @staticmethod
    def quantize_model_dynamic(
        model: CausalTransformer,
        dtype: torch.dtype = torch.qint8
    ) -> nn.Module:
        """
        Cuantiza modelo dinámicamente.
        
        :param model: Modelo a cuantizar
        :param dtype: Tipo de cuantización
        :return: Modelo cuantizado
        """
        try:
            quantized_model = torch.quantization.quantize_dynamic(
                model,
                {nn.Linear},
                dtype=dtype
            )
            print("✅ Modelo cuantizado dinámicamente")
            return quantized_model
        except Exception as e:
            print(f"⚠️ Error en cuantización: {e}")
            return model
    
    @staticmethod
    def prepare_model_for_quantization(
        model: CausalTransformer,
        backend: str = 'fbgemm'
    ) -> nn.Module:
        """
        Prepara modelo para cuantización estática.
        
        :param model: Modelo
        :param backend: Backend de cuantización
        :return: Modelo preparado
        """
        try:
            model.eval()
            model.qconfig = torch.quantization.get_default_qconfig(backend)
            prepared_model = torch.quantization.prepare(model, inplace=False)
            print(f"✅ Modelo preparado para cuantización estática (backend: {backend})")
            return prepared_model
        except Exception as e:
            print(f"⚠️ Error preparando modelo: {e}")
            return model
    
    @staticmethod
    def calculate_quantization_savings(
        model: CausalTransformer,
        quantized_model: nn.Module
    ) -> dict:
        """
        Calcula ahorro de memoria por cuantización.
        
        :param model: Modelo original
        :param quantized_model: Modelo cuantizado
        :return: Estadísticas de ahorro
        """
        original_params = count_parameters(model)
        
        # Estimar tamaño (simplificado)
        original_size_mb = original_params['total'] * 4 / (1024 ** 2)  # FP32
        quantized_size_mb = original_params['total'] * 1 / (1024 ** 2)  # INT8
        
        savings = original_size_mb - quantized_size_mb
        savings_percent = (savings / original_size_mb) * 100
        
        return {
            'original_size_mb': original_size_mb,
            'quantized_size_mb': quantized_size_mb,
            'savings_mb': savings,
            'savings_percent': savings_percent,
            'compression_ratio': original_size_mb / quantized_size_mb
        }


class AdvancedPruning:
    """
    Utilidades avanzadas de pruning estructural y no estructural.
    """
    
    @staticmethod
    def magnitude_pruning(
        model: CausalTransformer,
        pruning_ratio: float = 0.2
    ) -> nn.Module:
        """
        Pruning basado en magnitud de pesos.
        
        :param model: Modelo
        :param pruning_ratio: Ratio de pruning (0.0-1.0)
        :return: Modelo podado
        """
        pruned_model = model
        
        for name, module in pruned_model.named_modules():
            if isinstance(module, nn.Linear):
                # Calcular threshold
                weights = module.weight.data.abs()
                threshold = torch.quantile(weights, pruning_ratio)
                
                # Crear máscara
                mask = weights > threshold
                module.weight.data *= mask.float()
                
                # Registrar
                pruned_count = (~mask).sum().item()
                total_count = mask.numel()
                print(f"  Layer {name}: Pruned {pruned_count}/{total_count} ({pruned_count/total_count*100:.1f}%)")
        
        return pruned_model
    
    @staticmethod
    def structured_pruning(
        model: CausalTransformer,
        pruning_ratio: float = 0.2
    ) -> nn.Module:
        """
        Pruning estructural (elimina canales/filas completas).
        
        :param model: Modelo
        :param pruning_ratio: Ratio de pruning
        :return: Modelo podado
        """
        pruned_model = model
        
        for name, module in pruned_model.named_modules():
            if isinstance(module, nn.Linear):
                # Calcular importancia por fila
                row_importance = module.weight.data.abs().mean(dim=1)
                
                # Seleccionar filas a mantener
                num_to_keep = int(row_importance.numel() * (1 - pruning_ratio))
                _, indices = torch.topk(row_importance, num_to_keep)
                
                # Crear nuevo módulo con menos filas
                new_weight = module.weight.data[indices, :]
                new_module = nn.Linear(module.in_features, num_to_keep, bias=module.bias is not None)
                new_module.weight.data = new_weight
                if module.bias is not None:
                    new_module.bias.data = module.bias.data[indices]
                
                # Reemplazar (simplificado - en producción requiere más cuidado)
                print(f"  Layer {name}: Structured pruning {num_to_keep}/{row_importance.numel()} rows")
        
        return pruned_model
    
    @staticmethod
    def calculate_pruning_impact(
        model: CausalTransformer,
        pruned_model: nn.Module,
        test_input: torch.Tensor
    ) -> dict:
        """
        Calcula impacto del pruning en precisión y tamaño.
        
        :param model: Modelo original
        :param pruned_model: Modelo podado
        :param test_input: Input de prueba
        :return: Métricas de impacto
        """
        model.eval()
        pruned_model.eval()
        
        with torch.no_grad():
            output_original = model(test_input)
            output_pruned = pruned_model(test_input)
        
        # Calcular diferencia
        mse = F.mse_loss(output_original, output_pruned)
        cosine_sim = F.cosine_similarity(
            output_original.flatten(),
            output_pruned.flatten(),
            dim=0
        )
        
        # Calcular tamaño
        params_original = count_parameters(model)
        params_pruned = count_parameters(pruned_model)
        
        return {
            'mse': mse.item(),
            'cosine_similarity': cosine_sim.item(),
            'original_params': params_original['total'],
            'pruned_params': params_pruned['total'],
            'params_reduction': 1 - (params_pruned['total'] / params_original['total']),
            'size_reduction_mb': (params_original['total'] - params_pruned['total']) * 4 / (1024 ** 2)
        }


class ModelInterpreter:
    """
    Utilidades para interpretabilidad y explicabilidad de modelos.
    """
    
    @staticmethod
    def compute_gradient_importance(
        model: CausalTransformer,
        input_tensor: torch.Tensor,
        target_token: Optional[int] = None
    ) -> torch.Tensor:
        """
        Calcula importancia de tokens usando gradientes.
        
        :param model: Modelo
        :param input_tensor: Tensor de entrada
        :param target_token: Token objetivo (opcional)
        :return: Importancia por token
        """
        model.eval()
        input_tensor = input_tensor.clone().detach().requires_grad_(True)
        
        output = model(input_tensor)
        
        if target_token is None:
            # Usar el último token predicho
            target_token = torch.argmax(output[0, -1, :]).item()
        
        # Calcular gradiente
        target_score = output[0, -1, target_token]
        target_score.backward()
        
        # Importancia = |gradiente|
        importance = input_tensor.grad.abs().squeeze()
        
        return importance
    
    @staticmethod
    def compute_attention_rollout(
        attention_weights_list: List[torch.Tensor],
        head_fusion: str = 'mean'
    ) -> torch.Tensor:
        """
        Computa attention rollout para visualizar flujo de atención.
        
        :param attention_weights_list: Lista de pesos de atención por capa
        :param head_fusion: Método de fusión ('mean', 'max', 'min')
        :return: Matriz de attention rollout
        """
        if not attention_weights_list:
            return torch.zeros(1, 1)
        
        # Fusionar heads
        if head_fusion == 'mean':
            fused_attention = [attn.mean(dim=1) for attn in attention_weights_list]
        elif head_fusion == 'max':
            fused_attention = [attn.max(dim=1)[0] for attn in attention_weights_list]
        else:
            fused_attention = [attn.min(dim=1)[0] for attn in attention_weights_list]
        
        # Rollout: multiplicar atención de todas las capas
        rollout = fused_attention[0]
        for attn in fused_attention[1:]:
            rollout = torch.matmul(rollout, attn)
        
        return rollout
    
    @staticmethod
    def identify_important_tokens(
        model: CausalTransformer,
        input_tensor: torch.Tensor,
        top_k: int = 5
    ) -> dict:
        """
        Identifica tokens más importantes para la predicción.
        
        :param model: Modelo
        :param input_tensor: Tensor de entrada
        :param top_k: Número de tokens top
        :return: Diccionario con tokens importantes
        """
        importance = ModelInterpreter.compute_gradient_importance(model, input_tensor)
        
        # Obtener top k tokens
        top_importances, top_indices = torch.topk(importance, min(top_k, importance.numel()))
        
        return {
            'top_tokens': top_indices.tolist(),
            'importances': top_importances.tolist(),
            'importance_scores': importance.tolist()
        }


class TrainingUtilities:
    """
    Utilidades avanzadas para entrenamiento.
    """
    
    @staticmethod
    def create_learning_rate_scheduler(
        optimizer,
        scheduler_type: str = 'cosine',
        num_warmup_steps: int = 1000,
        num_training_steps: int = 10000
    ):
        """
        Crea scheduler de learning rate.
        
        :param optimizer: Optimizador
        :param scheduler_type: Tipo ('cosine', 'linear', 'polynomial')
        :param num_warmup_steps: Pasos de warmup
        :param num_training_steps: Total de pasos
        :return: Scheduler
        """
        from transformers import get_scheduler
        
        if scheduler_type == 'cosine':
            return get_scheduler(
                'cosine',
                optimizer=optimizer,
                num_warmup_steps=num_warmup_steps,
                num_training_steps=num_training_steps
            )
        elif scheduler_type == 'linear':
            return get_scheduler(
                'linear',
                optimizer=optimizer,
                num_warmup_steps=num_warmup_steps,
                num_training_steps=num_training_steps
            )
        else:
            return get_scheduler(
                'polynomial',
                optimizer=optimizer,
                num_warmup_steps=num_warmup_steps,
                num_training_steps=num_training_steps,
                power=0.5
            )
    
    @staticmethod
    def create_early_stopping_callback(
        patience: int = 3,
        min_delta: float = 0.001,
        monitor: str = 'loss'
    ):
        """
        Crea callback de early stopping.
        
        :param patience: Paciencia (número de epochs sin mejora)
        :param min_delta: Delta mínimo para considerar mejora
        :param monitor: Métrica a monitorear
        :return: Callback
        """
        class EarlyStopping:
            def __init__(self, patience, min_delta, monitor):
                self.patience = patience
                self.min_delta = min_delta
                self.monitor = monitor
                self.best_score = float('inf')
                self.counter = 0
                self.should_stop = False
            
            def __call__(self, score):
                if score < self.best_score - self.min_delta:
                    self.best_score = score
                    self.counter = 0
                else:
                    self.counter += 1
                    if self.counter >= self.patience:
                        self.should_stop = True
                
                return self.should_stop
        
        return EarlyStopping(patience, min_delta, monitor)
    
    @staticmethod
    def create_gradient_clipping_callback(
        max_norm: float = 1.0,
        norm_type: float = 2.0
    ):
        """
        Crea callback para gradient clipping.
        
        :param max_norm: Norma máxima
        :param norm_type: Tipo de norma
        :return: Función de clipping
        """
        def clip_gradients(model):
            torch.nn.utils.clip_grad_norm_(model.parameters(), max_norm, norm_type)
        
        return clip_gradients


class ModelConverter:
    """
    Utilidades avanzadas de conversión de modelos.
    """
    
    @staticmethod
    def convert_to_onnx(
        model: CausalTransformer,
        output_path: str,
        input_shape: tuple = (1, 128),
        opset_version: int = 13
    ):
        """
        Convierte modelo a ONNX.
        
        :param model: Modelo
        :param output_path: Ruta de salida
        :param input_shape: Forma del input
        :param opset_version: Versión de opset
        """
        try:
            import onnx
            model.eval()
            
            # Crear dummy input
            dummy_input = torch.randint(0, model.vocab_size, input_shape)
            
            # Exportar
            torch.onnx.export(
                model,
                dummy_input,
                output_path,
                input_names=['input_ids'],
                output_names=['logits'],
                dynamic_axes={
                    'input_ids': {0: 'batch_size', 1: 'sequence_length'},
                    'logits': {0: 'batch_size', 1: 'sequence_length'}
                },
                opset_version=opset_version,
                do_constant_folding=True
            )
            
            print(f"✅ Modelo exportado a ONNX: {output_path}")
            
            # Verificar
            onnx_model = onnx.load(output_path)
            onnx.checker.check_model(onnx_model)
            print("✅ ONNX model verificado correctamente")
            
        except ImportError:
            print("⚠️ ONNX no está instalado. Instala con: pip install onnx")
        except Exception as e:
            print(f"⚠️ Error exportando a ONNX: {e}")
    
    @staticmethod
    def convert_to_torchscript(
        model: CausalTransformer,
        output_path: str,
        input_shape: tuple = (1, 128),
        method: str = 'trace'
    ):
        """
        Convierte modelo a TorchScript.
        
        :param model: Modelo
        :param output_path: Ruta de salida
        :param input_shape: Forma del input
        :param method: Método ('trace' o 'script')
        """
        try:
            model.eval()
            dummy_input = torch.randint(0, model.vocab_size, input_shape)
            
            if method == 'trace':
                traced_model = torch.jit.trace(model, dummy_input)
                traced_model.save(output_path)
            else:
                scripted_model = torch.jit.script(model)
                scripted_model.save(output_path)
            
            print(f"✅ Modelo exportado a TorchScript ({method}): {output_path}")
            
        except Exception as e:
            print(f"⚠️ Error exportando a TorchScript: {e}")


