class ModelOptimizerPro:
    """
    Optimizador profesional avanzado con múltiples técnicas.
    """
    
    @staticmethod
    def optimize_model_complete(
        model: CausalTransformer,
        optimization_level: str = 'medium',
        target_device: str = 'cuda'
    ) -> nn.Module:
        """
        Optimiza modelo con pipeline completo de optimizaciones.
        
        :param model: Modelo a optimizar
        :param optimization_level: Nivel ('light', 'medium', 'aggressive')
        :param target_device: Device objetivo
        :return: Modelo optimizado
        """
        optimized_model = model
        
        if optimization_level == 'light':
            # Solo optimizaciones básicas
            optimized_model.eval()
            optimized_model = torch.jit.script(optimized_model) if hasattr(torch.jit, 'script') else optimized_model
            
        elif optimization_level == 'medium':
            # Optimizaciones moderadas
            optimized_model.eval()
            # Fusionar operaciones
            optimized_model = torch.jit.optimize_for_inference(optimized_model) if hasattr(torch.jit, 'optimize_for_inference') else optimized_model
            
        elif optimization_level == 'aggressive':
            # Todas las optimizaciones
            optimized_model.eval()
            # Cuantización dinámica
            quantizer = AdvancedQuantization()
            optimized_model = quantizer.quantize_model_dynamic(optimized_model)
            # Pruning
            pruner = AdvancedPruning()
            optimized_model = pruner.magnitude_pruning(optimized_model, pruning_ratio=0.1)
        
        print(f"✅ Modelo optimizado con nivel: {optimization_level}")
        return optimized_model
    
    @staticmethod
    def benchmark_optimization_impact(
        model: CausalTransformer,
        optimized_model: nn.Module,
        test_input: torch.Tensor,
        num_runs: int = 100
    ) -> dict:
        """
        Compara performance del modelo original vs optimizado.
        
        :param model: Modelo original
        :param optimized_model: Modelo optimizado
        :param test_input: Input de prueba
        :param num_runs: Número de ejecuciones
        :return: Métricas de comparación
        """
        import time
        
        model.eval()
        optimized_model.eval()
        
        # Benchmark original
        times_original = []
        with torch.no_grad():
            for _ in range(num_runs):
                start = time.time()
                _ = model(test_input)
                times_original.append(time.time() - start)
        
        # Benchmark optimizado
        times_optimized = []
        with torch.no_grad():
            for _ in range(num_runs):
                start = time.time()
                _ = optimized_model(test_input)
                times_optimized.append(time.time() - start)
        
        avg_original = sum(times_original) / len(times_original)
        avg_optimized = sum(times_optimized) / len(times_optimized)
        speedup = avg_original / avg_optimized if avg_optimized > 0 else 0
        
        return {
            'original_avg_ms': avg_original * 1000,
            'optimized_avg_ms': avg_optimized * 1000,
            'speedup': speedup,
            'speedup_percent': (speedup - 1) * 100 if speedup > 0 else 0,
            'original_p95_ms': sorted(times_original)[int(len(times_original) * 0.95)] * 1000,
            'optimized_p95_ms': sorted(times_optimized)[int(len(times_optimized) * 0.95)] * 1000
        }


