class AdvancedBenchmarking:
    """
    Utilidades avanzadas de benchmarking y profiling.
    """
    
    @staticmethod
    def comprehensive_benchmark(
        model: CausalTransformer,
        test_input: torch.Tensor,
        num_warmup: int = 10,
        num_runs: int = 100,
        batch_sizes: List[int] = [1, 4, 8, 16]
    ) -> dict:
        """
        Benchmark completo con múltiples configuraciones.
        
        :param model: Modelo
        :param test_input: Input de prueba
        :param num_warmup: Pasos de warmup
        :param num_runs: Número de ejecuciones
        :param batch_sizes: Tamaños de batch a probar
        :return: Resultados de benchmark
        """
        import time
        
        results = {}
        model.eval()
        
        for batch_size in batch_sizes:
            # Crear input con batch_size
            batch_input = test_input.repeat(batch_size, 1)
            
            # Warmup
            with torch.no_grad():
                for _ in range(num_warmup):
                    _ = model(batch_input)
            
            # Benchmark
            times = []
            with torch.no_grad():
                for _ in range(num_runs):
                    start = time.time()
                    _ = model(batch_input)
                    torch.cuda.synchronize() if torch.cuda.is_available() else None
                    times.append(time.time() - start)
            
            avg_time = sum(times) / len(times)
            p50_time = sorted(times)[int(len(times) * 0.50)]
            p95_time = sorted(times)[int(len(times) * 0.95)]
            p99_time = sorted(times)[int(len(times) * 0.99)]
            
            tokens_per_sec = (batch_size * test_input.shape[1]) / avg_time if avg_time > 0 else 0
            
            results[batch_size] = {
                'avg_time_ms': avg_time * 1000,
                'p50_ms': p50_time * 1000,
                'p95_ms': p95_time * 1000,
                'p99_ms': p99_time * 1000,
                'tokens_per_second': tokens_per_sec,
                'throughput': batch_size / avg_time if avg_time > 0 else 0
            }
        
        return results
    
    @staticmethod
    def memory_profiling(
        model: CausalTransformer,
        test_input: torch.Tensor,
        track_peak: bool = True
    ) -> dict:
        """
        Profiling detallado de memoria.
        
        :param model: Modelo
        :param test_input: Input de prueba
        :param track_peak: Si True, trackea memoria pico
        :return: Estadísticas de memoria
        """
        if torch.cuda.is_available():
            torch.cuda.reset_peak_memory_stats()
            torch.cuda.empty_cache()
            
            model = model.cuda()
            test_input = test_input.cuda()
            
            model.eval()
            with torch.no_grad():
                _ = model(test_input)
            
            peak_allocated = torch.cuda.max_memory_allocated() / (1024 ** 2)  # MB
            peak_reserved = torch.cuda.max_memory_reserved() / (1024 ** 2)  # MB
            
            return {
                'peak_allocated_mb': peak_allocated,
                'peak_reserved_mb': peak_reserved,
                'device': 'cuda'
            }
        else:
            try:
                import psutil
                process = psutil.Process()
                
                mem_before = process.memory_info().rss / (1024 ** 2)  # MB
                
                model.eval()
                with torch.no_grad():
                    _ = model(test_input)
                
                mem_after = process.memory_info().rss / (1024 ** 2)  # MB
                
                return {
                    'memory_before_mb': mem_before,
                    'memory_after_mb': mem_after,
                    'memory_used_mb': mem_after - mem_before,
                    'device': 'cpu'
                }
            except ImportError:
                return {'error': 'psutil no disponible para CPU profiling'}


class ModelComparisonPro:
    """
    Comparación avanzada de modelos con múltiples métricas.
    """
    
    @staticmethod
    def compare_models_comprehensive(
        models: List[CausalTransformer],
        model_names: List[str],
        test_input: torch.Tensor,
        test_loader=None
    ) -> dict:
        """
        Comparación comprehensiva de múltiples modelos.
        
        :param models: Lista de modelos
        :param model_names: Nombres de modelos
        :param test_input: Input de prueba
        :param test_loader: DataLoader opcional para evaluación
        :return: Resultados de comparación
        """
        results = {}
        
        for model, name in zip(models, model_names):
            # Parámetros
            params = count_parameters(model)
            
            # Memoria estimada
            memory = estimate_memory_usage(
                test_input.shape[0],
                test_input.shape[1],
                model.d_model,
                model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
                len(model.blocks),
                model.vocab_size
            )
            
            # Benchmark de velocidad
            benchmark = AdvancedBenchmarking.comprehensive_benchmark(
                model, test_input, num_runs=50
            )
            
            # Profiling de memoria
            memory_profile = AdvancedBenchmarking.memory_profiling(model, test_input)
            
            # Evaluación (si hay test_loader)
            evaluation = {}
            if test_loader:
                try:
                    evaluator = ModelEvaluator()
                    perplexity, accuracy = evaluator.evaluate(model, test_loader)
                    evaluation = {
                        'perplexity': perplexity,
                        'accuracy': accuracy
                    }
                except Exception as e:
                    evaluation = {'error': str(e)}
            
            results[name] = {
                'parameters': params,
                'memory_estimate': memory,
                'memory_profile': memory_profile,
                'benchmark': benchmark,
                'evaluation': evaluation,
                'config': {
                    'vocab_size': model.vocab_size,
                    'd_model': model.d_model,
                    'n_layers': len(model.blocks),
                    'n_heads': model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8
                }
            }
        
        return results
    
    @staticmethod
    def print_comparison_report(results: dict):
        """
        Imprime reporte de comparación formateado.
        
        :param results: Resultados de compare_models_comprehensive
        """
        print("\n" + "="*100)
        print("REPORTE DE COMPARACIÓN DE MODELOS")
        print("="*100)
        
        print(f"\n{'Modelo':<20} {'Parámetros (M)':<18} {'Memoria (GB)':<15} {'Speed (tok/s)':<15} {'Perplexity':<12}")
        print("-"*100)
        
        for name, data in results.items():
            params_m = data['parameters']['total_millions']
            memory_gb = data['memory_estimate']['total_gb']
            
            # Obtener velocidad promedio
            benchmark = data.get('benchmark', {})
            if benchmark:
                speed = benchmark.get(1, {}).get('tokens_per_second', 0)
            else:
                speed = 0
            
            # Obtener perplexity
            eval_data = data.get('evaluation', {})
            perplexity = eval_data.get('perplexity', 0) if 'error' not in eval_data else 'N/A'
            
            print(f"{name:<20} "
                  f"{params_m:>15.2f}M  "
                  f"{memory_gb:>12.3f}  "
                  f"{speed:>12.1f}  "
                  f"{perplexity:>10.2f}" if isinstance(perplexity, (int, float)) else f"{str(perplexity):>10}")


