class TroubleshootingGuide:
    """
    Guía de troubleshooting para problemas comunes.
    """
    
    @staticmethod
    def diagnose_training_issues(
        model: CausalTransformer,
        training_history: dict
    ) -> dict:
        """
        Diagnostica problemas comunes en entrenamiento.
        
        :param model: Modelo
        :param training_history: Historial de entrenamiento
        :return: Diagnóstico y recomendaciones
        """
        issues = []
        recommendations = []
        
        # Verificar loss
        if 'train_loss' in training_history:
            losses = training_history['train_loss']
            if losses[-1] > losses[0] * 1.5:
                issues.append('Loss aumentando durante entrenamiento')
                recommendations.append('Reducir learning rate')
                recommendations.append('Verificar datos de entrenamiento')
            
            if losses[-1] == losses[0]:
                issues.append('Loss no está cambiando')
                recommendations.append('Verificar que gradients se están calculando')
                recommendations.append('Aumentar learning rate')
                recommendations.append('Verificar que modelo está en modo train')
        
        # Verificar gradientes
        if 'grad_norms' in training_history:
            grad_norms = training_history['grad_norms']
            if max(grad_norms) > 10.0:
                issues.append('Gradientes explotando')
                recommendations.append('Aplicar gradient clipping (norm=1.0)')
                recommendations.append('Reducir learning rate')
            
            if max(grad_norms) < 1e-6:
                issues.append('Gradientes muy pequeños (vanishing)')
                recommendations.append('Usar inicialización mejor (Xavier/He)')
                recommendations.append('Reducir profundidad o usar skip connections')
                recommendations.append('Aumentar learning rate')
        
        # Verificar overfitting
        if 'train_loss' in training_history and 'val_loss' in training_history:
            train_loss = training_history['train_loss'][-1]
            val_loss = training_history['val_loss'][-1]
            if val_loss > train_loss * 1.5:
                issues.append('Overfitting detectado')
                recommendations.append('Aumentar dropout')
                recommendations.append('Aumentar weight decay')
                recommendations.append('Aumentar data augmentation')
                recommendations.append('Reducir capacidad del modelo')
        
        return {
            'issues': issues,
            'recommendations': recommendations,
            'status': 'healthy' if not issues else 'needs_attention'
        }
    
    @staticmethod
    def diagnose_memory_issues(
        model: CausalTransformer,
        batch_size: int,
        seq_len: int
    ) -> dict:
        """
        Diagnostica problemas de memoria.
        
        :param model: Modelo
        :param batch_size: Tamaño de batch
        :param seq_len: Longitud de secuencia
        :return: Diagnóstico y recomendaciones
        """
        memory_estimate = MemoryOptimizer.estimate_training_memory(
            model, batch_size, seq_len
        )
        
        recommendations = []
        
        if memory_estimate['total_gb'] > 20:
            recommendations.append('Usar gradient checkpointing')
            recommendations.append('Reducir batch size')
            recommendations.append('Usar mixed precision (FP16)')
        
        if memory_estimate['total_gb'] > 40:
            recommendations.append('Usar model parallelism')
            recommendations.append('Considerar distribuir entrenamiento en múltiples GPUs')
        
        return {
            'estimated_memory_gb': memory_estimate['total_gb'],
            'recommendations': recommendations,
            'optimization_options': {
                'with_mixed_precision': MemoryOptimizer.estimate_training_memory(
                    model, batch_size, seq_len, mixed_precision=True
                )['total_gb'],
                'with_checkpointing': MemoryOptimizer.estimate_training_memory(
                    model, batch_size, seq_len, gradient_checkpointing=True
                )['total_gb'],
                'with_both': MemoryOptimizer.estimate_training_memory(
                    model, batch_size, seq_len,
                    mixed_precision=True,
                    gradient_checkpointing=True
                )['total_gb']
            }
        }


