class KVCacheOptimizer:
    """
    Optimizador de KV Cache para acelerar generación autoregresiva.
    """
    
    @staticmethod
    def implement_kv_cache(
        model: CausalTransformer,
        cache_size: Optional[int] = None
    ) -> dict:
        """
        Implementa KV Cache para generación eficiente.
        
        :param model: Modelo
        :param cache_size: Tamaño del cache (opcional)
        :return: Configuración de KV cache
        """
        cache_config = {
            'enabled': True,
            'cache_size': cache_size or 2048,
            'implementation': 'torch',
            'dtype': 'float16'
        }
        
        print("✅ KV Cache configurado para generación eficiente")
        print(f"   Cache size: {cache_config['cache_size']}")
        
        return cache_config
    
    @staticmethod
    def estimate_cache_memory(
        batch_size: int,
        seq_len: int,
        d_model: int,
        n_heads: int,
        n_layers: int,
        cache_size: int,
        dtype_bytes: int = 2  # float16
    ) -> dict:
        """
        Estima memoria necesaria para KV cache.
        
        :param batch_size: Tamaño del batch
        :param seq_len: Longitud de secuencia
        :param d_model: Dimensión del modelo
        :param n_heads: Número de heads
        :param n_layers: Número de capas
        :param cache_size: Tamaño del cache
        :param dtype_bytes: Bytes por elemento (2 para float16)
        :return: Estimación de memoria
        """
        d_k = d_model // n_heads
        
        # Memoria por capa: K y V cache
        # K: (batch, n_heads, cache_size, d_k)
        # V: (batch, n_heads, cache_size, d_k)
        cache_per_layer = 2 * batch_size * n_heads * cache_size * d_k * dtype_bytes
        
        # Total para todas las capas
        total_cache = n_layers * cache_per_layer
        
        return {
            'cache_per_layer_mb': cache_per_layer / (1024 ** 2),
            'total_cache_mb': total_cache / (1024 ** 2),
            'total_cache_gb': total_cache / (1024 ** 3),
            'cache_size': cache_size
        }


class SparseAttentionOptimizer:
    """
    Optimizador para implementar atención sparse (local, strided, etc.).
    """
    
    @staticmethod
    def create_local_attention_mask(
        seq_len: int,
        window_size: int,
        causal: bool = True
    ) -> torch.Tensor:
        """
        Crea máscara para atención local (ventana).
        
        :param seq_len: Longitud de secuencia
        :param window_size: Tamaño de ventana
        :param causal: Si True, aplica restricción causal
        :return: Máscara de atención
        """
        mask = torch.zeros(seq_len, seq_len)
        
        for i in range(seq_len):
            start = max(0, i - window_size) if causal else 0
            end = min(seq_len, i + 1) if causal else min(seq_len, i + window_size + 1)
            mask[i, start:end] = 1.0
        
        return mask
    
    @staticmethod
    def create_strided_attention_mask(
        seq_len: int,
        stride: int = 2,
        causal: bool = True
    ) -> torch.Tensor:
        """
        Crea máscara para atención strided (cada N tokens).
        
        :param seq_len: Longitud de secuencia
        :param stride: Stride (cada cuántos tokens atender)
        :param causal: Si True, aplica restricción causal
        :return: Máscara de atención
        """
        mask = torch.zeros(seq_len, seq_len)
        
        for i in range(seq_len):
            # Atender a tokens cada 'stride' posiciones
            positions = list(range(0, i + 1, stride)) if causal else list(range(0, seq_len, stride))
            mask[i, positions] = 1.0
        
        return mask
    
    @staticmethod
    def calculate_sparse_attention_savings(
        seq_len: int,
        window_size: Optional[int] = None,
        stride: Optional[int] = None
    ) -> dict:
        """
        Calcula ahorro de memoria con atención sparse.
        
        :param seq_len: Longitud de secuencia
        :param window_size: Tamaño de ventana (para local attention)
        :param stride: Stride (para strided attention)
        :return: Estadísticas de ahorro
        """
        # Memoria atención completa
        full_attention_memory = seq_len * seq_len * 4  # float32 = 4 bytes
        
        if window_size:
            # Local attention
            sparse_attention_memory = seq_len * window_size * 4
            savings = full_attention_memory - sparse_attention_memory
        elif stride:
            # Strided attention
            num_attended = (seq_len // stride) + 1
            sparse_attention_memory = seq_len * num_attended * 4
            savings = full_attention_memory - sparse_attention_memory
        else:
            savings = 0
            sparse_attention_memory = full_attention_memory
        
        savings_percent = (savings / full_attention_memory) * 100 if full_attention_memory > 0 else 0
        
        return {
            'full_attention_mb': full_attention_memory / (1024 ** 2),
            'sparse_attention_mb': sparse_attention_memory / (1024 ** 2),
            'savings_mb': savings / (1024 ** 2),
            'savings_percent': savings_percent,
            'max_seq_len_full': int(8192 * 1024 * 1024 / (seq_len * 4)),
            'max_seq_len_sparse': int(8192 * 1024 * 1024 / (sparse_attention_memory / seq_len))
        }


class ModelProfiler:
    """
    Profiler avanzado para análisis detallado de modelos.
    """
    
    @staticmethod
    def profile_model_layers(
        model: CausalTransformer,
        test_input: torch.Tensor,
        detailed: bool = True
    ) -> dict:
        """
        Profila cada capa del modelo individualmente.
        
        :param model: Modelo
        :param test_input: Input de prueba
        :param detailed: Si True, incluye detalles por capa
        :return: Perfil de cada capa
        """
        import time
        
        model.eval()
        profile = {}
        
        with torch.no_grad():
            # Embeddings
            start = time.time()
            x = model.token_embedding(test_input)
            x = model.pos_encoding(x)
            embedding_time = time.time() - start
            profile['embeddings'] = {
                'time_ms': embedding_time * 1000,
                'output_shape': list(x.shape)
            }
            
            # Cada bloque
            for i, block in enumerate(model.blocks):
                start = time.time()
                
                # Atención
                attn_start = time.time()
                x_norm = block.ln1(x)
                attn_output, _ = block.attention(x_norm)
                x = x + attn_output
                attn_time = time.time() - attn_start
                
                # FFN
                ffn_start = time.time()
                x_norm = block.ln2(x)
                ffn_output = block.ffn(x_norm)
                x = x + ffn_output
                ffn_time = time.time() - ffn_start
                
                block_time = time.time() - start
                
                profile[f'block_{i}'] = {
                    'total_time_ms': block_time * 1000,
                    'attention_time_ms': attn_time * 1000,
                    'ffn_time_ms': ffn_time * 1000,
                    'attention_percent': (attn_time / block_time) * 100 if block_time > 0 else 0,
                    'ffn_percent': (ffn_time / block_time) * 100 if block_time > 0 else 0
                }
            
            # Output
            start = time.time()
            output = model.output_norm(x)
            output_logits = model.output(output)
            output_time = time.time() - start
            profile['output'] = {
                'time_ms': output_time * 1000,
                'output_shape': list(output_logits.shape)
            }
        
        return profile
    
    @staticmethod
    def identify_bottlenecks(profile: dict) -> dict:
        """
        Identifica cuellos de botella en el modelo.
        
        :param profile: Perfil del modelo
        :return: Análisis de bottlenecks
        """
        total_time = sum(layer.get('total_time_ms', layer.get('time_ms', 0)) for layer in profile.values())
        
        bottlenecks = []
        
        for layer_name, layer_data in profile.items():
            layer_time = layer_data.get('total_time_ms', layer_data.get('time_ms', 0))
            layer_percent = (layer_time / total_time) * 100 if total_time > 0 else 0
            
            if layer_percent > 20:  # Más del 20% del tiempo
                bottlenecks.append({
                    'layer': layer_name,
                    'time_ms': layer_time,
                    'percent': layer_percent,
                    'severity': 'high' if layer_percent > 40 else 'medium'
                })
        
        # Ordenar por tiempo
        bottlenecks.sort(key=lambda x: x['time_ms'], reverse=True)
        
        return {
            'total_time_ms': total_time,
            'bottlenecks': bottlenecks,
            'num_bottlenecks': len(bottlenecks),
            'recommendations': [
                f"Optimizar {b['layer']} (consume {b['percent']:.1f}% del tiempo)" 
                for b in bottlenecks[:3]
            ]
        }


class AdvancedDataAugmentation:
    """
    Data augmentation avanzada para transformers.
    """
    
    @staticmethod
    def back_translation_augmentation(
        texts: List[str],
        target_language: str = 'es'
    ) -> List[str]:
        """
        Aumenta datos usando back translation.
        
        :param texts: Lista de textos
        :param target_language: Idioma objetivo
        :return: Textos aumentados
        """
        # Implementación simplificada
        # En producción usar modelos de traducción reales
        augmented = []
        for text in texts:
            augmented.append(text)  # Original
            # Simular traducción
            augmented.append(f"[{target_language}] {text}")  # Traducido
        return augmented
    
    @staticmethod
    def synonym_replacement(
        texts: List[str],
        replacement_ratio: float = 0.1
    ) -> List[str]:
        """
        Reemplaza palabras con sinónimos.
        
        :param texts: Lista de textos
        :param replacement_ratio: Ratio de palabras a reemplazar
        :return: Textos aumentados
        """
        # Implementación simplificada
        # En producción usar diccionario de sinónimos
        augmented = []
        for text in texts:
            augmented.append(text)  # Original
            words = text.split()
            num_replace = max(1, int(len(words) * replacement_ratio))
            # Simular reemplazo
            augmented.append(' '.join(words))  # Por ahora igual
        return augmented
    
    @staticmethod
    def random_insertion(
        texts: List[str],
        insertion_ratio: float = 0.1
    ) -> List[str]:
        """
        Inserta palabras aleatorias en el texto.
        
        :param texts: Lista de textos
        :param insertion_ratio: Ratio de palabras a insertar
        :return: Textos aumentados
        """
        augmented = []
        for text in texts:
            augmented.append(text)  # Original
            words = text.split()
            num_insert = max(1, int(len(words) * insertion_ratio))
            # Simular inserción
            augmented.append(' '.join(words))
        return augmented


class ModelCheckpointManager:
    """
    Gestor avanzado de checkpoints con versionado.
    """
    
    @staticmethod
    def create_checkpoint(
        model: CausalTransformer,
        optimizer=None,
        scheduler=None,
        epoch: int = 0,
        step: int = 0,
        metrics: dict = None,
        checkpoint_dir: str = './checkpoints'
    ) -> str:
        """
        Crea checkpoint completo con versionado.
        
        :param model: Modelo
        :param optimizer: Optimizador (opcional)
        :param scheduler: Scheduler (opcional)
        :param epoch: Epoch actual
        :param step: Paso actual
        :param metrics: Métricas (opcional)
        :param checkpoint_dir: Directorio de checkpoints
        :return: Ruta del checkpoint creado
        """
        import os
        from datetime import datetime
        
        os.makedirs(checkpoint_dir, exist_ok=True)
        
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        checkpoint_name = f'checkpoint_epoch{epoch}_step{step}_{timestamp}.pt'
        checkpoint_path = os.path.join(checkpoint_dir, checkpoint_name)
        
        checkpoint = {
            'epoch': epoch,
            'step': step,
            'model_state_dict': model.state_dict(),
            'model_config': {
                'vocab_size': model.vocab_size,
                'd_model': model.d_model,
                'n_layers': len(model.blocks),
                'n_heads': model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
                'd_ff': model.blocks[0].ffn.linear1.out_features if hasattr(model.blocks[0], 'ffn') else 2048,
                'max_seq_len': getattr(model.pos_encoding, 'max_seq_len', None) or 512
            },
            'metrics': metrics or {},
            'timestamp': timestamp,
            'version': __version__
        }
        
        if optimizer:
            checkpoint['optimizer_state_dict'] = optimizer.state_dict()
        if scheduler:
            checkpoint['scheduler_state_dict'] = scheduler.state_dict()
        
        torch.save(checkpoint, checkpoint_path)
        print(f"✅ Checkpoint creado: {checkpoint_path}")
        
        return checkpoint_path
    
    @staticmethod
    def list_checkpoints(checkpoint_dir: str = './checkpoints') -> List[dict]:
        """
        Lista todos los checkpoints disponibles.
        
        :param checkpoint_dir: Directorio de checkpoints
        :return: Lista de checkpoints con metadatos
        """
        import os
        
        checkpoints = []
        
        if not os.path.exists(checkpoint_dir):
            return checkpoints
        
        for filename in os.listdir(checkpoint_dir):
            if filename.endswith('.pt'):
                filepath = os.path.join(checkpoint_dir, filename)
                try:
                    checkpoint = torch.load(filepath, map_location='cpu')
                    checkpoints.append({
                        'filename': filename,
                        'path': filepath,
                        'epoch': checkpoint.get('epoch', 0),
                        'step': checkpoint.get('step', 0),
                        'metrics': checkpoint.get('metrics', {}),
                        'timestamp': checkpoint.get('timestamp', 'unknown'),
                        'size_mb': os.path.getsize(filepath) / (1024 ** 2)
                    })
                except Exception as e:
                    print(f"⚠️ Error cargando checkpoint {filename}: {e}")
        
        # Ordenar por epoch y step
        checkpoints.sort(key=lambda x: (x['epoch'], x['step']), reverse=True)
        
        return checkpoints
    
    @staticmethod
    def load_latest_checkpoint(
        checkpoint_dir: str = './checkpoints',
        device: str = 'cpu'
    ) -> Tuple[dict, Optional[str]]:
        """
        Carga el checkpoint más reciente.
        
        :param checkpoint_dir: Directorio de checkpoints
        :param device: Device
        :return: Tuple (checkpoint, path)
        """
        checkpoints = ModelCheckpointManager.list_checkpoints(checkpoint_dir)
        
        if not checkpoints:
            return None, None
        
        latest = checkpoints[0]
        checkpoint = torch.load(latest['path'], map_location=device)
        
        print(f"✅ Checkpoint cargado: {latest['filename']}")
        print(f"   Epoch: {latest['epoch']}, Step: {latest['step']}")
        
        return checkpoint, latest['path']


class TrainingMonitorPro:
    """
    Monitor avanzado de entrenamiento con alertas automáticas.
    """
    
    @staticmethod
    def create_monitor(
        alert_thresholds: dict = None,
        log_frequency: int = 100
    ):
        """
        Crea monitor de entrenamiento.
        
        :param alert_thresholds: Umbrales para alertas
        :param log_frequency: Frecuencia de logging
        :return: Monitor
        """
        class Monitor:
            def __init__(self, thresholds, log_freq):
                self.thresholds = thresholds or {
                    'loss_increase': 1.5,
                    'gradient_explosion': 10.0,
                    'gradient_vanishing': 1e-6,
                    'overfitting': 1.5
                }
                self.log_freq = log_freq
                self.history = {
                    'loss': [],
                    'grad_norms': [],
                    'learning_rates': []
                }
                self.alerts = []
            
            def log_step(self, step: int, loss: float, grad_norm: float = None, lr: float = None):
                """Registra paso de entrenamiento."""
                self.history['loss'].append(loss)
                if grad_norm is not None:
                    self.history['grad_norms'].append(grad_norm)
                if lr is not None:
                    self.history['learning_rates'].append(lr)
                
                # Verificar alertas
                if len(self.history['loss']) > 1:
                    if self.history['loss'][-1] > self.history['loss'][-2] * self.thresholds['loss_increase']:
                        self.alerts.append({
                            'step': step,
                            'type': 'loss_increase',
                            'message': f'Loss aumentó significativamente en paso {step}'
                        })
                
                if grad_norm and grad_norm > self.thresholds['gradient_explosion']:
                    self.alerts.append({
                        'step': step,
                        'type': 'gradient_explosion',
                        'message': f'Gradientes explotando en paso {step}: {grad_norm:.2f}'
                    })
                
                if grad_norm and grad_norm < self.thresholds['gradient_vanishing']:
                    self.alerts.append({
                        'step': step,
                        'type': 'gradient_vanishing',
                        'message': f'Gradientes muy pequeños en paso {step}: {grad_norm:.2e}'
                    })
            
            def get_summary(self) -> dict:
                """Obtiene resumen del entrenamiento."""
                if not self.history['loss']:
                    return {}
                
                return {
                    'total_steps': len(self.history['loss']),
                    'current_loss': self.history['loss'][-1],
                    'best_loss': min(self.history['loss']),
                    'avg_grad_norm': sum(self.history['grad_norms']) / len(self.history['grad_norms']) if self.history['grad_norms'] else 0,
                    'num_alerts': len(self.alerts),
                    'alerts': self.alerts[-10:]  # Últimas 10 alertas
                }
        
        return Monitor(alert_thresholds, log_frequency)


class ModelVisualizerPro:
    """
    Visualizador avanzado de modelos con múltiples vistas.
    """
    
    @staticmethod
    def visualize_training_curves(
        training_history: dict,
        save_path: Optional[str] = None
    ):
        """
        Visualiza curvas de entrenamiento.
        
        :param training_history: Historial de entrenamiento
        :param save_path: Ruta para guardar
        """
        try:
            import matplotlib.pyplot as plt
        except ImportError:
            print("⚠️ matplotlib no está instalado")
            return
        
        fig, axes = plt.subplots(2, 2, figsize=(15, 10))
        
        # Loss
        if 'train_loss' in training_history:
            axes[0, 0].plot(training_history['train_loss'], label='Train Loss')
        if 'val_loss' in training_history:
            axes[0, 0].plot(training_history['val_loss'], label='Val Loss')
        axes[0, 0].set_xlabel('Epoch')
        axes[0, 0].set_ylabel('Loss')
        axes[0, 0].set_title('Training and Validation Loss')
        axes[0, 0].legend()
        axes[0, 0].grid(True)
        
        # Perplexity
        if 'train_perplexity' in training_history:
            axes[0, 1].plot(training_history['train_perplexity'], label='Train Perplexity')
        if 'val_perplexity' in training_history:
            axes[0, 1].plot(training_history['val_perplexity'], label='Val Perplexity')
        axes[0, 1].set_xlabel('Epoch')
        axes[0, 1].set_ylabel('Perplexity')
        axes[0, 1].set_title('Perplexity')
        axes[0, 1].legend()
        axes[0, 1].grid(True)
        
        # Learning Rate
        if 'learning_rate' in training_history:
            axes[1, 0].plot(training_history['learning_rate'])
            axes[1, 0].set_xlabel('Step')
            axes[1, 0].set_ylabel('Learning Rate')
            axes[1, 0].set_title('Learning Rate Schedule')
            axes[1, 0].grid(True)
        
        # Gradient Norms
        if 'grad_norms' in training_history:
            axes[1, 1].plot(training_history['grad_norms'])
            axes[1, 1].set_xlabel('Step')
            axes[1, 1].set_ylabel('Gradient Norm')
            axes[1, 1].set_title('Gradient Norms')
            axes[1, 1].grid(True)
        
        plt.tight_layout()
        
        if save_path:
            plt.savefig(save_path, dpi=300, bbox_inches='tight')
            print(f"✅ Gráficos guardados en: {save_path}")
        else:
            plt.show()
    
    @staticmethod
    def visualize_model_parameters(
        model: CausalTransformer,
        save_path: Optional[str] = None
    ):
        """
        Visualiza distribución de parámetros del modelo.
        
        :param model: Modelo
        :param save_path: Ruta para guardar
        """
        try:
            import matplotlib.pyplot as plt
        except ImportError:
            print("⚠️ matplotlib no está instalado")
            return
        
        # Recopilar todos los parámetros
        all_params = []
        layer_names = []
        
        for name, param in model.named_parameters():
            if param.requires_grad:
                all_params.extend(param.data.flatten().cpu().numpy().tolist())
                layer_names.append(name)
        
        fig, axes = plt.subplots(1, 2, figsize=(15, 5))
        
        # Histograma
        axes[0].hist(all_params, bins=50, alpha=0.7)
        axes[0].set_xlabel('Parameter Value')
        axes[0].set_ylabel('Frequency')
        axes[0].set_title('Distribution of Model Parameters')
        axes[0].grid(True)
        
        # Estadísticas por capa
        layer_stats = []
        for name, param in model.named_parameters():
            if param.requires_grad:
                layer_stats.append({
                    'name': name.split('.')[-1],
                    'mean': param.data.mean().item(),
                    'std': param.data.std().item(),
                    'min': param.data.min().item(),
                    'max': param.data.max().item()
                })
        
        if layer_stats:
            names = [s['name'] for s in layer_stats[:10]]  # Top 10
            means = [s['mean'] for s in layer_stats[:10]]
            
            axes[1].barh(names, means)
            axes[1].set_xlabel('Mean Parameter Value')
            axes[1].set_title('Mean Parameters by Layer (Top 10)')
            axes[1].grid(True)
        
        plt.tight_layout()
        
        if save_path:
            plt.savefig(save_path, dpi=300, bbox_inches='tight')
            print(f"✅ Visualización guardada en: {save_path}")
        else:
            plt.show()


class ModelExporterPro:
    """
    Exportador avanzado con múltiples formatos y optimizaciones.
    """
    
    @staticmethod
    def export_to_onnx_optimized(
        model: CausalTransformer,
        output_path: str,
        input_shape: tuple = (1, 128),
        dynamic_axes: bool = True,
        opset_version: int = 13,
        optimize: bool = True
    ):
        """
        Exporta a ONNX con optimizaciones.
        
        :param model: Modelo
        :param output_path: Ruta de salida
        :param input_shape: Forma del input
        :param dynamic_axes: Si True, permite ejes dinámicos
        :param opset_version: Versión de opset
        :param optimize: Si True, aplica optimizaciones
        """
        try:
            import onnx
            from onnxruntime.quantization import quantize_dynamic, QuantType
            
            model.eval()
            dummy_input = torch.randint(0, model.vocab_size, input_shape)
            
            # Exportar
            torch.onnx.export(
                model,
                dummy_input,
                output_path,
                input_names=['input_ids'],
                output_names=['logits'],
                dynamic_axes={
                    'input_ids': {0: 'batch_size', 1: 'sequence_length'},
                    'logits': {0: 'batch_size', 1: 'sequence_length'}
                } if dynamic_axes else None,
                opset_version=opset_version,
                do_constant_folding=True
            )
            
            print(f"✅ Modelo exportado a ONNX: {output_path}")
            
            # Optimizar si se solicita
            if optimize:
                optimized_path = output_path.replace('.onnx', '_optimized.onnx')
                try:
                    quantize_dynamic(
                        output_path,
                        optimized_path,
                        weight_type=QuantType.QUINT8
                    )
                    print(f"✅ Modelo ONNX optimizado: {optimized_path}")
                except Exception as e:
                    print(f"⚠️ Error optimizando ONNX: {e}")
            
            # Verificar
            onnx_model = onnx.load(output_path)
            onnx.checker.check_model(onnx_model)
            print("✅ ONNX model verificado correctamente")
            
        except ImportError:
            print("⚠️ ONNX no está instalado. Instala con: pip install onnx onnxruntime")
        except Exception as e:
            print(f"⚠️ Error exportando a ONNX: {e}")
    
    @staticmethod
    def export_to_tensorrt(
        model: CausalTransformer,
        output_path: str,
        input_shape: tuple = (1, 128),
        precision: str = 'fp16'
    ):
        """
        Exporta a TensorRT (requiere TensorRT instalado).
        
        :param model: Modelo
        :param output_path: Ruta de salida
        :param input_shape: Forma del input
        :param precision: Precisión ('fp32', 'fp16', 'int8')
        """
        try:
            import tensorrt as trt
            print("✅ TensorRT disponible")
            # Implementación simplificada
            # En producción usar API completa de TensorRT
            print(f"⚠️ Exportación a TensorRT requiere configuración adicional")
            print(f"   Path objetivo: {output_path}")
            print(f"   Precision: {precision}")
        except ImportError:
            print("⚠️ TensorRT no está instalado")
            print("   Instala con: pip install nvidia-tensorrt")
        except Exception as e:
            print(f"⚠️ Error con TensorRT: {e}")


class PerformanceAnalyzer:
    """
    Analizador avanzado de rendimiento.
    """
    
    @staticmethod
    def analyze_inference_performance(
        model: CausalTransformer,
        test_inputs: List[torch.Tensor],
        batch_sizes: List[int] = [1, 4, 8, 16]
    ) -> dict:
        """
        Analiza rendimiento de inferencia con diferentes configuraciones.
        
        :param model: Modelo
        :param test_inputs: Lista de inputs de prueba
        :param batch_sizes: Tamaños de batch a probar
        :return: Análisis de rendimiento
        """
        import time
        
        results = {}
        model.eval()
        
        for batch_size in batch_sizes:
            # Crear batch
            batch = torch.cat(test_inputs[:batch_size])
            
            # Warmup
            with torch.no_grad():
                for _ in range(5):
                    _ = model(batch)
            
            # Benchmark
            times = []
            with torch.no_grad():
                for _ in range(50):
                    start = time.time()
                    _ = model(batch)
                    if torch.cuda.is_available():
                        torch.cuda.synchronize()
                    times.append(time.time() - start)
            
            avg_time = sum(times) / len(times)
            p95_time = sorted(times)[int(len(times) * 0.95)]
            
            seq_len = batch.shape[1]
            tokens_per_sec = (batch_size * seq_len) / avg_time if avg_time > 0 else 0
            
            results[batch_size] = {
                'avg_latency_ms': avg_time * 1000,
                'p95_latency_ms': p95_time * 1000,
                'tokens_per_second': tokens_per_sec,
                'throughput_batches_per_sec': batch_size / avg_time if avg_time > 0 else 0
            }
        
        return results
    
    @staticmethod
    def compare_optimization_techniques(
        model: CausalTransformer,
        test_input: torch.Tensor,
        techniques: List[str] = ['baseline', 'quantization', 'pruning', 'both']
    ) -> dict:
        """
        Compara diferentes técnicas de optimización.
        
        :param model: Modelo
        :param test_input: Input de prueba
        :param techniques: Técnicas a comparar
        :return: Comparación de técnicas
        """
        results = {}
        
        # Baseline
        if 'baseline' in techniques:
            baseline = PerformanceAnalyzer.analyze_inference_performance(
                model, [test_input], batch_sizes=[1]
            )
            results['baseline'] = baseline[1]
        
        # Cuantización
        if 'quantization' in techniques:
            quantizer = AdvancedQuantization()
            quantized = quantizer.quantize_model_dynamic(model)
            quant_perf = PerformanceAnalyzer.analyze_inference_performance(
                quantized, [test_input], batch_sizes=[1]
            )
            results['quantization'] = quant_perf[1]
        
        # Pruning
        if 'pruning' in techniques:
            pruner = AdvancedPruning()
            pruned = pruner.magnitude_pruning(model, pruning_ratio=0.1)
            pruned_perf = PerformanceAnalyzer.analyze_inference_performance(
                pruned, [test_input], batch_sizes=[1]
            )
            results['pruning'] = pruned_perf[1]
        
        return results


class ModelValidatorPro:
    """
    Validador avanzado con checks exhaustivos.
    """
    
    @staticmethod
    def validate_model_complete(
        model: CausalTransformer,
        test_input: torch.Tensor,
        verbose: bool = True
    ) -> dict:
        """
        Validación completa del modelo.
        
        :param model: Modelo
        :param test_input: Input de prueba
        :param verbose: Si True, muestra detalles
        :return: Resultados de validación
        """
        results = {
            'valid': True,
            'errors': [],
            'warnings': [],
            'checks_passed': 0,
            'checks_total': 0
        }
        
        # Check 1: Forward pass
        results['checks_total'] += 1
        try:
            model.eval()
            with torch.no_grad():
                output = model(test_input)
            if output.shape[0] != test_input.shape[0]:
                results['errors'].append('Output batch size no coincide con input')
                results['valid'] = False
            else:
                results['checks_passed'] += 1
        except Exception as e:
            results['errors'].append(f'Error en forward pass: {e}')
            results['valid'] = False
        
        # Check 2: Parámetros
        results['checks_total'] += 1
        try:
            params = count_parameters(model)
            if params['total'] == 0:
                results['errors'].append('Modelo no tiene parámetros')
                results['valid'] = False
            else:
                results['checks_passed'] += 1
                if verbose:
                    print(f"  ✓ Parámetros: {params['total_millions']:.2f}M")
        except Exception as e:
            results['errors'].append(f'Error contando parámetros: {e}')
            results['valid'] = False
        
        # Check 3: Gradientes
        results['checks_total'] += 1
        try:
            model.train()
            output = model(test_input)
            loss = output.sum()
            loss.backward()
            
            grad_norms = []
            for param in model.parameters():
                if param.grad is not None:
                    grad_norms.append(param.grad.norm().item())
            
            if not grad_norms:
                results['warnings'].append('No se calcularon gradientes')
            else:
                results['checks_passed'] += 1
                if verbose:
                    avg_grad_norm = sum(grad_norms) / len(grad_norms)
                    print(f"  ✓ Gradientes: avg_norm={avg_grad_norm:.4f}")
        except Exception as e:
            results['warnings'].append(f'Error verificando gradientes: {e}')
        
        # Check 4: Memoria
        results['checks_total'] += 1
        try:
            memory = estimate_memory_usage(
                test_input.shape[0],
                test_input.shape[1],
                model.d_model,
                model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
                len(model.blocks),
                model.vocab_size
            )
            results['checks_passed'] += 1
            if verbose:
                print(f"  ✓ Memoria estimada: {memory['total_gb']:.2f} GB")
        except Exception as e:
            results['warnings'].append(f'Error estimando memoria: {e}')
        
        if verbose:
            print(f"\n✅ Validación completada: {results['checks_passed']}/{results['checks_total']} checks pasados")
            if results['errors']:
                print(f"❌ Errores: {len(results['errors'])}")
            if results['warnings']:
                print(f"⚠️  Warnings: {len(results['warnings'])}")
        
        return results


