class ModelEnsemblePro:
    """
    Sistema avanzado de ensembles para mejorar performance.
    """
    
    @staticmethod
    def create_ensemble(
        models: List[CausalTransformer],
        ensemble_method: str = 'average',
        weights: Optional[List[float]] = None
    ) -> callable:
        """
        Crea ensemble de modelos.
        
        :param models: Lista de modelos
        :param ensemble_method: Método ('average', 'weighted', 'voting')
        :param weights: Pesos para weighted average (opcional)
        :return: Función de ensemble
        """
        if weights is None:
            weights = [1.0 / len(models)] * len(models)
        
        def ensemble_forward(x: torch.Tensor) -> torch.Tensor:
            """Forward pass del ensemble."""
            outputs = []
            for model in models:
                model.eval()
                with torch.no_grad():
                    outputs.append(model(x))
            
            if ensemble_method == 'average':
                return torch.stack(outputs).mean(dim=0)
            elif ensemble_method == 'weighted':
                weighted_outputs = [w * out for w, out in zip(weights, outputs)]
                return torch.stack(weighted_outputs).sum(dim=0)
            elif ensemble_method == 'voting':
                # Voting para clasificación (simplificado)
                probs = torch.stack([torch.softmax(out, dim=-1) for out in outputs])
                return probs.mean(dim=0)
            else:
                return torch.stack(outputs).mean(dim=0)
        
        print(f"✅ Ensemble creado con {len(models)} modelos usando método: {ensemble_method}")
        return ensemble_forward
    
    @staticmethod
    def evaluate_ensemble(
        ensemble_fn: callable,
        test_loader,
        metrics: List[str] = ['perplexity', 'accuracy']
    ) -> dict:
        """
        Evalúa performance del ensemble.
        
        :param ensemble_fn: Función de ensemble
        :param test_loader: DataLoader de prueba
        :param metrics: Métricas a calcular
        :return: Resultados de evaluación
        """
        results = {}
        total_loss = 0
        total_correct = 0
        total_tokens = 0
        
        criterion = nn.CrossEntropyLoss(ignore_index=-1)
        
        for batch in test_loader:
            inputs, targets = batch
            outputs = ensemble_fn(inputs)
            
            # Reshape para loss
            outputs_flat = outputs.view(-1, outputs.size(-1))
            targets_flat = targets.view(-1)
            
            loss = criterion(outputs_flat, targets_flat)
            total_loss += loss.item()
            
            # Accuracy
            predictions = outputs_flat.argmax(dim=-1)
            mask = targets_flat != -1
            total_correct += (predictions[mask] == targets_flat[mask]).sum().item()
            total_tokens += mask.sum().item()
        
        if 'perplexity' in metrics:
            avg_loss = total_loss / len(test_loader)
            results['perplexity'] = torch.exp(torch.tensor(avg_loss)).item()
        
        if 'accuracy' in metrics:
            results['accuracy'] = total_correct / total_tokens if total_tokens > 0 else 0
        
        return results


class HyperparameterTuner:
    """
    Tuner avanzado de hiperparámetros con múltiples estrategias.
    """
    
    @staticmethod
    def grid_search(
        param_grid: dict,
        objective_fn: callable,
        max_iterations: int = 100
    ) -> dict:
        """
        Grid search para hiperparámetros.
        
        :param param_grid: Grid de parámetros
        :param objective_fn: Función objetivo
        :param max_iterations: Máximo de iteraciones
        :return: Mejores parámetros y resultados
        """
        from itertools import product
        
        best_score = float('-inf')
        best_params = None
        results = []
        
        # Generar todas las combinaciones
        keys = param_grid.keys()
        values = param_grid.values()
        
        combinations = list(product(*values))
        num_combinations = len(combinations)
        
        print(f"📊 Grid search: {num_combinations} combinaciones a evaluar")
        
        for i, combination in enumerate(combinations[:max_iterations]):
            params = dict(zip(keys, combination))
            
            try:
                score = objective_fn(params)
                results.append({'params': params, 'score': score})
                
                if score > best_score:
                    best_score = score
                    best_params = params
                
                if (i + 1) % 10 == 0:
                    print(f"  Progreso: {i+1}/{min(num_combinations, max_iterations)}")
            except Exception as e:
                print(f"⚠️ Error con parámetros {params}: {e}")
        
        return {
            'best_params': best_params,
            'best_score': best_score,
            'all_results': results,
            'num_evaluated': len(results)
        }
    
    @staticmethod
    def random_search(
        param_distributions: dict,
        objective_fn: callable,
        n_iter: int = 50
    ) -> dict:
        """
        Random search para hiperparámetros.
        
        :param param_distributions: Distribuciones de parámetros
        :param objective_fn: Función objetivo
        :param n_iter: Número de iteraciones
        :return: Mejores parámetros y resultados
        """
        import random
        
        best_score = float('-inf')
        best_params = None
        results = []
        
        print(f"📊 Random search: {n_iter} iteraciones")
        
        for i in range(n_iter):
            # Sample de distribuciones
            params = {}
            for key, dist in param_distributions.items():
                if isinstance(dist, list):
                    params[key] = random.choice(dist)
                elif isinstance(dist, tuple) and len(dist) == 2:
                    # Range (min, max)
                    params[key] = random.uniform(dist[0], dist[1])
                else:
                    params[key] = dist
            
            try:
                score = objective_fn(params)
                results.append({'params': params, 'score': score})
                
                if score > best_score:
                    best_score = score
                    best_params = params
                
                if (i + 1) % 10 == 0:
                    print(f"  Progreso: {i+1}/{n_iter}, Best: {best_score:.4f}")
            except Exception as e:
                print(f"⚠️ Error con parámetros {params}: {e}")
        
        return {
            'best_params': best_params,
            'best_score': best_score,
            'all_results': results,
            'num_evaluated': len(results)
        }


class ModelCompressionPipeline:
    """
    Pipeline completo de compresión de modelos.
    """
    
    @staticmethod
    def compress_model_comprehensive(
        model: CausalTransformer,
        target_size_mb: Optional[float] = None,
        target_accuracy_loss: float = 0.05,
        compression_methods: List[str] = ['quantization', 'pruning']
    ) -> dict:
        """
        Comprime modelo usando múltiples técnicas.
        
        :param model: Modelo a comprimir
        :param target_size_mb: Tamaño objetivo en MB
        :param target_accuracy_loss: Pérdida máxima de accuracy
        :param compression_methods: Métodos a usar
        :return: Modelo comprimido y estadísticas
        """
        compressed_model = model
        compression_stats = {
            'original_size_mb': 0,
            'compressed_size_mb': 0,
            'compression_ratio': 0,
            'methods_applied': []
        }
        
        # Estimar tamaño original
        params = count_parameters(model)
        original_size_bytes = params['total'] * 4  # float32
        compression_stats['original_size_mb'] = original_size_bytes / (1024 ** 2)
        
        # Aplicar métodos de compresión
        if 'quantization' in compression_methods:
            quantizer = AdvancedQuantization()
            compressed_model = quantizer.quantize_model_dynamic(compressed_model)
            compression_stats['methods_applied'].append('dynamic_quantization')
        
        if 'pruning' in compression_methods:
            pruner = AdvancedPruning()
            compressed_model = pruner.magnitude_pruning(
                compressed_model, 
                pruning_ratio=0.1
            )
            compression_stats['methods_applied'].append('magnitude_pruning')
        
        # Estimar tamaño comprimido
        # Simplificado: asumir 50% reducción con cuantización + pruning
        compressed_size_bytes = original_size_bytes * 0.5
        compression_stats['compressed_size_mb'] = compressed_size_bytes / (1024 ** 2)
        compression_stats['compression_ratio'] = (
            compression_stats['original_size_mb'] / 
            compression_stats['compressed_size_mb']
        )
        
        print(f"✅ Compresión completada:")
        print(f"   Tamaño original: {compression_stats['original_size_mb']:.2f} MB")
        print(f"   Tamaño comprimido: {compression_stats['compressed_size_mb']:.2f} MB")
        print(f"   Ratio de compresión: {compression_stats['compression_ratio']:.2f}x")
        print(f"   Métodos aplicados: {', '.join(compression_stats['methods_applied'])}")
        
        return {
            'compressed_model': compressed_model,
            'stats': compression_stats
        }


class DistributedTrainingPro:
    """
    Configuración avanzada de entrenamiento distribuido.
    """
    
    @staticmethod
    def setup_multi_gpu_training(
        model: CausalTransformer,
        num_gpus: int = None,
        strategy: str = 'ddp'
    ) -> dict:
        """
        Configura entrenamiento multi-GPU.
        
        :param model: Modelo
        :param num_gpus: Número de GPUs (None = auto-detect)
        :param strategy: Estrategia ('ddp', 'dp')
        :return: Configuración de entrenamiento distribuido
        """
        if not torch.cuda.is_available():
            return {'error': 'CUDA no disponible'}
        
        if num_gpus is None:
            num_gpus = torch.cuda.device_count()
        
        config = {
            'num_gpus': num_gpus,
            'strategy': strategy,
            'available': num_gpus > 1
        }
        
        if strategy == 'ddp' and num_gpus > 1:
            print(f"✅ Configurado DistributedDataParallel para {num_gpus} GPUs")
            config['model'] = torch.nn.parallel.DistributedDataParallel(model)
        elif strategy == 'dp' and num_gpus > 1:
            print(f"✅ Configurado DataParallel para {num_gpus} GPUs")
            config['model'] = torch.nn.DataParallel(model)
        else:
            print(f"⚠️ Solo 1 GPU disponible, usando entrenamiento normal")
            config['model'] = model
        
        return config
    
    @staticmethod
    def optimize_for_distributed(
        batch_size: int,
        num_gpus: int,
        gradient_accumulation: int = 1
    ) -> dict:
        """
        Optimiza hiperparámetros para entrenamiento distribuido.
        
        :param batch_size: Batch size por GPU
        :param num_gpus: Número de GPUs
        :param gradient_accumulation: Pasos de acumulación
        :return: Configuración optimizada
        """
        effective_batch_size = batch_size * num_gpus * gradient_accumulation
        
        return {
            'batch_size_per_gpu': batch_size,
            'num_gpus': num_gpus,
            'gradient_accumulation': gradient_accumulation,
            'effective_batch_size': effective_batch_size,
            'recommendations': [
                f'Usar learning rate ajustado: lr_base * sqrt({effective_batch_size})',
                f'Gradient accumulation: {gradient_accumulation} pasos',
                f'Total batch size efectivo: {effective_batch_size}'
            ]
        }


class ModelServingOptimizer:
    """
    Optimizador para serving en producción.
    """
    
    @staticmethod
    def optimize_for_serving(
        model: CausalTransformer,
        expected_qps: int = 100,
        max_latency_ms: int = 100
    ) -> dict:
        """
        Optimiza modelo para serving en producción.
        
        :param model: Modelo
        :param expected_qps: Queries por segundo esperadas
        :param max_latency_ms: Latencia máxima en ms
        :return: Recomendaciones de optimización
        """
        recommendations = []
        
        # Cuantización
        if expected_qps > 50:
            recommendations.append({
                'technique': 'quantization',
                'priority': 'high',
                'reason': f'QPS alto ({expected_qps}) requiere modelo ligero',
                'implementation': 'Use AdvancedQuantization.quantize_model_dynamic()'
            })
        
        # Batch processing
        if expected_qps > 100:
            recommendations.append({
                'technique': 'batch_processing',
                'priority': 'high',
                'reason': 'Procesar múltiples requests en batch mejora throughput',
                'implementation': 'Implementar batching dinámico'
            })
        
        # KV Cache
        recommendations.append({
            'technique': 'kv_cache',
            'priority': 'medium',
            'reason': 'Acelera generación autoregresiva',
            'implementation': 'Use KVCacheOptimizer.implement_kv_cache()'
        })
        
        # Model compilation
        recommendations.append({
            'technique': 'torch_compile',
            'priority': 'medium',
            'reason': 'Torch compile optimiza el modelo para inferencia',
            'implementation': 'model = torch.compile(model)'
        })
        
        return {
            'expected_qps': expected_qps,
            'max_latency_ms': max_latency_ms,
            'recommendations': recommendations,
            'optimization_priority': sorted(recommendations, key=lambda x: {'high': 0, 'medium': 1, 'low': 2}[x['priority']])
        }
    
    @staticmethod
    def create_serving_config(
        model_path: str,
        batch_size: int = 8,
        max_batch_size: int = 32,
        timeout_ms: int = 1000
    ) -> dict:
        """
        Crea configuración para serving.
        
        :param model_path: Ruta del modelo
        :param batch_size: Batch size inicial
        :param max_batch_size: Batch size máximo
        :param timeout_ms: Timeout en ms
        :return: Configuración de serving
        """
        return {
            'model_path': model_path,
            'batch_size': batch_size,
            'max_batch_size': max_batch_size,
            'timeout_ms': timeout_ms,
            'dynamic_batching': True,
            'preload_model': True,
            'gpu_memory_fraction': 0.8,
            'enable_batching': True
        }


class AdvancedModelAnalysis:
    """
    Análisis avanzado de modelos con múltiples perspectivas.
    """
    
    @staticmethod
    def analyze_model_architecture(
        model: CausalTransformer
    ) -> dict:
        """
        Analiza arquitectura del modelo en detalle.
        
        :param model: Modelo
        :return: Análisis de arquitectura
        """
        analysis = {
            'total_layers': len(model.blocks),
            'd_model': model.d_model,
            'vocab_size': model.vocab_size,
            'num_heads': model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
            'd_ff': model.blocks[0].ffn.linear1.out_features if hasattr(model.blocks[0], 'ffn') else 2048,
            'total_parameters': count_parameters(model)['total'],
            'trainable_parameters': sum(p.numel() for p in model.parameters() if p.requires_grad),
            'layer_details': []
        }
        
        # Detalles por capa
        for i, block in enumerate(model.blocks):
            layer_info = {
                'layer_index': i,
                'has_attention': hasattr(block, 'attention'),
                'has_ffn': hasattr(block, 'ffn'),
                'has_norm': hasattr(block, 'ln1') and hasattr(block, 'ln2')
            }
            
            if hasattr(block, 'attention'):
                layer_info['attention_heads'] = block.attention.n_heads
                layer_info['attention_dim'] = block.attention.d_model
            
            analysis['layer_details'].append(layer_info)
        
        return analysis
    
    @staticmethod
    def compare_architectures(
        models: List[CausalTransformer],
        model_names: List[str]
    ) -> dict:
        """
        Compara múltiples arquitecturas.
        
        :param models: Lista de modelos
        :param model_names: Nombres de modelos
        :return: Comparación de arquitecturas
        """
        comparisons = []
        
        for model, name in zip(models, model_names):
            analysis = AdvancedModelAnalysis.analyze_model_architecture(model)
            comparisons.append({
                'name': name,
                **analysis
            })
        
        return {
            'models': comparisons,
            'summary': {
                'num_models': len(models),
                'avg_parameters': sum(c['total_parameters'] for c in comparisons) / len(comparisons),
                'avg_layers': sum(c['total_layers'] for c in comparisons) / len(comparisons)
            }
        }


class ModelVersioningSystem:
    """
    Sistema de versionado para modelos.
    """
    
    @staticmethod
    def create_model_version(
        model: CausalTransformer,
        version: str,
        metadata: dict = None,
        save_path: str = './models'
    ) -> str:
        """
        Crea versión del modelo con metadata.
        
        :param model: Modelo
        :param version: Versión (ej: '1.0.0')
        :param metadata: Metadata adicional
        :param save_path: Directorio de guardado
        :return: Ruta del modelo guardado
        """
        import os
        from datetime import datetime
        
        os.makedirs(save_path, exist_ok=True)
        
        model_data = {
            'version': version,
            'created_at': datetime.now().isoformat(),
            'model_state_dict': model.state_dict(),
            'model_config': {
                'vocab_size': model.vocab_size,
                'd_model': model.d_model,
                'n_layers': len(model.blocks),
                'n_heads': model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8
            },
            'metadata': metadata or {}
        }
        
        filename = f'model_v{version}.pt'
        filepath = os.path.join(save_path, filename)
        
        torch.save(model_data, filepath)
        print(f"✅ Modelo versionado guardado: {filepath}")
        
        return filepath
    
    @staticmethod
    def load_model_version(
        version: str,
        model_class: type,
        save_path: str = './models',
        device: str = 'cpu'
    ) -> Tuple[CausalTransformer, dict]:
        """
        Carga versión específica del modelo.
        
        :param version: Versión a cargar
        :param model_class: Clase del modelo
        :param save_path: Directorio de modelos
        :param device: Device
        :return: Tuple (modelo, metadata)
        """
        filename = f'model_v{version}.pt'
        filepath = os.path.join(save_path, filename)
        
        if not os.path.exists(filepath):
            raise FileNotFoundError(f"Modelo versión {version} no encontrado")
        
        model_data = torch.load(filepath, map_location=device)
        
        # Recrear modelo
        config = model_data['model_config']
        model = model_class(**config)
        model.load_state_dict(model_data['model_state_dict'])
        model.to(device)
        
        print(f"✅ Modelo versión {version} cargado")
        return model, model_data['metadata']


