class ModelDebugger:
    """
    Debugger avanzado para modelos Transformer.
    """
    
    @staticmethod
    def debug_forward_pass(
        model: CausalTransformer,
        input_tensor: torch.Tensor,
        verbose: bool = True
    ) -> dict:
        """
        Debug del forward pass paso a paso.
        
        :param model: Modelo
        :param input_tensor: Input
        :param verbose: Si True, imprime detalles
        :return: Información de debug
        """
        debug_info = {
            'input_shape': list(input_tensor.shape),
            'input_stats': {
                'min': input_tensor.min().item(),
                'max': input_tensor.max().item(),
                'mean': input_tensor.mean().item(),
                'std': input_tensor.std().item()
            },
            'layers': []
        }
        
        model.eval()
        x = input_tensor
        
        # Embeddings
        try:
            x_emb = model.token_embedding(x)
            x_pos = model.pos_encoding(x_emb)
            debug_info['layers'].append({
                'name': 'embeddings',
                'output_shape': list(x_pos.shape),
                'output_stats': {
                    'min': x_pos.min().item(),
                    'max': x_pos.max().item(),
                    'mean': x_pos.mean().item(),
                    'has_nan': torch.isnan(x_pos).any().item(),
                    'has_inf': torch.isinf(x_pos).any().item()
                }
            })
            x = x_pos
        except Exception as e:
            debug_info['layers'].append({
                'name': 'embeddings',
                'error': str(e)
            })
            return debug_info
        
        # Cada bloque
        for i, block in enumerate(model.blocks):
            try:
                # Atención
                x_norm1 = block.ln1(x)
                attn_out, attn_weights = block.attention(x_norm1)
                x = x + attn_out
                
                # FFN
                x_norm2 = block.ln2(x)
                ffn_out = block.ffn(x_norm2)
                x = x + ffn_out
                
                debug_info['layers'].append({
                    'name': f'block_{i}',
                    'output_shape': list(x.shape),
                    'attention_weights_shape': list(attn_weights.shape) if attn_weights is not None else None,
                    'output_stats': {
                        'min': x.min().item(),
                        'max': x.max().item(),
                        'mean': x.mean().item(),
                        'std': x.std().item(),
                        'has_nan': torch.isnan(x).any().item(),
                        'has_inf': torch.isinf(x).any().item()
                    }
                })
            except Exception as e:
                debug_info['layers'].append({
                    'name': f'block_{i}',
                    'error': str(e)
                })
                break
        
        # Output
        try:
            x_norm = model.output_norm(x)
            output = model.output(x_norm)
            debug_info['output'] = {
                'shape': list(output.shape),
                'stats': {
                    'min': output.min().item(),
                    'max': output.max().item(),
                    'mean': output.mean().item(),
                    'has_nan': torch.isnan(output).any().item(),
                    'has_inf': torch.isinf(output).any().item()
                }
            }
        except Exception as e:
            debug_info['output'] = {'error': str(e)}
        
        if verbose:
            print("🔍 DEBUG INFO:")
            print(f"  Input shape: {debug_info['input_shape']}")
            for layer in debug_info['layers']:
                if 'error' in layer:
                    print(f"  ❌ {layer['name']}: ERROR - {layer['error']}")
                else:
                    print(f"  ✅ {layer['name']}: {layer['output_shape']}")
            if 'output' in debug_info:
                if 'error' in debug_info['output']:
                    print(f"  ❌ Output: ERROR - {debug_info['output']['error']}")
                else:
                    print(f"  ✅ Output: {debug_info['output']['shape']}")
        
        return debug_info
    
    @staticmethod
    def check_gradient_flow(
        model: CausalTransformer,
        input_tensor: torch.Tensor,
        target_tensor: torch.Tensor
    ) -> dict:
        """
        Verifica flujo de gradientes.
        
        :param model: Modelo
        :param input_tensor: Input
        :param target_tensor: Target
        :return: Información de gradientes
        """
        model.train()
        output = model(input_tensor)
        loss = nn.CrossEntropyLoss()(output.view(-1, output.size(-1)), target_tensor.view(-1))
        loss.backward()
        
        grad_info = {
            'loss': loss.item(),
            'layers': []
        }
        
        for name, param in model.named_parameters():
            if param.grad is not None:
                grad_norm = param.grad.norm().item()
                grad_mean = param.grad.mean().item()
                grad_std = param.grad.std().item()
                
                grad_info['layers'].append({
                    'name': name,
                    'grad_norm': grad_norm,
                    'grad_mean': grad_mean,
                    'grad_std': grad_std,
                    'has_zero_grad': (param.grad == 0).all().item(),
                    'has_nan_grad': torch.isnan(param.grad).any().item()
                })
        
        return grad_info


class ModelInspector:
    """
    Inspector avanzado para análisis detallado de modelos.
    """
    
    @staticmethod
    def inspect_layer_weights(
        model: CausalTransformer,
        layer_name: str = None
    ) -> dict:
        """
        Inspecciona pesos de capas específicas.
        
        :param model: Modelo
        :param layer_name: Nombre de capa (None = todas)
        :return: Información de pesos
        """
        inspection = {}
        
        for name, param in model.named_parameters():
            if layer_name is None or layer_name in name:
                inspection[name] = {
                    'shape': list(param.shape),
                    'dtype': str(param.dtype),
                    'requires_grad': param.requires_grad,
                    'stats': {
                        'min': param.data.min().item(),
                        'max': param.data.max().item(),
                        'mean': param.data.mean().item(),
                        'std': param.data.std().item(),
                        'num_elements': param.numel()
                    },
                    'has_nan': torch.isnan(param.data).any().item(),
                    'has_inf': torch.isinf(param.data).any().item()
                }
        
        return inspection
    
    @staticmethod
    def compare_model_weights(
        model_a: CausalTransformer,
        model_b: CausalTransformer
    ) -> dict:
        """
        Compara pesos entre dos modelos.
        
        :param model_a: Modelo A
        :param model_b: Modelo B
        :return: Comparación
        """
        comparison = {
            'common_layers': [],
            'only_in_a': [],
            'only_in_b': [],
            'differences': []
        }
        
        params_a = dict(model_a.named_parameters())
        params_b = dict(model_b.named_parameters())
        
        all_keys = set(params_a.keys()) | set(params_b.keys())
        
        for key in all_keys:
            if key in params_a and key in params_b:
                comparison['common_layers'].append(key)
                
                # Calcular diferencia
                diff = (params_a[key].data - params_b[key].data).abs()
                comparison['differences'].append({
                    'layer': key,
                    'mean_diff': diff.mean().item(),
                    'max_diff': diff.max().item(),
                    'shape_match': params_a[key].shape == params_b[key].shape
                })
            elif key in params_a:
                comparison['only_in_a'].append(key)
            else:
                comparison['only_in_b'].append(key)
        
        return comparison


class ModelExportManager:
    """
    Gestor avanzado de exportación de modelos.
    """
    
    @staticmethod
    def export_to_multiple_formats(
        model: CausalTransformer,
        base_path: str = './exports',
        formats: List[str] = ['pytorch', 'onnx']
    ) -> dict:
        """
        Exporta modelo a múltiples formatos.
        
        :param model: Modelo
        :param base_path: Directorio base
        :param formats: Formatos a exportar
        :return: Rutas de archivos exportados
        """
        import os
        os.makedirs(base_path, exist_ok=True)
        
        exported = {}
        
        # PyTorch
        if 'pytorch' in formats:
            pytorch_path = os.path.join(base_path, 'model.pt')
            torch.save({
                'model_state_dict': model.state_dict(),
                'model_config': {
                    'vocab_size': model.vocab_size,
                    'd_model': model.d_model,
                    'n_layers': len(model.blocks),
                    'n_heads': model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8
                }
            }, pytorch_path)
            exported['pytorch'] = pytorch_path
            print(f"✅ Exportado a PyTorch: {pytorch_path}")
        
        # ONNX
        if 'onnx' in formats:
            try:
                onnx_path = os.path.join(base_path, 'model.onnx')
                ModelExporterPro.export_to_onnx_optimized(
                    model, onnx_path, optimize=False
                )
                exported['onnx'] = onnx_path
            except Exception as e:
                print(f"⚠️ Error exportando a ONNX: {e}")
        
        # JSON metadata
        metadata_path = os.path.join(base_path, 'metadata.json')
        try:
            import json
            metadata = {
                'vocab_size': model.vocab_size,
                'd_model': model.d_model,
                'n_layers': len(model.blocks),
                'n_heads': model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
                'parameters': count_parameters(model)['total_millions'],
                'exported_formats': list(exported.keys()),
                'version': __version__
            }
            with open(metadata_path, 'w') as f:
                json.dump(metadata, f, indent=2)
            exported['metadata'] = metadata_path
        except Exception as e:
            print(f"⚠️ Error creando metadata: {e}")
        
        return exported


class ModelComparisonVisualizer:
    """
    Visualizador para comparaciones de modelos.
    """
    
    @staticmethod
    def visualize_model_comparison(
        comparison_data: dict,
        save_path: Optional[str] = None
    ):
        """
        Visualiza comparación de modelos.
        
        :param comparison_data: Datos de comparación
        :param save_path: Ruta para guardar
        """
        try:
            import matplotlib.pyplot as plt
        except ImportError:
            print("⚠️ matplotlib no está instalado")
            return
        
        fig, axes = plt.subplots(2, 2, figsize=(15, 10))
        
        # Parámetros
        if 'models' in comparison_data:
            models = comparison_data['models']
            names = [m['name'] for m in models]
            params = [m.get('parameters', {}).get('total_millions', 0) for m in models]
            
            axes[0, 0].bar(names, params)
            axes[0, 0].set_title('Total Parameters (Millions)')
            axes[0, 0].set_ylabel('Parameters (M)')
            axes[0, 0].tick_params(axis='x', rotation=45)
        
        # Memoria
        if 'models' in comparison_data:
            memory = [m.get('memory_estimate', {}).get('total_gb', 0) for m in models]
            axes[0, 1].bar(names, memory)
            axes[0, 1].set_title('Memory Usage (GB)')
            axes[0, 1].set_ylabel('Memory (GB)')
            axes[0, 1].tick_params(axis='x', rotation=45)
        
        # Performance
        if 'models' in comparison_data:
            perf = [m.get('benchmark', {}).get(1, {}).get('tokens_per_second', 0) for m in models]
            axes[1, 0].bar(names, perf)
            axes[1, 0].set_title('Tokens per Second')
            axes[1, 0].set_ylabel('Tokens/sec')
            axes[1, 0].tick_params(axis='x', rotation=45)
        
        # Accuracy/Perplexity
        if 'models' in comparison_data:
            eval_data = [m.get('evaluation', {}) for m in models]
            perplexity = [e.get('perplexity', 0) if isinstance(e.get('perplexity'), (int, float)) else 0 for e in eval_data]
            axes[1, 1].bar(names, perplexity)
            axes[1, 1].set_title('Perplexity')
            axes[1, 1].set_ylabel('Perplexity')
            axes[1, 1].tick_params(axis='x', rotation=45)
        
        plt.tight_layout()
        
        if save_path:
            plt.savefig(save_path, dpi=300, bbox_inches='tight')
            print(f"✅ Visualización guardada: {save_path}")
        else:
            plt.show()


class AdvancedModelUtilities:
    """
    Utilidades avanzadas adicionales para modelos.
    """
    
    @staticmethod
    def create_model_from_checkpoint(
        checkpoint_path: str,
        model_class: type = CausalTransformer
    ) -> CausalTransformer:
        """
        Crea modelo desde checkpoint.
        
        :param checkpoint_path: Ruta del checkpoint
        :param model_class: Clase del modelo
        :return: Modelo cargado
        """
        checkpoint = torch.load(checkpoint_path, map_location='cpu')
        
        if 'model_config' in checkpoint:
            config = checkpoint['model_config']
            model = model_class(**config)
            model.load_state_dict(checkpoint['model_state_dict'])
        else:
            # Fallback: intentar cargar directamente
            model = model_class(vocab_size=10000, d_model=512, num_heads=8, num_layers=6)
            model.load_state_dict(checkpoint.get('model_state_dict', checkpoint))
        
        print(f"✅ Modelo cargado desde: {checkpoint_path}")
        return model
    
    @staticmethod
    def get_model_summary_table(
        model: CausalTransformer
    ) -> str:
        """
        Genera tabla resumen del modelo.
        
        :param model: Modelo
        :return: Tabla en formato string
        """
        params = count_parameters(model)
        memory = estimate_memory_usage(
            1, 128, model.d_model,
            model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
            len(model.blocks), model.vocab_size
        )
        
        table = f"""
╔═══════════════════════════════════════════════════════════════╗
║                    MODEL SUMMARY TABLE                        ║
╠═══════════════════════════════════════════════════════════════╣
║ Parameter                                 │ Value              ║
╠═══════════════════════════════════════════════════════════════╣
║ Vocabulary Size                          │ {model.vocab_size:>20} ║
║ Model Dimension (d_model)                │ {model.d_model:>20} ║
║ Number of Layers                          │ {len(model.blocks):>20} ║
║ Number of Attention Heads                 │ {model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8:>20} ║
║ Total Parameters                          │ {params['total_millions']:>18.2f}M ║
║ Trainable Parameters                      │ {params['trainable_millions']:>18.2f}M ║
║ Estimated Memory (inference)              │ {memory['total_gb']:>18.2f} GB ║
║ Model Weights Size                        │ {memory['model_weights_gb']:>18.2f} GB ║
╚═══════════════════════════════════════════════════════════════╝
"""
        return table
    
    @staticmethod
    def validate_model_consistency(
        model: CausalTransformer
    ) -> dict:
        """
        Valida consistencia del modelo.
        
        :param model: Modelo
        :return: Resultados de validación
        """
        issues = []
        warnings = []
        
        # Verificar que todas las capas tienen el mismo d_model
        d_models = set()
        for block in model.blocks:
            if hasattr(block, 'attention') and hasattr(block.attention, 'd_model'):
                d_models.add(block.attention.d_model)
        
        if len(d_models) > 1:
            issues.append(f'Inconsistencia en d_model: {d_models}')
        
        # Verificar shapes de embeddings
        if model.token_embedding.embedding_dim != model.d_model:
            issues.append(
                f'Embedding dim ({model.token_embedding.embedding_dim}) != d_model ({model.d_model})'
            )
        
        # Verificar número de capas
        if len(model.blocks) == 0:
            issues.append('Modelo no tiene capas')
        
        # Verificar que output tiene el tamaño correcto
        if model.output.out_features != model.vocab_size:
            issues.append(
                f'Output size ({model.output.out_features}) != vocab_size ({model.vocab_size})'
            )
        
        return {
            'valid': len(issues) == 0,
            'issues': issues,
            'warnings': warnings
        }


