class BatchProcessor:
    """
    Procesador avanzado de batches para inferencia eficiente.
    """
    
    @staticmethod
    def create_batch_processor(
        model: CausalTransformer,
        max_batch_size: int = 32,
        dynamic_batching: bool = True
    ) -> callable:
        """
        Crea procesador de batches.
        
        :param model: Modelo
        :param max_batch_size: Tamaño máximo de batch
        :param dynamic_batching: Si True, agrupa requests dinámicamente
        :return: Función de procesamiento por batch
        """
        class Processor:
            def __init__(self, model, max_batch, dynamic):
                self.model = model
                self.max_batch = max_batch
                self.dynamic = dynamic
                self.queue = []
                self.model.eval()
            
            def process(self, inputs: List[torch.Tensor]) -> List[torch.Tensor]:
                """Procesa lista de inputs en batches."""
                results = []
                
                # Agrupar en batches
                batches = []
                current_batch = []
                current_size = 0
                
                for inp in inputs:
                    batch_size = inp.shape[0]
                    if current_size + batch_size <= self.max_batch:
                        current_batch.append(inp)
                        current_size += batch_size
                    else:
                        if current_batch:
                            batches.append(torch.cat(current_batch, dim=0))
                        current_batch = [inp]
                        current_size = batch_size
                
                if current_batch:
                    batches.append(torch.cat(current_batch, dim=0))
                
                # Procesar cada batch
                with torch.no_grad():
                    for batch in batches:
                        output = self.model(batch)
                        # Split resultados
                        batch_results = torch.split(output, [inp.shape[0] for inp in current_batch])
                        results.extend(batch_results)
                
                return results
        
        return Processor(model, max_batch_size, dynamic_batching).process


class ModelCacheManager:
    """
    Gestor de cache para modelos y resultados.
    """
    
    @staticmethod
    def create_cache(
        cache_size: int = 1000,
        cache_type: str = 'lru'
    ) -> dict:
        """
        Crea sistema de cache.
        
        :param cache_size: Tamaño del cache
        :param cache_type: Tipo ('lru', 'fifo')
        :return: Sistema de cache
        """
        class Cache:
            def __init__(self, size, ctype):
                self.size = size
                self.ctype = ctype
                self.cache = {}
                self.order = []
            
            def get(self, key: str):
                """Obtiene valor del cache."""
                if key in self.cache:
                    if self.ctype == 'lru':
                        self.order.remove(key)
                        self.order.append(key)
                    return self.cache[key]
                return None
            
            def put(self, key: str, value):
                """Guarda valor en cache."""
                if key in self.cache:
                    if self.ctype == 'lru':
                        self.order.remove(key)
                else:
                    if len(self.cache) >= self.size:
                        # Eliminar más antiguo
                        oldest = self.order.pop(0) if self.order else next(iter(self.cache))
                        del self.cache[oldest]
                
                self.cache[key] = value
                self.order.append(key)
            
            def stats(self) -> dict:
                """Estadísticas del cache."""
                return {
                    'size': len(self.cache),
                    'max_size': self.size,
                    'hit_rate': 0,  # Se calcularía con tracking
                    'type': self.ctype
                }
        
        return Cache(cache_size, cache_type)


class ModelExperimentTracker:
    """
    Tracker avanzado de experimentos con versionado.
    """
    
    @staticmethod
    def create_experiment(
        experiment_name: str,
        config: dict,
        base_dir: str = './experiments'
    ) -> object:
        """
        Crea nuevo experimento.
        
        :param experiment_name: Nombre del experimento
        :param config: Configuración
        :param base_dir: Directorio base
        :return: Objeto de experimento
        """
        import os
        from datetime import datetime
        import json
        
        os.makedirs(base_dir, exist_ok=True)
        
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        exp_dir = os.path.join(base_dir, f"{experiment_name}_{timestamp}")
        os.makedirs(exp_dir, exist_ok=True)
        
        class Experiment:
            def __init__(self, name, config, directory):
                self.name = name
                self.config = config
                self.directory = directory
                self.metrics = {}
                self.artifacts = []
                
                # Guardar config
                with open(os.path.join(directory, 'config.json'), 'w') as f:
                    json.dump(config, f, indent=2)
            
            def log_metric(self, name: str, value: float, step: int = None):
                """Registra métrica."""
                if name not in self.metrics:
                    self.metrics[name] = []
                self.metrics[name].append({
                    'value': value,
                    'step': step,
                    'timestamp': datetime.now().isoformat()
                })
            
            def save_model(self, model: CausalTransformer, name: str = 'model'):
                """Guarda modelo."""
                path = os.path.join(self.directory, f'{name}.pt')
                torch.save({
                    'model_state_dict': model.state_dict(),
                    'config': self.config
                }, path)
                self.artifacts.append(path)
                print(f"✅ Modelo guardado: {path}")
            
            def save_results(self):
                """Guarda resultados."""
                results_path = os.path.join(self.directory, 'results.json')
                results = {
                    'metrics': self.metrics,
                    'artifacts': self.artifacts,
                    'config': self.config
                }
                with open(results_path, 'w') as f:
                    json.dump(results, f, indent=2)
                print(f"✅ Resultados guardados: {results_path}")
        
        return Experiment(experiment_name, config, exp_dir)


class ModelMemoryAnalyzer:
    """
    Analizador avanzado de memoria.
    """
    
    @staticmethod
    def analyze_memory_breakdown(
        model: CausalTransformer,
        batch_size: int = 1,
        seq_len: int = 128
    ) -> dict:
        """
        Análisis detallado de uso de memoria.
        
        :param model: Modelo
        :param batch_size: Tamaño de batch
        :param seq_len: Longitud de secuencia
        :return: Breakdown de memoria
        """
        breakdown = {
            'model_weights': 0,
            'embeddings': 0,
            'attention': 0,
            'ffn': 0,
            'activations': 0,
            'gradients': 0,
            'optimizer_states': 0,
            'total': 0
        }
        
        # Peso del modelo
        total_params = sum(p.numel() for p in model.parameters())
        breakdown['model_weights'] = total_params * 4 / (1024 ** 3)  # float32
        
        # Embeddings
        if hasattr(model, 'token_embedding'):
            emb_params = sum(p.numel() for p in model.token_embedding.parameters())
            breakdown['embeddings'] = emb_params * 4 / (1024 ** 3)
        
        # Atención (estimación)
        n_heads = model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8
        d_model = model.d_model
        attn_params = len(model.blocks) * (d_model * d_model * 4)  # Q, K, V, O
        breakdown['attention'] = attn_params * 4 / (1024 ** 3)
        
        # FFN (estimación)
        if hasattr(model.blocks[0], 'ffn'):
            ffn_params = sum(p.numel() for p in model.blocks[0].ffn.parameters()) * len(model.blocks)
            breakdown['ffn'] = ffn_params * 4 / (1024 ** 3)
        
        # Activaciones (estimación)
        activation_mem = batch_size * seq_len * d_model * len(model.blocks) * 4 / (1024 ** 3)
        breakdown['activations'] = activation_mem
        
        # Gradientes (mismo tamaño que pesos en entrenamiento)
        breakdown['gradients'] = breakdown['model_weights']
        
        # Optimizer states (Adam necesita 2x para momentum y variance)
        breakdown['optimizer_states'] = breakdown['model_weights'] * 2
        
        breakdown['total'] = sum(breakdown.values())
        
        return breakdown
    
    @staticmethod
    def get_memory_recommendations(
        breakdown: dict,
        available_memory_gb: float = 16.0
    ) -> List[str]:
        """
        Obtiene recomendaciones basadas en uso de memoria.
        
        :param breakdown: Breakdown de memoria
        :param available_memory_gb: Memoria disponible
        :return: Lista de recomendaciones
        """
        recommendations = []
        total = breakdown['total']
        
        if total > available_memory_gb:
            recommendations.append(f'⚠️ Memoria requerida ({total:.2f} GB) excede disponible ({available_memory_gb} GB)')
            recommendations.append('   - Reducir batch size')
            recommendations.append('   - Usar gradient checkpointing')
            recommendations.append('   - Usar mixed precision (FP16)')
        
        if breakdown['activations'] > breakdown['model_weights']:
            recommendations.append('💡 Activaciones usan más memoria que pesos')
            recommendations.append('   - Considerar gradient checkpointing')
            recommendations.append('   - Reducir secuencia máxima')
        
        if breakdown['optimizer_states'] > breakdown['model_weights'] * 2:
            recommendations.append('💡 Optimizer states ocupan mucho espacio')
            recommendations.append('   - Considerar optimizadores más eficientes')
        
        return recommendations


class ModelTestingSuite:
    """
    Suite completa de testing para modelos.
    """
    
    @staticmethod
    def run_all_tests(
        model: CausalTransformer,
        test_input: torch.Tensor
    ) -> dict:
        """
        Ejecuta todos los tests.
        
        :param model: Modelo
        :param test_input: Input de prueba
        :return: Resultados de tests
        """
        results = {
            'forward_pass': False,
            'backward_pass': False,
            'gradient_check': False,
            'memory_check': False,
            'output_shape_check': False,
            'errors': []
        }
        
        # Test 1: Forward pass
        try:
            model.eval()
            with torch.no_grad():
                output = model(test_input)
            results['forward_pass'] = True
            results['output_shape'] = list(output.shape)
        except Exception as e:
            results['errors'].append(f'Forward pass failed: {e}')
        
        # Test 2: Backward pass
        try:
            model.train()
            output = model(test_input)
            loss = output.sum()
            loss.backward()
            results['backward_pass'] = True
        except Exception as e:
            results['errors'].append(f'Backward pass failed: {e}')
        
        # Test 3: Gradient check
        try:
            grad_norms = [p.grad.norm().item() for p in model.parameters() if p.grad is not None]
            if grad_norms:
                results['gradient_check'] = True
                results['avg_grad_norm'] = sum(grad_norms) / len(grad_norms)
        except Exception as e:
            results['errors'].append(f'Gradient check failed: {e}')
        
        # Test 4: Memory check
        try:
            memory = estimate_memory_usage(
                test_input.shape[0],
                test_input.shape[1],
                model.d_model,
                model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
                len(model.blocks),
                model.vocab_size
            )
            results['memory_check'] = True
            results['memory_gb'] = memory['total_gb']
        except Exception as e:
            results['errors'].append(f'Memory check failed: {e}')
        
        # Test 5: Output shape check
        try:
            if results['forward_pass']:
                expected_shape = (test_input.shape[0], test_input.shape[1], model.vocab_size)
                if results['output_shape'] == list(expected_shape):
                    results['output_shape_check'] = True
                else:
                    results['errors'].append(
                        f'Output shape mismatch: expected {expected_shape}, got {results["output_shape"]}'
                    )
        except Exception as e:
            results['errors'].append(f'Output shape check failed: {e}')
        
        results['all_passed'] = all([
            results['forward_pass'],
            results['backward_pass'],
            results['gradient_check'],
            results['memory_check'],
            results['output_shape_check']
        ])
        
        return results


class ModelSerializationManager:
    """
    Gestor avanzado de serialización/deserialización.
    """
    
    @staticmethod
    def serialize_model(
        model: CausalTransformer,
        include_optimizer: bool = False,
        optimizer=None,
        include_scheduler: bool = False,
        scheduler=None
    ) -> dict:
        """
        Serializa modelo completo.
        
        :param model: Modelo
        :param include_optimizer: Si True, incluye optimizer
        :param optimizer: Optimizer (opcional)
        :param include_scheduler: Si True, incluye scheduler
        :param scheduler: Scheduler (opcional)
        :return: Datos serializados
        """
        serialized = {
            'model_state_dict': model.state_dict(),
            'model_config': {
                'vocab_size': model.vocab_size,
                'd_model': model.d_model,
                'n_layers': len(model.blocks),
                'n_heads': model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8
            },
            'version': __version__
        }
        
        if include_optimizer and optimizer:
            serialized['optimizer_state_dict'] = optimizer.state_dict()
        
        if include_scheduler and scheduler:
            serialized['scheduler_state_dict'] = scheduler.state_dict()
        
        return serialized
    
    @staticmethod
    def deserialize_model(
        data: dict,
        model_class: type = CausalTransformer
    ) -> CausalTransformer:
        """
        Deserializa modelo.
        
        :param data: Datos serializados
        :param model_class: Clase del modelo
        :return: Modelo deserializado
        """
        config = data['model_config']
        model = model_class(**config)
        model.load_state_dict(data['model_state_dict'])
        return model


