class ModelOptimizationPipeline:
    """
    Pipeline completo de optimización automatizado.
    """
    
    @staticmethod
    def optimize_pipeline(
        model: CausalTransformer,
        target: str = 'inference',
        optimization_steps: List[str] = None
    ) -> dict:
        """
        Pipeline completo de optimización.
        
        :param model: Modelo
        :param target: Objetivo ('inference', 'training', 'deployment')
        :param optimization_steps: Pasos de optimización (None = auto)
        :return: Modelo optimizado y estadísticas
        """
        if optimization_steps is None:
            if target == 'inference':
                optimization_steps = ['quantization', 'pruning', 'compilation']
            elif target == 'training':
                optimization_steps = ['mixed_precision', 'gradient_checkpointing']
            else:  # deployment
                optimization_steps = ['quantization', 'onnx_export']
        
        optimized_model = model
        stats = {
            'steps_applied': [],
            'original_params': count_parameters(model)['total'],
            'optimization_gains': {}
        }
        
        for step in optimization_steps:
            if step == 'quantization':
                quantizer = AdvancedQuantization()
                optimized_model = quantizer.quantize_model_dynamic(optimized_model)
                stats['steps_applied'].append('quantization')
                stats['optimization_gains']['quantization'] = '~4x size reduction'
            
            elif step == 'pruning':
                pruner = AdvancedPruning()
                optimized_model = pruner.magnitude_pruning(optimized_model, pruning_ratio=0.1)
                stats['steps_applied'].append('pruning')
                stats['optimization_gains']['pruning'] = '~10% sparsity'
            
            elif step == 'compilation':
                try:
                    optimized_model = torch.compile(optimized_model)
                    stats['steps_applied'].append('torch_compile')
                    stats['optimization_gains']['compilation'] = '~20% speedup'
                except Exception as e:
                    stats['steps_applied'].append(f'compilation_failed: {e}')
        
        stats['final_params'] = count_parameters(optimized_model)['total']
        
        print(f"✅ Pipeline de optimización completado:")
        print(f"   Pasos aplicados: {', '.join(stats['steps_applied'])}")
        print(f"   Objetivo: {target}")
        
        return {
            'optimized_model': optimized_model,
            'stats': stats
        }


class ModelRecommendationEngine:
    """
    Motor de recomendaciones inteligentes para modelos.
    """
    
    @staticmethod
    def get_recommendations(
        model: CausalTransformer,
        use_case: str = 'general',
        constraints: dict = None
    ) -> dict:
        """
        Obtiene recomendaciones personalizadas.
        
        :param model: Modelo
        :param use_case: Caso de uso ('general', 'production', 'research', 'deployment')
        :param constraints: Restricciones (memoria, latencia, etc.)
        :return: Recomendaciones
        """
        recommendations = {
            'use_case': use_case,
            'recommendations': [],
            'optimizations': [],
            'warnings': []
        }
        
        params = count_parameters(model)
        memory = estimate_memory_usage(
            1, 128, model.d_model,
            model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
            len(model.blocks), model.vocab_size
        )
        
        if use_case == 'production':
            if memory['total_gb'] > 8:
                recommendations['optimizations'].append({
                    'type': 'quantization',
                    'priority': 'high',
                    'reason': 'Modelo grande para producción',
                    'impact': 'Reducir tamaño 4x'
                })
            
            recommendations['recommendations'].append('Usar ModelOptimizerPro con nivel "aggressive"')
            recommendations['recommendations'].append('Implementar health monitoring')
            recommendations['recommendations'].append('Configurar A/B testing')
        
        elif use_case == 'deployment':
            recommendations['optimizations'].append({
                'type': 'onnx_export',
                'priority': 'high',
                'reason': 'Mejor compatibilidad',
                'impact': 'Exportar a ONNX optimizado'
            })
            recommendations['recommendations'].append('Usar ModelServingOptimizer')
            recommendations['recommendations'].append('Implementar batch processing')
        
        elif use_case == 'research':
            recommendations['recommendations'].append('Usar TrainingMonitorPro para tracking')
            recommendations['recommendations'].append('Configurar experiment tracking')
            recommendations['recommendations'].append('Usar ModelProfiler para análisis')
        
        if constraints:
            if constraints.get('max_memory_gb', float('inf')) < memory['total_gb']:
                recommendations['warnings'].append(
                    f'Memoria requerida ({memory["total_gb"]:.2f} GB) excede límite'
                )
                recommendations['optimizations'].append({
                    'type': 'gradient_checkpointing',
                    'priority': 'critical',
                    'reason': 'Reducir memoria de activaciones'
                })
        
        return recommendations


class ModelMetricsAggregator:
    """
    Agregador de métricas para análisis comparativo.
    """
    
    @staticmethod
    def aggregate_metrics(
        models: List[CausalTransformer],
        model_names: List[str],
        test_inputs: List[torch.Tensor]
    ) -> dict:
        """
        Agrega métricas de múltiples modelos.
        
        :param models: Lista de modelos
        :param model_names: Nombres
        :param test_inputs: Inputs de prueba
        :return: Métricas agregadas
        """
        aggregated = {
            'models': [],
            'summary': {}
        }
        
        for model, name in zip(models, model_names):
            metrics = {
                'name': name,
                'parameters': count_parameters(model),
                'memory': estimate_memory_usage(
                    1, 128, model.d_model,
                    model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
                    len(model.blocks), model.vocab_size
                )
            }
            
            # Performance
            import time
            model.eval()
            with torch.no_grad():
                start = time.time()
                _ = model(test_inputs[0])
                metrics['inference_time_ms'] = (time.time() - start) * 1000
            
            aggregated['models'].append(metrics)
        
        # Summary
        if aggregated['models']:
            aggregated['summary'] = {
                'avg_parameters': sum(m['parameters']['total'] for m in aggregated['models']) / len(aggregated['models']),
                'avg_memory_gb': sum(m['memory']['total_gb'] for m in aggregated['models']) / len(aggregated['models']),
                'avg_inference_ms': sum(m['inference_time_ms'] for m in aggregated['models']) / len(aggregated['models']),
                'total_models': len(aggregated['models'])
            }
        
        return aggregated


class ModelConfigurationBuilder:
    """
    Constructor de configuraciones optimizadas.
    """
    
    @staticmethod
    def build_configuration(
        requirements: dict,
        preset: str = None
    ) -> dict:
        """
        Construye configuración basada en requisitos.
        
        :param requirements: Requisitos (memory_gb, latency_ms, accuracy_target)
        :param preset: Preset opcional
        :return: Configuración optimizada
        """
        if preset:
            recipe = TrainingRecipe.get_recipe(preset)
            return recipe.get('config', {})
        
        # Construir desde requisitos
        config = {
            'vocab_size': requirements.get('vocab_size', 30000),
            'd_model': 512,
            'num_heads': 8,
            'num_layers': 6,
            'd_ff': 2048,
            'dropout': 0.1
        }
        
        # Ajustar según memoria disponible
        if 'max_memory_gb' in requirements:
            max_mem = requirements['max_memory_gb']
            if max_mem < 4:
                config['d_model'] = 256
                config['num_layers'] = 4
            elif max_mem < 8:
                config['d_model'] = 384
                config['num_layers'] = 5
        
        # Ajustar según latencia requerida
        if 'max_latency_ms' in requirements:
            max_lat = requirements['max_latency_ms']
            if max_lat < 50:
                config['num_layers'] = min(config['num_layers'], 4)
                config['d_model'] = min(config['d_model'], 384)
        
        return config
    
    @staticmethod
    def validate_configuration(
        config: dict
    ) -> Tuple[bool, List[str], List[str]]:
        """
        Valida configuración.
        
        :param config: Configuración
        :return: (is_valid, errors, warnings)
        """
        errors = []
        warnings = []
        
        # Validaciones básicas
        if config.get('d_model', 0) % config.get('num_heads', 1) != 0:
            errors.append('d_model debe ser divisible por num_heads')
        
        if config.get('vocab_size', 0) <= 0:
            errors.append('vocab_size debe ser positivo')
        
        if config.get('num_layers', 0) <= 0:
            errors.append('num_layers debe ser positivo')
        
        # Warnings
        if config.get('d_model', 0) > 1024:
            warnings.append('d_model muy grande, puede causar problemas de memoria')
        
        if config.get('num_layers', 0) > 24:
            warnings.append('num_layers muy grande, puede causar problemas de entrenamiento')
        
        return len(errors) == 0, errors, warnings


class ModelValidationSuite:
    """
    Suite completa de validación para modelos.
    """
    
    @staticmethod
    def run_full_validation(
        model: CausalTransformer,
        test_input: torch.Tensor,
        test_target: torch.Tensor = None
    ) -> dict:
        """
        Ejecuta validación completa.
        
        :param model: Modelo
        :param test_input: Input de prueba
        :param test_target: Target de prueba (opcional)
        :return: Resultados de validación
        """
        results = {
            'architecture': {},
            'forward_pass': {},
            'backward_pass': {},
            'consistency': {},
            'performance': {},
            'all_passed': False
        }
        
        # Validación de arquitectura
        arch_validation = AdvancedModelUtilities.validate_model_consistency(model)
        results['architecture'] = arch_validation
        
        # Validación de forward pass
        debug_info = ModelDebugger.debug_forward_pass(model, test_input, verbose=False)
        results['forward_pass'] = {
            'success': 'output' in debug_info and 'error' not in debug_info.get('output', {}),
            'output_shape': debug_info.get('output', {}).get('shape', [])
        }
        
        # Validación de backward pass
        if test_target is not None:
            grad_info = ModelDebugger.check_gradient_flow(model, test_input, test_target)
            results['backward_pass'] = {
                'success': len(grad_info.get('layers', [])) > 0,
                'grad_norms': [l['grad_norm'] for l in grad_info.get('layers', [])]
            }
        
        # Validación de consistencia
        inspector_result = ModelInspector.inspect_layer_weights(model)
        has_nan = any(layer.get('has_nan', False) for layer in inspector_result.values())
        has_inf = any(layer.get('has_inf', False) for layer in inspector_result.values())
        results['consistency'] = {
            'no_nan': not has_nan,
            'no_inf': not has_inf,
            'layers_checked': len(inspector_result)
        }
        
        # Validación de performance
        test_results = ModelTestingSuite.run_all_tests(model, test_input)
        results['performance'] = test_results
        
        # Resultado final
        results['all_passed'] = (
            arch_validation['valid'] and
            results['forward_pass']['success'] and
            results['backward_pass'].get('success', True) and
            results['consistency']['no_nan'] and
            results['consistency']['no_inf'] and
            test_results.get('all_passed', False)
        )
        
        return results


