class ModelAutoTuner:
    """
    Tuner automático de hiperparámetros con múltiples estrategias.
    """
    
    @staticmethod
    def auto_tune(
        model_class: type,
        objective_fn: callable,
        search_space: dict,
        method: str = 'random',
        n_trials: int = 20
    ) -> dict:
        """
        Tune automático de hiperparámetros.
        
        :param model_class: Clase del modelo
        :param objective_fn: Función objetivo
        :param search_space: Espacio de búsqueda
        :param method: Método ('random', 'grid', 'bayesian')
        :param n_trials: Número de trials
        :return: Mejores hiperparámetros
        """
        if method == 'random':
            return HyperparameterTuner.random_search(search_space, objective_fn, n_trials)
        elif method == 'grid':
            return HyperparameterTuner.grid_search(search_space, objective_fn, n_trials)
        else:
            # Bayesian optimization (simplificado)
            print(f"⚠️ Bayesian optimization requiere bibliotecas adicionales")
            return HyperparameterTuner.random_search(search_space, objective_fn, n_trials)


class ModelDiagnosticSystem:
    """
    Sistema de diagnóstico automático para modelos.
    """
    
    @staticmethod
    def diagnose_model(
        model: CausalTransformer,
        test_input: torch.Tensor,
        test_target: torch.Tensor = None,
        training_history: dict = None
    ) -> dict:
        """
        Diagnóstico completo del modelo.
        
        :param model: Modelo
        :param test_input: Input de prueba
        :param test_target: Target (opcional)
        :param training_history: Historial (opcional)
        :return: Diagnóstico completo
        """
        diagnosis = {
            'model_health': 'unknown',
            'issues': [],
            'recommendations': [],
            'metrics': {}
        }
        
        # Validación básica
        validation = ModelValidationSuite.run_full_validation(model, test_input, test_target)
        if not validation['all_passed']:
            diagnosis['model_health'] = 'unhealthy'
            diagnosis['issues'].append('Validación falló')
        else:
            diagnosis['model_health'] = 'healthy'
        
        # Diagnóstico de entrenamiento
        if training_history:
            training_diagnosis = TroubleshootingGuide.diagnose_training_issues(model, training_history)
            diagnosis['issues'].extend(training_diagnosis.get('issues', []))
            diagnosis['recommendations'].extend(training_diagnosis.get('recommendations', []))
        
        # Análisis de memoria
        memory_breakdown = ModelMemoryAnalyzer.analyze_memory_breakdown(model)
        diagnosis['metrics']['memory'] = memory_breakdown
        
        # Recomendaciones de optimización
        recommendations = ModelRecommendationEngine.get_recommendations(
            model, use_case='general'
        )
        diagnosis['recommendations'].extend(recommendations.get('recommendations', []))
        
        return diagnosis


class ModelPerformancePredictor:
    """
    Predictor de performance basado en configuración.
    """
    
    @staticmethod
    def predict_performance(
        config: dict,
        dataset_size: int = 10000,
        batch_size: int = 32
    ) -> dict:
        """
        Predice performance del modelo.
        
        :param config: Configuración del modelo
        :param dataset_size: Tamaño del dataset
        :param batch_size: Tamaño de batch
        :return: Predicciones de performance
        """
        predictions = {
            'estimated_parameters': 0,
            'estimated_memory_gb': 0,
            'estimated_training_time_hours': 0,
            'estimated_inference_time_ms': 0
        }
        
        # Estimar parámetros (simplificado)
        vocab_size = config.get('vocab_size', 30000)
        d_model = config.get('d_model', 512)
        n_layers = config.get('num_layers', 6)
        n_heads = config.get('num_heads', 8)
        d_ff = config.get('d_ff', 2048)
        
        # Estimación aproximada
        embed_params = vocab_size * d_model
        attn_params = n_layers * (4 * d_model * d_model)  # Q, K, V, O
        ffn_params = n_layers * (2 * d_model * d_ff)
        output_params = d_model * vocab_size
        
        total_params = embed_params + attn_params + ffn_params + output_params
        predictions['estimated_parameters'] = total_params
        
        # Estimar memoria
        memory = estimate_memory_usage(
            batch_size, 128, d_model, n_heads, n_layers, vocab_size
        )
        predictions['estimated_memory_gb'] = memory['total_gb']
        
        # Estimar tiempo de entrenamiento (simplificado)
        # Asumir ~1000 samples/segundo en GPU moderna
        samples_per_sec = 1000
        epochs = 10
        training_time_seconds = (dataset_size / batch_size) * epochs / samples_per_sec
        predictions['estimated_training_time_hours'] = training_time_seconds / 3600
        
        # Estimar tiempo de inferencia
        # Asumir ~1000 tokens/segundo
        tokens_per_sec = 1000
        seq_len = 128
        inference_time_seconds = seq_len / tokens_per_sec
        predictions['estimated_inference_time_ms'] = inference_time_seconds * 1000
        
        return predictions


class ModelComparisonDashboard:
    """
    Dashboard completo para comparación de modelos.
    """
    
    @staticmethod
    def create_comparison_dashboard(
        comparison_data: dict,
        save_path: Optional[str] = None
    ):
        """
        Crea dashboard de comparación.
        
        :param comparison_data: Datos de comparación
        :param save_path: Ruta para guardar
        """
        try:
            import matplotlib.pyplot as plt
        except ImportError:
            print("⚠️ matplotlib no está instalado")
            return
        
        fig = plt.figure(figsize=(20, 12))
        
        if 'models' in comparison_data:
            models = comparison_data['models']
            names = [m['name'] for m in models]
            
            # Parámetros
            ax1 = plt.subplot(2, 3, 1)
            params = [m.get('parameters', {}).get('total_millions', 0) for m in models]
            ax1.bar(names, params)
            ax1.set_title('Total Parameters (M)')
            ax1.set_ylabel('Parameters (M)')
            ax1.tick_params(axis='x', rotation=45)
            
            # Memoria
            ax2 = plt.subplot(2, 3, 2)
            memory = [m.get('memory_estimate', {}).get('total_gb', 0) for m in models]
            ax2.bar(names, memory, color='orange')
            ax2.set_title('Memory Usage (GB)')
            ax2.set_ylabel('Memory (GB)')
            ax2.tick_params(axis='x', rotation=45)
            
            # Performance
            ax3 = plt.subplot(2, 3, 3)
            perf = [m.get('benchmark', {}).get(1, {}).get('tokens_per_second', 0) for m in models]
            ax3.bar(names, perf, color='green')
            ax3.set_title('Tokens per Second')
            ax3.set_ylabel('Tokens/sec')
            ax3.tick_params(axis='x', rotation=45)
            
            # Perplexity
            ax4 = plt.subplot(2, 3, 4)
            eval_data = [m.get('evaluation', {}) for m in models]
            perplexity = [e.get('perplexity', 0) if isinstance(e.get('perplexity'), (int, float)) else 0 for e in eval_data]
            ax4.bar(names, perplexity, color='red')
            ax4.set_title('Perplexity')
            ax4.set_ylabel('Perplexity')
            ax4.tick_params(axis='x', rotation=45)
            
            # Accuracy
            ax5 = plt.subplot(2, 3, 5)
            accuracy = [e.get('accuracy', 0) if isinstance(e.get('accuracy'), (int, float)) else 0 for e in eval_data]
            ax5.bar(names, accuracy, color='purple')
            ax5.set_title('Accuracy')
            ax5.set_ylabel('Accuracy')
            ax5.tick_params(axis='x', rotation=45)
            
            # Comparación de costos
            ax6 = plt.subplot(2, 3, 6)
            costs = [m.get('cost', {}).get('cost_per_1k_tokens', 0) for m in models]
            ax6.bar(names, costs, color='brown')
            ax6.set_title('Cost per 1K Tokens')
            ax6.set_ylabel('Cost')
            ax6.tick_params(axis='x', rotation=45)
        
        plt.tight_layout()
        
        if save_path:
            plt.savefig(save_path, dpi=300, bbox_inches='tight')
            print(f"✅ Dashboard guardado: {save_path}")
        else:
            plt.show()


class ModelLifecycleManager:
    """
    Gestor completo del ciclo de vida del modelo.
    """
    
    @staticmethod
    def create_lifecycle_manager(
        model: CausalTransformer,
        lifecycle_stages: List[str] = None
    ) -> object:
        """
        Crea gestor de ciclo de vida.
        
        :param model: Modelo
        :param lifecycle_stages: Etapas del ciclo de vida
        :return: Gestor de ciclo de vida
        """
        if lifecycle_stages is None:
            lifecycle_stages = ['development', 'training', 'validation', 'optimization', 'deployment', 'monitoring']
        
        class LifecycleManager:
            def __init__(self, model, stages):
                self.model = model
                self.stages = stages
                self.current_stage = 'development'
                self.history = {}
            
            def transition_to(self, stage: str):
                """Transición a nueva etapa."""
                if stage in self.stages:
                    self.history[self.current_stage] = {
                        'started': True,
                        'completed': True
                    }
                    self.current_stage = stage
                    self.history[stage] = {'started': True}
                    print(f"✅ Transición a etapa: {stage}")
                else:
                    print(f"⚠️ Etapa {stage} no válida")
            
            def get_current_stage_recommendations(self) -> List[str]:
                """Obtiene recomendaciones para etapa actual."""
                recommendations = ModelKnowledgeBase.get_best_practices(self.current_stage)
                return list(recommendations.values()) if recommendations else []
            
            def get_status(self) -> dict:
                """Obtiene estado actual."""
                return {
                    'current_stage': self.current_stage,
                    'stages': self.stages,
                    'history': self.history
                }
        
        return LifecycleManager(model, lifecycle_stages)


class ModelQualityAssurance:
    """
    Sistema de aseguramiento de calidad para modelos.
    """
    
    @staticmethod
    def run_qa_checks(
        model: CausalTransformer,
        test_input: torch.Tensor,
        quality_thresholds: dict = None
    ) -> dict:
        """
        Ejecuta checks de calidad.
        
        :param model: Modelo
        :param test_input: Input de prueba
        :param quality_thresholds: Umbrales de calidad
        :return: Resultados de QA
        """
        if quality_thresholds is None:
            quality_thresholds = {
                'max_memory_gb': 16.0,
                'min_accuracy': 0.5,
                'max_latency_ms': 1000.0,
                'max_perplexity': 100.0
            }
        
        qa_results = {
            'passed': True,
            'checks': {},
            'warnings': [],
            'failures': []
        }
        
        # Check 1: Memoria
        memory = estimate_memory_usage(
            1, 128, model.d_model,
            model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
            len(model.blocks), model.vocab_size
        )
        qa_results['checks']['memory'] = {
            'value': memory['total_gb'],
            'threshold': quality_thresholds['max_memory_gb'],
            'passed': memory['total_gb'] <= quality_thresholds['max_memory_gb']
        }
        if not qa_results['checks']['memory']['passed']:
            qa_results['failures'].append('Memoria excede umbral')
            qa_results['passed'] = False
        
        # Check 2: Latencia
        import time
        model.eval()
        with torch.no_grad():
            start = time.time()
            _ = model(test_input)
            latency_ms = (time.time() - start) * 1000
        
        qa_results['checks']['latency'] = {
            'value': latency_ms,
            'threshold': quality_thresholds['max_latency_ms'],
            'passed': latency_ms <= quality_thresholds['max_latency_ms']
        }
        if not qa_results['checks']['latency']['passed']:
            qa_results['warnings'].append('Latencia alta')
        
        # Check 3: Consistencia
        consistency = AdvancedModelUtilities.validate_model_consistency(model)
        qa_results['checks']['consistency'] = {
            'passed': consistency['valid'],
            'issues': consistency['issues']
        }
        if not consistency['valid']:
            qa_results['failures'].extend(consistency['issues'])
            qa_results['passed'] = False
        
        return qa_results


class ModelReportingSystem:
    """
    Sistema completo de reportes para modelos.
    """
    
    @staticmethod
    def generate_comprehensive_report(
        model: CausalTransformer,
        test_input: torch.Tensor,
        include_plots: bool = True
    ) -> str:
        """
        Genera reporte completo.
        
        :param model: Modelo
        :param test_input: Input de prueba
        :param include_plots: Si True, incluye visualizaciones
        :return: Reporte en markdown
        """
        params = count_parameters(model)
        memory = estimate_memory_usage(
            1, 128, model.d_model,
            model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
            len(model.blocks), model.vocab_size
        )
        
        report = f"""# Reporte Completo del Modelo

## Información General
- **Versión del Módulo**: {__version__}
- **Fecha de Generación**: {__import__('datetime').datetime.now().strftime('%Y-%m-%d %H:%M:%S')}

## Arquitectura
- **Vocab Size**: {model.vocab_size}
- **Model Dimension**: {model.d_model}
- **Number of Layers**: {len(model.blocks)}
- **Number of Heads**: {model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8}

## Estadísticas
### Parámetros
- **Total**: {params['total_millions']:.2f}M
- **Trainable**: {params['trainable_millions']:.2f}M

### Memoria
- **Total Estimada**: {memory['total_gb']:.2f} GB
- **Model Weights**: {memory['model_weights_gb']:.2f} GB
- **Activations**: {memory['activations_gb']:.2f} GB

## Validación
"""
        # Agregar resultados de validación
        validation = ModelValidationSuite.run_full_validation(model, test_input)
        report += f"""
- **Estado General**: {'✅ PASSED' if validation['all_passed'] else '❌ FAILED'}
- **Forward Pass**: {'✅' if validation['forward_pass']['success'] else '❌'}
- **Backward Pass**: {'✅' if validation['backward_pass'].get('success', False) else '❌'}
- **Consistencia**: {'✅' if validation['consistency']['no_nan'] and validation['consistency']['no_inf'] else '❌'}

## Recomendaciones
"""
        # Agregar recomendaciones
        recommendations = ModelRecommendationEngine.get_recommendations(model)
        for rec in recommendations.get('recommendations', [])[:5]:
            report += f"- {rec}\n"
        
        report += "\n## Próximos Pasos\n"
        report += "- Revisar validaciones fallidas\n"
        report += "- Aplicar recomendaciones de optimización\n"
        report += "- Ejecutar tests completos\n"
        
        return report


