class ModelUtilitySuite:
    """
    Suite completa de utilidades para operaciones comunes.
    """
    
    @staticmethod
    def clone_model(
        model: CausalTransformer
    ) -> CausalTransformer:
        """
        Clona modelo completamente.
        
        :param model: Modelo a clonar
        :return: Modelo clonado
        """
        config = {
            'vocab_size': model.vocab_size,
            'd_model': model.d_model,
            'num_heads': model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
            'num_layers': len(model.blocks),
            'd_ff': model.blocks[0].ffn.linear1.out_features if hasattr(model.blocks[0], 'ffn') else 2048,
            'max_seq_length': getattr(model.pos_encoding, 'max_seq_len', None) or 512,
            'dropout': 0.1
        }
        
        cloned = CausalTransformer(**config)
        cloned.load_state_dict(model.state_dict())
        
        print("✅ Modelo clonado exitosamente")
        return cloned
    
    @staticmethod
    def get_model_info(
        model: CausalTransformer
    ) -> dict:
        """
        Obtiene información completa del modelo.
        
        :param model: Modelo
        :return: Información completa
        """
        params = count_parameters(model)
        memory = estimate_memory_usage(
            1, 128, model.d_model,
            model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
            len(model.blocks), model.vocab_size
        )
        
        return {
            'architecture': {
                'vocab_size': model.vocab_size,
                'd_model': model.d_model,
                'num_layers': len(model.blocks),
                'num_heads': model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
                'd_ff': model.blocks[0].ffn.linear1.out_features if hasattr(model.blocks[0], 'ffn') else 2048
            },
            'parameters': params,
            'memory': memory,
            'device': next(model.parameters()).device if next(model.parameters(), None) else 'cpu',
            'dtype': next(model.parameters()).dtype if next(model.parameters(), None) else None
        }


class ModelBatchInferenceOptimizer:
    """
    Optimizador avanzado para inferencia por lotes.
    """
    
    @staticmethod
    def optimize_batch_inference(
        model: CausalTransformer,
        batch_sizes: List[int] = [1, 4, 8, 16, 32],
        seq_lengths: List[int] = [64, 128, 256, 512]
    ) -> dict:
        """
        Optimiza configuración de batch inference.
        
        :param model: Modelo
        :param batch_sizes: Tamaños de batch a probar
        :param seq_lengths: Longitudes de secuencia a probar
        :return: Configuración óptima
        """
        results = {}
        
        for batch_size in batch_sizes:
            for seq_len in seq_lengths:
                try:
                    # Estimar memoria
                    memory = estimate_memory_usage(
                        batch_size, seq_len, model.d_model,
                        model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
                        len(model.blocks), model.vocab_size
                    )
                    
                    # Estimar throughput
                    tokens_per_batch = batch_size * seq_len
                    
                    results[f'batch_{batch_size}_seq_{seq_len}'] = {
                        'batch_size': batch_size,
                        'seq_len': seq_len,
                        'memory_gb': memory['total_gb'],
                        'tokens_per_batch': tokens_per_batch,
                        'feasible': memory['total_gb'] < 16.0  # Asumir 16GB disponible
                    }
                except Exception as e:
                    results[f'batch_{batch_size}_seq_{seq_len}'] = {
                        'error': str(e),
                        'feasible': False
                    }
        
        # Encontrar configuración óptima
        feasible_configs = {k: v for k, v in results.items() if v.get('feasible', False)}
        
        if feasible_configs:
            # Maximizar tokens por batch
            optimal = max(feasible_configs.items(), key=lambda x: x[1].get('tokens_per_batch', 0))
            return {
                'optimal_config': optimal[1],
                'all_configs': results,
                'recommendation': f"Usar batch_size={optimal[1]['batch_size']}, seq_len={optimal[1]['seq_len']}"
            }
        else:
            return {
                'optimal_config': None,
                'all_configs': results,
                'recommendation': 'Reducir batch_size o seq_len, o usar optimizaciones de memoria'
            }


class ModelTrainingAssistant:
    """
    Asistente inteligente para entrenamiento.
    """
    
    @staticmethod
    def create_training_plan(
        model: CausalTransformer,
        dataset_size: int,
        available_memory_gb: float = 16.0,
        training_time_hours: float = None
    ) -> dict:
        """
        Crea plan de entrenamiento optimizado.
        
        :param model: Modelo
        :param dataset_size: Tamaño del dataset
        :param available_memory_gb: Memoria disponible
        :param training_time_hours: Tiempo disponible (opcional)
        :return: Plan de entrenamiento
        """
        memory = estimate_memory_usage(
            1, 128, model.d_model,
            model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
            len(model.blocks), model.vocab_size
        )
        
        plan = {
            'recommended_batch_size': 8,
            'recommended_learning_rate': 2e-4,
            'recommended_epochs': 10,
            'estimated_training_time': 0,
            'optimizations': []
        }
        
        # Ajustar batch size según memoria
        if memory['total_gb'] > available_memory_gb * 0.8:
            plan['recommended_batch_size'] = 4
            plan['optimizations'].append('Reducir batch size a 4')
            plan['optimizations'].append('Usar gradient accumulation')
        elif memory['total_gb'] < available_memory_gb * 0.5:
            plan['recommended_batch_size'] = 16
            plan['optimizations'].append('Aumentar batch size a 16')
        
        # Ajustar learning rate según tamaño de modelo
        params = count_parameters(model)
        if params['total_millions'] > 100:
            plan['recommended_learning_rate'] = 1e-4
        elif params['total_millions'] < 10:
            plan['recommended_learning_rate'] = 3e-4
        
        # Estimar tiempo
        samples_per_sec = 1000  # Estimación
        steps_per_epoch = dataset_size / plan['recommended_batch_size']
        time_per_epoch = steps_per_epoch / samples_per_sec / 3600  # horas
        plan['estimated_training_time'] = time_per_epoch * plan['recommended_epochs']
        
        # Ajustar epochs si hay restricción de tiempo
        if training_time_hours and plan['estimated_training_time'] > training_time_hours:
            plan['recommended_epochs'] = int(training_time_hours / time_per_epoch)
            plan['optimizations'].append(f'Reducir epochs a {plan["recommended_epochs"]} por tiempo limitado')
        
        return plan


