class IntelligentCacheManager:
    """
    Gestor de caché inteligente para modelos.
    """
    
    @staticmethod
    def create_smart_cache(
        max_size: int = 1000,
        eviction_policy: str = 'lru'
    ):
        """
        Crea sistema de caché inteligente.
        
        :param max_size: Tamaño máximo del caché
        :param eviction_policy: Política de evicción ('lru', 'lfu', 'fifo')
        :return: Sistema de caché
        """
        class SmartCache:
            def __init__(self, max_size, eviction_policy):
                self.max_size = max_size
                self.eviction_policy = eviction_policy
                self.cache = {}
                self.access_times = {}
                self.access_counts = {}
                
            def get(self, key):
                """Obtiene valor del caché."""
                if key in self.cache:
                    self.access_times[key] = __import__('time').time()
                    self.access_counts[key] = self.access_counts.get(key, 0) + 1
                    return self.cache[key]
                return None
            
            def put(self, key, value):
                """Agrega valor al caché."""
                if len(self.cache) >= self.max_size:
                    self._evict()
                self.cache[key] = value
                self.access_times[key] = __import__('time').time()
                self.access_counts[key] = 0
            
            def _evict(self):
                """Evicta entrada según política."""
                if self.eviction_policy == 'lru':
                    # Least Recently Used
                    key_to_remove = min(self.access_times.items(), key=lambda x: x[1])[0]
                elif self.eviction_policy == 'lfu':
                    # Least Frequently Used
                    key_to_remove = min(self.access_counts.items(), key=lambda x: x[1])[0]
                else:  # FIFO
                    key_to_remove = min(self.access_times.items(), key=lambda x: x[1])[0]
                
                del self.cache[key_to_remove]
                del self.access_times[key_to_remove]
                if key_to_remove in self.access_counts:
                    del self.access_counts[key_to_remove]
            
            def get_stats(self):
                """Obtiene estadísticas del caché."""
                return {
                    'size': len(self.cache),
                    'max_size': self.max_size,
                    'hit_rate': 0.0,  # Calcular en producción
                    'eviction_policy': self.eviction_policy
                }
        
        return SmartCache(max_size, eviction_policy)


class AdaptiveOptimizer:
    """
    Optimizador adaptativo que ajusta hiperparámetros automáticamente.
    """
    
    @staticmethod
    def create_adaptive_training_plan(
        model: CausalTransformer,
        dataset_size: int,
        initial_lr: float = 2e-4,
        target_metric: str = 'loss'
    ) -> dict:
        """
        Crea plan de entrenamiento adaptativo.
        
        :param model: Modelo
        :param dataset_size: Tamaño del dataset
        :param initial_lr: Learning rate inicial
        :param target_metric: Métrica objetivo
        :return: Plan adaptativo
        """
        plan = {
            'learning_rate_schedule': 'cosine_with_warmup',
            'warmup_steps': int(dataset_size * 0.1),
            'total_steps': int(dataset_size * 1.0),
            'initial_lr': initial_lr,
            'min_lr': initial_lr * 0.01,
            'gradient_clipping': 1.0,
            'adaptive_batch_size': True,
            'early_stopping_patience': 5
        }
        
        # Ajustar según tamaño de modelo
        params = count_parameters(model)
        if params['total_millions'] > 500:
            plan['gradient_clipping'] = 0.5
            plan['warmup_steps'] = int(dataset_size * 0.2)
        
        return plan
    
    @staticmethod
    def adjust_hyperparameters(
        current_metrics: dict,
        previous_metrics: dict = None
    ) -> dict:
        """
        Ajusta hiperparámetros basado en métricas.
        
        :param current_metrics: Métricas actuales
        :param previous_metrics: Métricas previas
        :return: Ajustes recomendados
        """
        adjustments = {}
        
        if previous_metrics:
            loss_change = current_metrics.get('loss', 0) - previous_metrics.get('loss', 0)
            
            if loss_change > 0.1:  # Loss aumentando
                adjustments['reduce_lr'] = True
                adjustments['lr_factor'] = 0.5
                adjustments['increase_gradient_clipping'] = True
            elif loss_change < -0.05:  # Loss mejorando bien
                adjustments['maintain_lr'] = True
        
        return adjustments


class ModelBenchmarkingSuite:
    """
    Suite completa de benchmarking para modelos.
    """
    
    @staticmethod
    def run_comprehensive_benchmark(
        model: CausalTransformer,
        test_input: torch.Tensor,
        num_runs: int = 10
    ) -> dict:
        """
        Ejecuta benchmark completo.
        
        :param model: Modelo
        :param test_input: Input de prueba
        :param num_runs: Número de ejecuciones
        :return: Resultados de benchmark
        """
        import time
        
        model.eval()
        
        # Warmup
        with torch.no_grad():
            _ = model(test_input)
        
        # Forward pass benchmarks
        forward_times = []
        for _ in range(num_runs):
            start = time.time()
            with torch.no_grad():
                _ = model(test_input)
            forward_times.append(time.time() - start)
        
        # Memory usage
        memory_mb = estimate_memory_usage(
            test_input.shape[0], test_input.shape[1],
            model.d_model,
            model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
            len(model.blocks), model.vocab_size
        )['total_mb']
        
        # Throughput
        avg_time = sum(forward_times) / len(forward_times)
        tokens_per_sec = (test_input.shape[0] * test_input.shape[1]) / avg_time
        
        return {
            'avg_forward_time_ms': avg_time * 1000,
            'min_forward_time_ms': min(forward_times) * 1000,
            'max_forward_time_ms': max(forward_times) * 1000,
            'std_forward_time_ms': __import__('numpy').std(forward_times) * 1000 if len(forward_times) > 1 else 0,
            'tokens_per_second': tokens_per_sec,
            'memory_mb': memory_mb,
            'num_runs': num_runs
        }
    
    @staticmethod
    def compare_models_benchmark(
        models: list,
        model_names: list,
        test_input: torch.Tensor
    ) -> dict:
        """
        Compara múltiples modelos en benchmark.
        
        :param models: Lista de modelos
        :param model_names: Nombres de modelos
        :param test_input: Input de prueba
        :return: Comparación de benchmarks
        """
        results = {}
        
        for model, name in zip(models, model_names):
            benchmark = ModelBenchmarkingSuite.run_comprehensive_benchmark(model, test_input)
            results[name] = benchmark
        
        # Rankings
        fastest = min(results.items(), key=lambda x: x[1]['avg_forward_time_ms'])
        most_efficient = min(results.items(), key=lambda x: x[1]['memory_mb'])
        highest_throughput = max(results.items(), key=lambda x: x[1]['tokens_per_second'])
        
        return {
            'results': results,
            'rankings': {
                'fastest': fastest[0],
                'most_efficient': most_efficient[0],
                'highest_throughput': highest_throughput[0]
            }
        }


class ModelHealthDashboard:
    """
    Dashboard de salud para modelos.
    """
    
    @staticmethod
    def create_health_dashboard(
        model: CausalTransformer,
        test_input: torch.Tensor,
        metrics_history: dict = None
    ) -> dict:
        """
        Crea dashboard de salud completo.
        
        :param model: Modelo
        :param test_input: Input de prueba
        :param metrics_history: Historial de métricas
        :return: Dashboard de salud
        """
        dashboard = {
            'status': 'healthy',
            'checks': {},
            'recommendations': []
        }
        
        # Check 1: Forward pass
        try:
            model.eval()
            with torch.no_grad():
                output = model(test_input)
            dashboard['checks']['forward_pass'] = {
                'status': 'ok',
                'output_shape': list(output.shape)
            }
        except Exception as e:
            dashboard['checks']['forward_pass'] = {
                'status': 'error',
                'error': str(e)
            }
            dashboard['status'] = 'unhealthy'
        
        # Check 2: Memory
        memory = estimate_memory_usage(
            test_input.shape[0], test_input.shape[1],
            model.d_model,
            model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
            len(model.blocks), model.vocab_size
        )
        dashboard['checks']['memory'] = {
            'status': 'ok' if memory['total_gb'] < 16 else 'warning',
            'memory_gb': memory['total_gb']
        }
        
        if memory['total_gb'] > 16:
            dashboard['recommendations'].append('Considerar optimizaciones de memoria')
        
        # Check 3: Performance
        benchmark = ModelBenchmarkingSuite.run_comprehensive_benchmark(model, test_input, num_runs=5)
        dashboard['checks']['performance'] = {
            'status': 'ok' if benchmark['avg_forward_time_ms'] < 1000 else 'warning',
            'latency_ms': benchmark['avg_forward_time_ms'],
            'throughput': benchmark['tokens_per_second']
        }
        
        if benchmark['avg_forward_time_ms'] > 1000:
            dashboard['recommendations'].append('Considerar optimización para inferencia')
        
        # Check 4: Model consistency
        try:
            consistency = AdvancedTesting.test_model_consistency(model, test_input)
            dashboard['checks']['consistency'] = {
                'status': 'ok' if consistency['is_consistent'] else 'warning',
                'max_difference': consistency['max_difference']
            }
        except:
            dashboard['checks']['consistency'] = {'status': 'skipped'}
        
        return dashboard


class ModelExperimentTracker:
    """
    Rastreador avanzado de experimentos.
    """
    
    @staticmethod
    def create_experiment(
        experiment_name: str,
        config: dict,
        base_dir: str = './experiments'
    ) -> dict:
        """
        Crea nuevo experimento.
        
        :param experiment_name: Nombre del experimento
        :param config: Configuración
        :param base_dir: Directorio base
        :return: Información del experimento
        """
        import os
        import json
        from datetime import datetime
        
        experiment_dir = os.path.join(base_dir, experiment_name)
        os.makedirs(experiment_dir, exist_ok=True)
        
        experiment_info = {
            'name': experiment_name,
            'created_at': datetime.now().isoformat(),
            'config': config,
            'directory': experiment_dir,
            'status': 'running'
        }
        
        # Guardar configuración
        config_path = os.path.join(experiment_dir, 'config.json')
        with open(config_path, 'w') as f:
            json.dump(experiment_info, f, indent=2)
        
        return experiment_info
    
    @staticmethod
    def log_metrics(
        experiment_name: str,
        metrics: dict,
        step: int,
        base_dir: str = './experiments'
    ):
        """
        Registra métricas del experimento.
        
        :param experiment_name: Nombre del experimento
        :param metrics: Métricas
        :param step: Paso/época
        :param base_dir: Directorio base
        """
        import os
        import json
        
        experiment_dir = os.path.join(base_dir, experiment_name)
        metrics_file = os.path.join(experiment_dir, 'metrics.jsonl')
        
        log_entry = {
            'step': step,
            'metrics': metrics,
            'timestamp': __import__('datetime').datetime.now().isoformat()
        }
        
        with open(metrics_file, 'a') as f:
            f.write(json.dumps(log_entry) + '\n')


