class ModelProductionReady:
    """
    Verificador de preparación para producción.
    """
    
    @staticmethod
    def check_production_readiness(
        model: CausalTransformer,
        test_input: torch.Tensor
    ) -> dict:
        """
        Verifica si el modelo está listo para producción.
        
        :param model: Modelo a verificar
        :param test_input: Input de prueba
        :return: Resultados de verificación
        """
        checks = {
            'all_passed': True,
            'checks': {},
            'recommendations': []
        }
        
        # Check 1: Model validation
        try:
            validation = ModelValidator.validate_model_config(
                vocab_size=model.vocab_size,
                d_model=model.d_model,
                n_heads=model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
                n_layers=len(model.blocks)
            )
            checks['checks']['validation'] = validation[0]
            if not validation[0]:
                checks['all_passed'] = False
                checks['recommendations'].append('Corregir errores de validación')
        except:
            checks['checks']['validation'] = {'status': 'skipped'}
        
        # Check 2: Performance
        try:
            benchmark = ModelBenchmarkingSuite.run_comprehensive_benchmark(model, test_input)
            checks['checks']['performance'] = {
                'passed': benchmark['avg_forward_time_ms'] < 1000,
                'latency_ms': benchmark['avg_forward_time_ms']
            }
            if benchmark['avg_forward_time_ms'] > 1000:
                checks['recommendations'].append('Optimizar para reducir latencia')
        except:
            checks['checks']['performance'] = {'status': 'skipped'}
        
        # Check 3: Memory
        try:
            memory = estimate_memory_usage(
                test_input.shape[0], test_input.shape[1],
                model.d_model,
                model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
                len(model.blocks), model.vocab_size
            )
            checks['checks']['memory'] = {
                'passed': memory['total_gb'] < 16,
                'memory_gb': memory['total_gb']
            }
            if memory['total_gb'] > 16:
                checks['recommendations'].append('Aplicar optimizaciones de memoria')
        except:
            checks['checks']['memory'] = {'status': 'skipped'}
        
        return checks


