class ArchitectureComparisonEngine:
    """
    Motor de comparación avanzada de arquitecturas.
    """
    
    @staticmethod
    def compare_architectures_comprehensive(
        architectures: list,
        architecture_names: list,
        test_input: torch.Tensor,
        metrics: list = ['params', 'memory', 'latency', 'throughput']
    ) -> dict:
        """
        Compara arquitecturas de forma comprensiva.
        
        :param architectures: Lista de configuraciones de arquitecturas
        :param architecture_names: Nombres de arquitecturas
        :param test_input: Input de prueba
        :param metrics: Métricas a comparar
        :return: Comparación completa
        """
        comparison = {}
        
        for arch_config, name in zip(architectures, architecture_names):
            model = CausalTransformer(**arch_config)
            
            arch_results = {}
            
            if 'params' in metrics:
                params = count_parameters(model)
                arch_results['params'] = params['total_millions']
            
            if 'memory' in metrics:
                memory = estimate_memory_usage(
                    test_input.shape[0], test_input.shape[1],
                    arch_config['d_model'],
                    arch_config['n_heads'],
                    arch_config['n_layers'],
                    arch_config['vocab_size']
                )
                arch_results['memory_gb'] = memory['total_gb']
            
            if 'latency' in metrics or 'throughput' in metrics:
                benchmark = ModelBenchmarkingSuite.run_comprehensive_benchmark(
                    model, test_input, num_runs=5
                )
                if 'latency' in metrics:
                    arch_results['latency_ms'] = benchmark['avg_forward_time_ms']
                if 'throughput' in metrics:
                    arch_results['throughput'] = benchmark['tokens_per_second']
            
            comparison[name] = {
                'config': arch_config,
                'results': arch_results
            }
        
        # Rankings
        rankings = {}
        if 'params' in metrics:
            rankings['smallest'] = min(comparison.items(), key=lambda x: x[1]['results'].get('params', float('inf')))[0]
            rankings['largest'] = max(comparison.items(), key=lambda x: x[1]['results'].get('params', 0))[0]
        
        if 'latency' in metrics:
            rankings['fastest'] = min(comparison.items(), key=lambda x: x[1]['results'].get('latency_ms', float('inf')))[0]
            rankings['slowest'] = max(comparison.items(), key=lambda x: x[1]['results'].get('latency_ms', 0))[0]
        
        return {
            'comparison': comparison,
            'rankings': rankings,
            'metrics': metrics
        }
    
    @staticmethod
    def find_optimal_architecture(
        constraints: dict,
        vocab_size: int = 10000
    ) -> dict:
        """
        Encuentra arquitectura óptima según restricciones.
        
        :param constraints: Restricciones (max_params, max_memory, max_latency)
        :param vocab_size: Tamaño del vocabulario
        :return: Arquitectura óptima
        """
        candidates = []
        
        # Generar candidatos
        for d_model in [128, 256, 512, 768, 1024]:
            for n_layers in [2, 4, 6, 12, 24]:
                for n_heads in [4, 8, 16]:
                    if d_model % n_heads != 0:
                        continue
                    
                    config = {
                        'vocab_size': vocab_size,
                        'd_model': d_model,
                        'n_heads': n_heads,
                        'n_layers': n_layers,
                        'd_ff': 4 * d_model,
                        'max_seq_len': 512,
                        'dropout': 0.1
                    }
                    
                    # Estimar parámetros
                    params = (vocab_size * d_model + 
                             n_layers * (12 * d_model * d_model) +
                             vocab_size * d_model)
                    
                    # Filtrar por restricciones
                    if constraints.get('max_params') and params > constraints['max_params']:
                        continue
                    
                    candidates.append({
                        'config': config,
                        'estimated_params': params
                    })
        
        # Seleccionar mejor candidato
        if candidates:
            # Ordenar por criterio (parámetros si no hay otros criterios)
            if constraints.get('max_params'):
                candidates.sort(key=lambda x: abs(x['estimated_params'] - constraints['max_params'] * 0.8))
            
            return candidates[0]['config']
        
        # Retornar configuración por defecto
        return ConfigManager.create_config_from_preset('medium')


class MetaLearningFramework:
    """
    Framework de meta-learning para transformers.
    """
    
    @staticmethod
    def create_meta_learner(
        base_config: dict,
        adaptation_layers: list = None
    ) -> dict:
        """
        Crea meta-learner para rápida adaptación.
        
        :param base_config: Configuración base
        :param adaptation_layers: Capas a adaptar
        :return: Meta-learner configurado
        """
        if adaptation_layers is None:
            adaptation_layers = ['last_layer', 'attention']
        
        meta_learner = {
            'base_config': base_config,
            'adaptation_layers': adaptation_layers,
            'adaptation_strategy': 'few_shot',
            'meta_learning_rate': 1e-3,
            'adaptation_steps': 5
        }
        
