class FederatedLearningHelper:
    """
    Helper para federated learning.
    """
    
    @staticmethod
    def create_federated_round(
        model: CausalTransformer,
        client_models: list,
        aggregation_method: str = 'average'
    ) -> dict:
        """
        Crea ronda de federated learning.
        
        :param model: Modelo global
        :param client_models: Lista de modelos de clientes
        :param aggregation_method: Método de agregación
        :return: Resultados de la ronda
        """
        round_results = {
            'num_clients': len(client_models),
            'aggregation_method': aggregation_method,
            'updates_applied': False
        }
        
        if aggregation_method == 'average':
            # Promediar pesos de clientes
            global_state = model.state_dict()
            
            for key in global_state:
                if key in client_models[0].state_dict():
                    client_weights = [cm.state_dict()[key] for cm in client_models]
                    averaged = torch.stack(client_weights).mean(dim=0)
                    global_state[key] = averaged
            
            model.load_state_dict(global_state)
            round_results['updates_applied'] = True
        
        return round_results
    
    @staticmethod
    def create_client_model(
        global_model: CausalTransformer
    ) -> CausalTransformer:
        """
        Crea modelo para cliente en federated learning.
        
        :param global_model: Modelo global
        :return: Modelo de cliente
        """
        client_model = ModelUtilitySuite.clone_model(global_model)
        print("✅ Modelo de cliente creado")
        return client_model


class ModelContinualLearning:
    """
    Utilidades para continual learning.
    """
    
    @staticmethod
    def create_continual_learner(
        model: CausalTransformer,
        task_memory_size: int = 1000
    ):
        """
        Crea learner para continual learning.
        
        :param model: Modelo
        :param task_memory_size: Tamaño de memoria por tarea
        :return: Continual learner
        """
        class ContinualLearner:
            def __init__(self, model, memory_size):
                self.model = model
                self.task_memory = {}
                self.task_count = 0
                self.memory_size = memory_size
            
            def learn_task(
                self,
                task_name: str,
                task_data,
                epochs: int = 5
            ):
                """Aprende nueva tarea."""
                self.task_count += 1
                
                # Guardar muestra de datos para replay
                if len(task_data) > self.memory_size:
                    # Seleccionar muestra representativa
                    import random
                    self.task_memory[task_name] = random.sample(task_data, self.memory_size)
                else:
                    self.task_memory[task_name] = task_data
                
                # Entrenar en nueva tarea
                # En producción, usar datos reales
                print(f"✅ Tarea {task_name} aprendida")
            
            def replay_memory(self, task_name: str):
                """Replay de memoria de tarea."""
                return self.task_memory.get(task_name, [])
            
            def get_task_count(self) -> int:
                """Obtiene número de tareas aprendidas."""
                return self.task_count
        
        return ContinualLearner(model, task_memory_size)


class ModelEdgeOptimizer:
    """
    Optimizador para deployment en edge devices.
    """
    
    @staticmethod
    def optimize_for_edge(
        model: CausalTransformer,
        target_device: str = 'mobile',
        memory_limit_mb: float = 100.0
    ) -> dict:
        """
        Optimiza modelo para edge devices.
        
        :param model: Modelo
        :param target_device: Dispositivo objetivo
        :param memory_limit_mb: Límite de memoria en MB
        :return: Modelo optimizado y configuración
        """
        optimization_steps = []
        
        # Step 1: Quantization
        optimizer = ModelOptimizer()
        quantized_model = optimizer.apply_mixed_precision(model)
        optimization_steps.append('mixed_precision')
        
        # Step 2: Pruning
        pruner = ModelPruner()
        pruned_model = pruner.prune_magnitude(quantized_model, sparsity=0.5)
        optimization_steps.append('pruning')
        
        # Step 3: Verificar memoria
        memory = estimate_memory_usage(
            1, 128, model.d_model,
            model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
            len(model.blocks), model.vocab_size
        )
        
        memory_mb = memory['total_mb']
        
        if memory_mb > memory_limit_mb:
            # Aplicar más optimizaciones
            compressed_model = ModelCompressor.compress_with_svd(pruned_model, compression_ratio=0.5)
            optimization_steps.append('svd_compression')
            optimized_model = compressed_model
        else:
            optimized_model = pruned_model
        
        return {
            'optimized_model': optimized_model,
            'optimization_steps': optimization_steps,
            'final_memory_mb': memory_mb,
            'meets_requirements': memory_mb <= memory_limit_mb
        }


class ModelSecurityAuditor:
    """
    Auditor de seguridad para modelos.
    """
    
    @staticmethod
    def audit_model_security(
        model: CausalTransformer,
        test_input: torch.Tensor
    ) -> dict:
        """
        Audita seguridad del modelo.
        
        :param model: Modelo
        :param test_input: Input de prueba
        :return: Resultados de auditoría
        """
        audit = {
            'security_score': 100,
            'issues': [],
            'recommendations': []
        }
        
        # Check 1: Input validation
        try:
            sanitized = ModelSecurity.sanitize_input(
                test_input, vocab_size=model.vocab_size, max_seq_len=512
            )
            if not torch.equal(test_input, sanitized):
                audit['issues'].append('Input validation no funciona correctamente')
                audit['security_score'] -= 10
        except:
            audit['issues'].append('Input validation no implementado')
            audit['security_score'] -= 20
        
        # Check 2: Output validation
        try:
            model.eval()
            with torch.no_grad():
                output = model(test_input)
            validation = ModelSecurity.validate_output(output)
            if not validation['is_valid']:
                audit['issues'].append('Output validation falló')
                audit['security_score'] -= 10
        except:
            audit['issues'].append('Output validation no implementado')
            audit['security_score'] -= 20
        
        # Check 3: Adversarial robustness
        try:
            adversarial_test = AdversarialTester.test_adversarial_robustness(
                model, test_input, epsilon=0.1
            )
            if adversarial_test['attack_success_rate'] > 0.5:
                audit['issues'].append('Modelo vulnerable a ataques adversariales')
                audit['security_score'] -= 15
                audit['recommendations'].append('Entrenar con adversarial training')
        except:
            audit['issues'].append('Adversarial testing no disponible')
            audit['security_score'] -= 10
        
        # Recomendaciones generales
        if audit['security_score'] < 80:
            audit['recommendations'].append('Implementar input/output validation completo')
            audit['recommendations'].append('Aplicar adversarial training')
            audit['recommendations'].append('Revisar sanitización de inputs')
        
        return audit


def create_complete_feature_matrix():
    """
    Crea matriz completa de características del módulo.
    """
