class IntelligentRecommendationSystem:
    """
    Sistema inteligente de recomendaciones para modelos.
    """
    
    @staticmethod
    def recommend_architecture(
        requirements: dict,
        use_case: str = 'general'
    ) -> dict:
        """
        Recomienda arquitectura basada en requirements.
        
        :param requirements: Requisitos (latency, memory, accuracy, etc.)
        :param use_case: Caso de uso
        :return: Recomendación de arquitectura
        """
        # Presets según caso de uso
        use_case_presets = {
            'general': 'medium',
            'mobile': 'small',
            'server': 'large',
            'research': 'large',
            'production': 'medium'
        }
        
        base_preset = use_case_presets.get(use_case, 'medium')
        base_config = ConfigManager.create_config_from_preset(base_preset)
        
        # Ajustar según requirements
        if requirements.get('low_latency', False):
            # Reducir número de capas
            base_config['n_layers'] = max(2, base_config['n_layers'] - 2)
            base_config['d_model'] = max(256, base_config['d_model'] - 128)
        
        if requirements.get('low_memory', False):
            # Reducir dimensiones
            base_config['d_model'] = max(128, base_config['d_model'] // 2)
            base_config['n_layers'] = max(2, base_config['n_layers'] // 2)
        
        if requirements.get('high_accuracy', False):
            # Aumentar capacidad
            base_config['d_model'] = min(1024, base_config['d_model'] + 256)
            base_config['n_layers'] = min(24, base_config['n_layers'] + 2)
        
        recommendation = {
            'recommended_config': base_config,
            'reasoning': [],
            'estimated_params': 0,
            'estimated_memory_gb': 0
        }
        
        # Calcular estimaciones
        params = (base_config['vocab_size'] * base_config['d_model'] + 
                 base_config['n_layers'] * (12 * base_config['d_model'] * base_config['d_model']))
        recommendation['estimated_params'] = params
        
        memory = estimate_memory_usage(
            1, 128, base_config['d_model'],
            base_config['n_heads'],
            base_config['n_layers'],
            base_config['vocab_size']
        )
        recommendation['estimated_memory_gb'] = memory['total_gb']
        
        # Agregar reasoning
        if requirements.get('low_latency'):
            recommendation['reasoning'].append('Arquitectura optimizada para baja latencia')
        if requirements.get('low_memory'):
            recommendation['reasoning'].append('Arquitectura optimizada para bajo uso de memoria')
        if requirements.get('high_accuracy'):
            recommendation['reasoning'].append('Arquitectura optimizada para alta precisión')
        
        return recommendation
    
    @staticmethod
    def recommend_optimizations(
        model: CausalTransformer,
        constraints: dict = None
    ) -> list:
        """
        Recomienda optimizaciones para el modelo.
        
        :param model: Modelo
        :param constraints: Restricciones
        :return: Lista de recomendaciones
        """
        recommendations = []
        
        # Analizar modelo
        params = count_parameters(model)
        memory = estimate_memory_usage(
            1, 128, model.d_model,
            model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
            len(model.blocks), model.vocab_size
        )
        
        # Recomendaciones basadas en características
        if params['total_millions'] > 500:
            recommendations.append({
                'type': 'quantization',
                'priority': 'high',
                'reason': 'Modelo muy grande, cuantización reducirá tamaño significativamente',
                'expected_improvement': '50-70% reducción de tamaño'
            })
        
        if memory['total_gb'] > 16:
            recommendations.append({
                'type': 'pruning',
                'priority': 'high',
                'reason': 'Uso de memoria alto, pruning reducirá memoria',
                'expected_improvement': '30-50% reducción de memoria'
            })
        
        if params['total_millions'] > 100:
            recommendations.append({
                'type': 'mixed_precision',
                'priority': 'medium',
                'reason': 'Modelo grande se beneficiaría de mixed precision',
                'expected_improvement': '2x reducción de memoria, 1.5x speedup'
            })
        
        # Recomendaciones según constraints
        if constraints:
            if constraints.get('target_latency_ms') and constraints['target_latency_ms'] < 100:
                recommendations.append({
                    'type': 'onnx_export',
                    'priority': 'high',
                    'reason': 'Latencia objetivo muy baja, ONNX optimizará inferencia',
                    'expected_improvement': '2-3x speedup'
                })
        
        return recommendations


