class ModelComparisonMatrix:
    """
    Matriz de comparación avanzada de modelos.
    """
    
    @staticmethod
    def create_comparison_matrix(
        models: list,
        model_names: list,
        test_input: torch.Tensor,
        metrics: list = None
    ) -> dict:
        """
        Crea matriz de comparación completa.
        
        :param models: Lista de modelos
        :param model_names: Nombres de modelos
        :param test_input: Input de prueba
        :param metrics: Métricas a comparar
        :return: Matriz de comparación
        """
        if metrics is None:
            metrics = ['params', 'memory', 'latency', 'throughput', 'accuracy']
        
        matrix = {}
        
        for model, name in zip(models, model_names):
            model_data = {}
            
            # Parámetros
            if 'params' in metrics:
                params = count_parameters(model)
                model_data['params_millions'] = params['total_millions']
            
            # Memoria
            if 'memory' in metrics:
                memory = estimate_memory_usage(
                    test_input.shape[0], test_input.shape[1],
                    model.d_model,
                    model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
                    len(model.blocks), model.vocab_size
                )
                model_data['memory_gb'] = memory['total_gb']
            
            # Performance
            if 'latency' in metrics or 'throughput' in metrics:
                benchmark = ModelBenchmarkingSuite.run_comprehensive_benchmark(
                    model, test_input, num_runs=5
                )
                if 'latency' in metrics:
                    model_data['latency_ms'] = benchmark['avg_forward_time_ms']
                if 'throughput' in metrics:
                    model_data['throughput'] = benchmark['tokens_per_second']
            
            matrix[name] = model_data
        
        # Rankings
        rankings = {}
        if 'params' in metrics:
            rankings['smallest'] = min(matrix.items(), key=lambda x: x[1].get('params_millions', float('inf')))[0]
            rankings['largest'] = max(matrix.items(), key=lambda x: x[1].get('params_millions', 0))[0]
        
        if 'latency' in metrics:
            rankings['fastest'] = min(matrix.items(), key=lambda x: x[1].get('latency_ms', float('inf')))[0]
            rankings['slowest'] = max(matrix.items(), key=lambda x: x[1].get('latency_ms', 0))[0]
        
        if 'throughput' in metrics:
            rankings['highest_throughput'] = max(matrix.items(), key=lambda x: x[1].get('throughput', 0))[0]
        
        return {
            'matrix': matrix,
            'rankings': rankings,
            'metrics': metrics
        }


class ModelEfficiencyAnalyzer:
    """
    Analizador de eficiencia de modelos.
    """
    
    @staticmethod
    def calculate_efficiency_score(
        model: CausalTransformer,
        performance_metrics: dict
    ) -> dict:
        """
        Calcula score de eficiencia del modelo.
        
        :param model: Modelo
        :param performance_metrics: Métricas de performance
        :return: Score de eficiencia
        """
        params = count_parameters(model)
        
        # Calcular eficiencia (performance / recursos)
        efficiency_score = 0.0
        factors = {}
        
        # Factor de throughput por parámetro
        if 'throughput' in performance_metrics and params['total'] > 0:
            throughput_per_param = performance_metrics['throughput'] / params['total'] * 1e6
            factors['throughput_efficiency'] = throughput_per_param
        
        # Factor de accuracy por parámetro
        if 'accuracy' in performance_metrics and params['total'] > 0:
            accuracy_per_param = performance_metrics['accuracy'] / params['total'] * 1e6
            factors['accuracy_efficiency'] = accuracy_per_param
        
        # Score combinado
        if factors:
            efficiency_score = sum(factors.values()) / len(factors)
        
        return {
            'efficiency_score': efficiency_score,
            'factors': factors,
            'parameters_millions': params['total_millions'],
            'recommendation': 'Efficient' if efficiency_score > 0.5 else 'Could be optimized'
        }
    
    @staticmethod
    def compare_efficiency(
        models: list,
        model_names: list,
        performance_metrics: list
    ) -> dict:
        """
        Compara eficiencia de múltiples modelos.
        
        :param models: Lista de modelos
        :param model_names: Nombres
        :param performance_metrics: Lista de métricas por modelo
        :return: Comparación de eficiencia
        """
        efficiency_scores = {}
        
        for model, name, metrics in zip(models, model_names, performance_metrics):
            score = ModelEfficiencyAnalyzer.calculate_efficiency_score(model, metrics)
            efficiency_scores[name] = score
        
        # Ranking
        most_efficient = max(efficiency_scores.items(), key=lambda x: x[1]['efficiency_score'])
        
        return {
            'efficiency_scores': efficiency_scores,
            'most_efficient': most_efficient[0],
            'most_efficient_score': most_efficient[1]['efficiency_score']
        }


class ModelResourceManager:
    """
    Gestor de recursos para modelos.
    """
    
    @staticmethod
    def allocate_resources(
        model: CausalTransformer,
        available_resources: dict
    ) -> dict:
        """
        Asigna recursos óptimos para el modelo.
        
        :param model: Modelo
        :param available_resources: Recursos disponibles
        :return: Asignación de recursos
        """
        memory = estimate_memory_usage(
            1, 128, model.d_model,
            model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
            len(model.blocks), model.vocab_size
        )
        
        allocation = {
            'memory_gb_required': memory['total_gb'],
            'memory_gb_available': available_resources.get('memory_gb', 16),
            'gpu_required': memory['total_gb'] > 8,
            'gpu_available': available_resources.get('gpu_available', False),
            'feasible': False,
            'recommendations': []
        }
        
        # Verificar factibilidad
        if memory['total_gb'] <= available_resources.get('memory_gb', 16):
            allocation['feasible'] = True
        else:
            allocation['recommendations'].append('Aplicar optimizaciones de memoria')
            allocation['recommendations'].append(f'Reducir memoria de {memory["total_gb"]:.2f}GB a < {available_resources.get("memory_gb", 16)}GB')
        
        # Verificar GPU
        if allocation['gpu_required'] and not allocation['gpu_available']:
            allocation['recommendations'].append('GPU recomendada pero no disponible')
            allocation['recommendations'].append('Usar CPU será más lento')
        
        return allocation
    
    @staticmethod
    def optimize_resource_usage(
        model: CausalTransformer,
        resource_constraints: dict
    ) -> dict:
        """
        Optimiza uso de recursos según constraints.
        
        :param model: Modelo
        :param resource_constraints: Restricciones de recursos
        :return: Plan de optimización
        """
        plan = {
            'optimizations': [],
            'estimated_memory_after': 0,
            'meets_constraints': False
        }
        
        memory = estimate_memory_usage(
            1, 128, model.d_model,
            model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
            len(model.blocks), model.vocab_size
        )
        
        current_memory = memory['total_gb']
        target_memory = resource_constraints.get('max_memory_gb', 16)
        
        if current_memory > target_memory:
            # Aplicar optimizaciones
            plan['optimizations'].append('quantization')
            estimated_after_quant = current_memory * 0.5
            
            if estimated_after_quant > target_memory:
                plan['optimizations'].append('pruning')
                estimated_after_prune = estimated_after_quant * 0.7
                
                if estimated_after_prune > target_memory:
                    plan['optimizations'].append('svd_compression')
                    plan['estimated_memory_after'] = estimated_after_prune * 0.5
                else:
                    plan['estimated_memory_after'] = estimated_after_prune
            else:
                plan['estimated_memory_after'] = estimated_after_quant
            
            plan['meets_constraints'] = plan['estimated_memory_after'] <= target_memory
        else:
            plan['estimated_memory_after'] = current_memory
            plan['meets_constraints'] = True
        
        return plan


