class DeepDataAnalysis:
    """
    Análisis profundo de datos para entrenamiento.
    """
    
    @staticmethod
    def analyze_dataset_quality(
        data_loader,
        vocab_size: int = 10000
    ) -> dict:
        """
        Analiza calidad del dataset.
        
        :param data_loader: DataLoader
        :param vocab_size: Tamaño del vocabulario
        :return: Análisis de calidad
        """
        analysis = {
            'quality_score': 100,
            'issues': [],
            'statistics': {},
            'recommendations': []
        }
        
        stats = ModelDataAnalyzer.analyze_dataset_statistics(data_loader)
        issues = ModelDataAnalyzer.detect_data_issues(data_loader)
        
        analysis['statistics'] = stats
        
        # Evaluar calidad
        if issues.get('has_nan', False):
            analysis['quality_score'] -= 20
            analysis['issues'].append('Dataset contiene NaN')
            analysis['recommendations'].append('Limpiar datos y remover NaN')
        
        if issues.get('has_inf', False):
            analysis['quality_score'] -= 20
            analysis['issues'].append('Dataset contiene Inf')
            analysis['recommendations'].append('Limpiar datos y remover Inf')
        
        if issues.get('empty_sequences', 0) > 0:
            analysis['quality_score'] -= 10
            analysis['issues'].append(f'{issues["empty_sequences"]} secuencias vacías')
            analysis['recommendations'].append('Remover secuencias vacías')
        
        if stats.get('vocab_coverage', 0) < vocab_size * 0.5:
            analysis['quality_score'] -= 15
            analysis['issues'].append('Cobertura de vocabulario baja')
            analysis['recommendations'].append('Aumentar diversidad de datos')
        
        if stats.get('avg_seq_len', 0) < 10:
            analysis['quality_score'] -= 10
            analysis['issues'].append('Secuencias muy cortas en promedio')
            analysis['recommendations'].append('Considerar filtrar secuencias muy cortas')
        
        return analysis
    
    @staticmethod
    def detect_data_biases(
        data_loader,
        sample_size: int = 1000
    ) -> dict:
        """
        Detecta sesgos en los datos.
        
        :param data_loader: DataLoader
        :param sample_size: Tamaño de muestra
        :return: Análisis de sesgos
        """
        bias_analysis = {
            'biases_detected': [],
            'bias_score': 0,
            'recommendations': []
        }
        
        # Análisis simplificado
        # En producción, usar análisis más sofisticado
        
        token_frequencies = {}
        total_tokens = 0
        
        count = 0
        for batch in data_loader:
            if 'input_ids' in batch:
                for seq in batch['input_ids']:
                    unique_tokens = torch.unique(seq)
                    for token in unique_tokens:
                        if token.item() > 0:  # Ignorar padding
                            token_frequencies[token.item()] = token_frequencies.get(token.item(), 0) + 1
                            total_tokens += 1
                    
                    count += 1
                    if count >= sample_size:
                        break
            if count >= sample_size:
                break
        
        # Detectar tokens muy frecuentes (posible bias)
        if token_frequencies:
            max_freq = max(token_frequencies.values())
            avg_freq = sum(token_frequencies.values()) / len(token_frequencies)
            
            if max_freq > avg_freq * 10:
                bias_analysis['biases_detected'].append('Algunos tokens son extremadamente frecuentes')
                bias_analysis['bias_score'] += 20
                bias_analysis['recommendations'].append('Balancear distribución de tokens')
        
        return bias_analysis


class AdvancedExperimentDesign:
    """
    Diseño avanzado de experimentos.
    """
    
    @staticmethod
    def design_experiment(
        hypothesis: str,
        variables: dict,
        metrics: list = None
    ) -> dict:
        """
        Diseña experimento estructurado.
        
        :param hypothesis: Hipótesis a probar
        :param variables: Variables independientes
        :param metrics: Métricas a medir
        :return: Diseño de experimento
        """
        if metrics is None:
            metrics = ['loss', 'accuracy', 'perplexity']
        
        experiment = {
            'hypothesis': hypothesis,
            'variables': variables,
            'metrics': metrics,
            'control_group': None,
            'treatment_groups': [],
            'sample_size': 100,
            'randomization': True,
            'replication': 3
        }
        
        return experiment
    
    @staticmethod
    def analyze_experiment_results(
        results: list,
        significance_level: float = 0.05
    ) -> dict:
        """
        Analiza resultados de experimentos.
        
        :param results: Lista de resultados
        :param significance_level: Nivel de significancia
        :return: Análisis estadístico
        """
        analysis = {
            'mean_metrics': {},
            'std_metrics': {},
            'significant_differences': [],
            'conclusions': []
        }
        
        if len(results) > 0:
            # Calcular estadísticas
            all_metrics = {}
            for result in results:
                for metric_name, metric_value in result.get('metrics', {}).items():
                    if metric_name not in all_metrics:
                        all_metrics[metric_name] = []
                    all_metrics[metric_name].append(metric_value)
            
            for metric_name, values in all_metrics.items():
                if values:
                    analysis['mean_metrics'][metric_name] = sum(values) / len(values)
                    if len(values) > 1:
                        mean_val = analysis['mean_metrics'][metric_name]
                        variance = sum((x - mean_val) ** 2 for x in values) / (len(values) - 1)
                        analysis['std_metrics'][metric_name] = variance ** 0.5
        
        return analysis


class ModelVisualizationAdvanced:
    """
    Visualización avanzada mejorada.
    """
    
    @staticmethod
    def create_comprehensive_dashboard(
        model: CausalTransformer,
        test_input: torch.Tensor,
        metrics_history: list = None,
        save_path: str = None
    ):
        """
        Crea dashboard comprensivo del modelo.
        
        :param model: Modelo
        :param test_input: Input de prueba
        :param metrics_history: Historial de métricas
        :param save_path: Ruta para guardar
        """
        try:
            import matplotlib.pyplot as plt
        except ImportError:
            print("⚠️ matplotlib no está instalado")
            return
        
        fig = plt.figure(figsize=(20, 12))
        
        # 1. Arquitectura del modelo
        ax1 = plt.subplot(2, 3, 1)
        params = count_parameters(model)
        ax1.bar(['Trainable', 'Non-trainable'], 
                [params['trainable'], params['total'] - params['trainable']])
        ax1.set_title('Model Parameters')
        ax1.set_ylabel('Count')
        
        # 2. Memoria por componente
        ax2 = plt.subplot(2, 3, 2)
        memory = estimate_memory_usage(
            test_input.shape[0], test_input.shape[1],
            model.d_model,
            model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
            len(model.blocks), model.vocab_size
        )
        memory_components = ['Model Weights', 'Activations', 'Gradients']
        memory_values = [
            memory.get('model_weights_gb', 0),
            memory.get('activations_gb', 0),
            memory.get('gradients_gb', 0)
        ]
        ax2.bar(memory_components, memory_values)
        ax2.set_title('Memory Breakdown')
        ax2.set_ylabel('GB')
        
        # 3. Performance benchmark
        ax3 = plt.subplot(2, 3, 3)
        benchmark = ModelBenchmarkingSuite.run_comprehensive_benchmark(model, test_input, num_runs=5)
        perf_metrics = ['Avg Latency', 'Min Latency', 'Max Latency']
        perf_values = [
            benchmark['avg_forward_time_ms'],
            benchmark['min_forward_time_ms'],
            benchmark['max_forward_time_ms']
        ]
        ax3.bar(perf_metrics, perf_values)
        ax3.set_title('Performance Metrics')
        ax3.set_ylabel('ms')
        
        # 4. Training curves (si hay historial)
        if metrics_history and len(metrics_history) > 0:
            ax4 = plt.subplot(2, 3, 4)
            losses = [m.get('loss', 0) for m in metrics_history]
            ax4.plot(range(len(losses)), losses)
            ax4.set_title('Training Loss')
            ax4.set_xlabel('Step')
            ax4.set_ylabel('Loss')
            ax4.grid(True)
        
        # 5. Model architecture diagram
        ax5 = plt.subplot(2, 3, 5)
        arch_info = [
            f"Vocab: {model.vocab_size}",
            f"d_model: {model.d_model}",
            f"Layers: {len(model.blocks)}",
            f"Heads: {model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8}",
            f"Params: {params['total_millions']:.2f}M"
        ]
        ax5.text(0.1, 0.5, '\n'.join(arch_info), fontsize=12, verticalalignment='center')
        ax5.set_title('Model Architecture')
        ax5.axis('off')
        
        # 6. Health status
        ax6 = plt.subplot(2, 3, 6)
        dashboard = ModelHealthDashboard.create_health_dashboard(model, test_input)
        status_colors = {'ok': 'green', 'warning': 'yellow', 'error': 'red'}
        checks = dashboard.get('checks', {})
        check_names = list(checks.keys())[:5]
        check_statuses = [checks[c].get('status', 'unknown') for c in check_names]
        colors = [status_colors.get(s, 'gray') for s in check_statuses]
        ax6.barh(check_names, [1] * len(check_names), color=colors)
        ax6.set_title('Health Status')
        ax6.set_xlabel('Status')
        
        plt.tight_layout()
        
        if save_path:
            plt.savefig(save_path, dpi=300, bbox_inches='tight')
            print(f"✅ Dashboard guardado en: {save_path}")
        else:
            plt.show()


class ModelProductionOptimizer:
    """
    Optimizador específico para producción.
    """
    
    @staticmethod
    def optimize_for_production(
        model: CausalTransformer,
        production_requirements: dict
    ) -> dict:
        """
        Optimiza modelo para requisitos de producción.
        
        :param model: Modelo
        :param production_requirements: Requisitos
        :return: Modelo optimizado y reporte
        """
        optimization_report = {
            'optimizations_applied': [],
            'performance_gains': {},
            'meets_requirements': False
        }
        
        # Requisitos
        max_latency_ms = production_requirements.get('max_latency_ms', 1000)
        max_memory_gb = production_requirements.get('max_memory_gb', 16)
        min_throughput = production_requirements.get('min_throughput', 100)
        
        # Benchmark inicial
        test_input = torch.randint(0, model.vocab_size, (1, 128))
        initial_benchmark = ModelBenchmarkingSuite.run_comprehensive_benchmark(
            model, test_input, num_runs=5
        )
        
        optimized_model = model
        
        # Optimización 1: Latencia
        if initial_benchmark['avg_forward_time_ms'] > max_latency_ms:
            # Aplicar optimizaciones para latencia
            optimized_model = InferenceOptimizer.optimize_for_onnx(optimized_model)
            optimization_report['optimizations_applied'].append('onnx_optimization')
            
            # Verificar mejora
            new_benchmark = ModelBenchmarkingSuite.run_comprehensive_benchmark(
                optimized_model, test_input, num_runs=5
            )
            latency_improvement = (initial_benchmark['avg_forward_time_ms'] - 
                                  new_benchmark['avg_forward_time_ms']) / initial_benchmark['avg_forward_time_ms']
            optimization_report['performance_gains']['latency'] = latency_improvement
        
        # Optimización 2: Memoria
        memory = estimate_memory_usage(
            test_input.shape[0], test_input.shape[1],
            model.d_model,
            model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8,
            len(model.blocks), model.vocab_size
        )
        
        if memory['total_gb'] > max_memory_gb:
            # Aplicar optimizaciones de memoria
            optimized_model = ModelOptimizer.apply_mixed_precision(optimized_model)
            optimization_report['optimizations_applied'].append('mixed_precision')
            
            # Estimación de mejora
            memory_improvement = 0.5  # 50% reducción estimada
            optimization_report['performance_gains']['memory'] = memory_improvement
        
        # Verificar si cumple requisitos
        final_benchmark = ModelBenchmarkingSuite.run_comprehensive_benchmark(
            optimized_model, test_input, num_runs=5
        )
        final_memory = estimate_memory_usage(
            test_input.shape[0], test_input.shape[1],
            optimized_model.d_model,
            optimized_model.blocks[0].attention.n_heads if hasattr(optimized_model.blocks[0], 'attention') else 8,
            len(optimized_model.blocks), optimized_model.vocab_size
        )
        
        optimization_report['meets_requirements'] = (
            final_benchmark['avg_forward_time_ms'] <= max_latency_ms and
            final_memory['total_gb'] <= max_memory_gb and
            final_benchmark['tokens_per_second'] >= min_throughput
        )
        
        return {
            'optimized_model': optimized_model,
            'report': optimization_report
        }


class ModelVersionControl:
    """
    Sistema de control de versiones para modelos.
    """
    
    @staticmethod
    def create_version_system(
        base_path: str = './model_versions'
    ):
        """
        Crea sistema de control de versiones.
        
        :param base_path: Ruta base
        :return: Sistema de versiones
        """
        import os
        import json
        
        os.makedirs(base_path, exist_ok=True)
        
        class VersionSystem:
            def __init__(self, path):
                self.path = path
                self.versions_file = os.path.join(path, 'versions.json')
                self.versions = {}
                self._load_versions()
            
            def _load_versions(self):
                """Carga versiones desde disco."""
                if os.path.exists(self.versions_file):
                    with open(self.versions_file, 'r') as f:
                        self.versions = json.load(f)
            
            def _save_versions(self):
                """Guarda versiones a disco."""
                with open(self.versions_file, 'w') as f:
                    json.dump(self.versions, f, indent=2)
            
            def create_version(
                self,
                model: CausalTransformer,
                version_name: str,
                metadata: dict = None
            ):
                """Crea nueva versión del modelo."""
                version_path = os.path.join(self.path, version_name)
                os.makedirs(version_path, exist_ok=True)
                
                # Guardar modelo
                model_file = os.path.join(version_path, 'model.pt')
                torch.save(model.state_dict(), model_file)
                
                # Guardar metadata
                version_info = {
                    'version': version_name,
                    'created_at': __import__('datetime').datetime.now().isoformat(),
                    'metadata': metadata or {},
                    'model_config': {
                        'vocab_size': model.vocab_size,
                        'd_model': model.d_model,
                        'n_layers': len(model.blocks),
                        'n_heads': model.blocks[0].attention.n_heads if hasattr(model.blocks[0], 'attention') else 8
                    }
                }
                
                metadata_file = os.path.join(version_path, 'metadata.json')
                with open(metadata_file, 'w') as f:
                    json.dump(version_info, f, indent=2)
                
                self.versions[version_name] = version_info
                self._save_versions()
                
                print(f"✅ Versión {version_name} creada")
            
            def list_versions(self) -> list:
                """Lista todas las versiones."""
                return list(self.versions.keys())
            
            def get_version(self, version_name: str) -> dict:
                """Obtiene información de una versión."""
                return self.versions.get(version_name, {})
            
            def compare_versions(self, v1: str, v2: str) -> dict:
                """Compara dos versiones."""
                ver1 = self.versions.get(v1, {})
                ver2 = self.versions.get(v2, {})
                
                comparison = {
                    'versions': [v1, v2],
                    'differences': {}
                }
                
                if ver1 and ver2:
                    config1 = ver1.get('model_config', {})
                    config2 = ver2.get('model_config', {})
                    
                    for key in config1:
                        if config1[key] != config2.get(key):
                            comparison['differences'][key] = {
                                'v1': config1[key],
                                'v2': config2.get(key)
                            }
                
                return comparison
        
        return VersionSystem(base_path)


def create_complete_api_reference():
    """
    Crea referencia completa de API.
    """
    reference = f"""
# ============================================================================
# REFERENCIA COMPLETA DE API - TRANSFORMER ARCHITECTURE EXPLANATION
# ============================================================================

Versión: {__version__}
Autor: {__author__}

## CLASES PRINCIPALES

### CausalTransformer
Modelo principal de transformer causal.

**Parámetros:**
- vocab_size (int): Tamaño del vocabulario
- d_model (int): Dimensión del modelo
- n_heads (int): Número de cabezas de atención
- n_layers (int): Número de capas
- d_ff (int): Dimensión de feed-forward
- max_seq_len (int): Longitud máxima de secuencia
- dropout (float): Tasa de dropout

**Métodos:**
- forward(input_ids): Forward pass

### TextGenerator
Generador de texto.

**Métodos:**
- generate(prompt, max_length, temperature, strategy): Genera texto

### ModelTrainer
Entrenador de modelos.

**Métodos:**
- train_epoch(): Entrena una época
- eval_epoch(): Evalúa una época

## CLASES UTILITARIAS (150+)

Ver documentación completa en el módulo para lista completa.

## FUNCIONES AUXILIARES

### count_parameters(model)
Cuenta parámetros del modelo.

### estimate_memory_usage(...)
Estima uso de memoria.

### save_model_checkpoint(...)
Guarda checkpoint del modelo.

### load_model_checkpoint(...)
Carga checkpoint del modelo.

## EJEMPLOS

Ver ejemplos completos en el módulo.
"""
    return reference


